-- Poems batch 76
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('afa76362-2f62-4abf-80ca-aa28364d7d8f','春野五首  其三','宋庠','宋','宋诗','song-poetry','','[]','近出東郊道，時巾下澤車。',48,'全唐诗/poet.song.10000.json','["近出東郊道，時巾下澤車。", "田溝蛙拖紫，沙徑鳥留書。", "木引藤絲遠，牆蒸菌蔕虛。", "幽懷聊俯仰，無意事施蘧。"]'),
('5215215c-7c04-422f-9c40-d2d3080b24f3','春野五首  其四','宋庠','宋','宋诗','song-poetry','','[]','沃野周原接，遥陂鄭洧連。',48,'全唐诗/poet.song.10000.json','["沃野周原接，遥陂鄭洧連。", "鬰葱中縣氣，南北富人阡。", "鳥騁因風野，虹生欲霽天。", "斜陽墟落外，䍧豕食春田。"]'),
('a3f7b521-2dbb-4589-92ad-bb90d4a2b420','春野五首  其五','宋庠','宋','宋诗','song-poetry','','[]','夕藹收芳甸，春蒿徧宿荄。',48,'全唐诗/poet.song.10000.json','["夕藹收芳甸，春蒿徧宿荄。", "朝虹先雨出，寒雁後陽來。", "遠木芊芊茂，幽花脈脈開。", "欣逢老農語，爭席坐林隈。"]'),
('745f7f6e-9dc7-44bf-ab33-1d6e98e1896b','林下','宋庠','宋','宋诗','song-poetry','','[]','偶作中林適，聊觀萬化春。',48,'全唐诗/poet.song.10000.json','["偶作中林適，聊觀萬化春。", "蜂巢喧似市，禽舌巧于人。", "陂溜鳴田尾，藤梢衣樹身。", "鄉農時晤語，野意合天真。"]'),
('d32e67ed-a1bb-4787-9cdb-7e6ac46dacf4','郡圃海棠初開追憶學士院玉堂後西軒此花最盛置酒有感','宋庠','宋','宋诗','song-poetry','','[]','昔作瀛洲賞，今逢汶水春。',48,'全唐诗/poet.song.10000.json','["昔作瀛洲賞，今逢汶水春。", "可憐無並色，來對始衰人。", "溫樹遥知漢，仙桃尚記秦。", "臨樽如舊識，爭忍判芳辰。"]'),
('afd8e2de-d456-425c-86be-012e151cc9d8','寄題奉寧樞密直諫議新葺漱玉齋','宋庠','宋','宋诗','song-poetry','','[]','聞說西齋水，潺湲逼畫楹。',48,'全唐诗/poet.song.10000.json','["聞說西齋水，潺湲逼畫楹。", "雖添新竇響，不改故源清。", "花落波浮亂，杯遲屈曲行。", "無因陪夜宿，同賞瀑巖聲。"]'),
('069c73d9-6547-48bc-a980-b088bf7e1f00','次鞏縣','宋庠','宋','宋诗','song-poetry','','[]','昔走成周道，春風尚落花。',48,'全唐诗/poet.song.10000.json','["昔走成周道，春風尚落花。", "今馳河內傳，秋日正臨霞。", "山色依前綠，顛毛只是華。", "見迎多故吏，衰壯兩驚嗟。"]'),
('1cc7f38f-13f2-4565-b07e-0c253b13f891','病臂痛踰月不能御刀筆','宋庠','宋','宋诗','song-poetry','','[]','百疾乘衰運，雙肱怯痺摇。',48,'全唐诗/poet.song.10000.json','["百疾乘衰運，雙肱怯痺摇。", "身知九折痛，肉訝半分銷。", "掉市將誰羨，拘原莫我邀。", "惟堪楚林下，如槁學承蜩。"]'),
('618ca7aa-4f52-4271-9015-c2eac13392f7','傷死馬','宋庠','宋','宋诗','song-poetry','','[]','辨道曾資智，嘶風忽絕音。',48,'全唐诗/poet.song.10000.json','["辨道曾資智，嘶風忽絕音。", "故蹄休踐雪，朽骨詎酬金。", "附尾讒蠅散，投鞍嚙鼠侵。", "棄帷宜一報，盡力有前箴。"]'),
('7437d771-0b7a-4077-9983-e969b05e34b7','涉淮泝清迫于冰涸舟次下邳先寄彭門趙侍御二首  其一','宋庠','宋','宋诗','song-poetry','','[]','病骨憂南土，孤懷念北遷。',48,'全唐诗/poet.song.10000.json','["病骨憂南土，孤懷念北遷。", "欣承紫泥詔，且向汶陽田。", "夜雪淮冰合，朝暾海氣鮮。", "風波雖繚繞，自有故交憐。"]'),
('a178fdb9-3ab6-44d6-81d5-9c7435cd68a4','涉淮泝清迫于冰涸舟次下邳先寄彭門趙侍御二首  其二','宋庠','宋','宋诗','song-poetry','','[]','此地淮壖極，連檣北轉初。',48,'全唐诗/poet.song.10000.json','["此地淮壖極，連檣北轉初。", "風煙寒背楚，陂澤遠通徐。", "葆髮驚秋外，葵心戀闕餘。", "不憂芳歲晚，松柏自扶疏。"]'),
('ae40100d-56a7-4ff7-834d-e801d3df7fcb','次韵和北京太師丞相潞國公創作茅齋之什','宋庠','宋','宋诗','song-poetry','','[]','地僻誅茅後，堂幽搆厦餘。',48,'全唐诗/poet.song.10000.json','["地僻誅茅後，堂幽搆厦餘。", "誰知冶城望，更作傅巖居。", "凈供香厨飯，真籤蕊笈書。", "因公高世想，轉憶舊田廬。"]'),
('689318cd-66e7-4647-96cf-4f0a1a484010','廢書','宋庠','宋','宋诗','song-poetry','','[]','斷簡孔堂壞，遺經汲塚虛。',48,'全唐诗/poet.song.10000.json','["斷簡孔堂壞，遺經汲塚虛。", "謾求芸辟蠹，先歎魯成魚。", "舊帛愁連蓋，亡篇恨蠟車。", "吾家先訓在，楹鑿晏生廬。"]'),
('872c0f9d-cbda-4368-b9f5-7102a46064dc','初春置酒河上得前忠武記室饒廷評書因成感詠以寄','宋庠','宋','宋诗','song-poetry','','[]','故歡清潩上，今醉濁河邊。',48,'全唐诗/poet.song.10000.json','["故歡清潩上，今醉濁河邊。", "素領添新髮，春風似去年。", "暖雲邙北樹，芳草鞏陰田。", "感舊情何極，重看記室牋。"]'),
('2fc40ca2-4546-47fc-8236-bb1df426b634','得天經書問','宋庠','宋','宋诗','song-poetry','','[]','久卧堪憂巷，驚聞不滅書。',48,'全唐诗/poet.song.10000.json','["久卧堪憂巷，驚聞不滅書。", "高風五柳外，深意八行餘。", "努力邀加飯，相逢約下車。", "殷勤長跪讀，雙睫費漣如。"]'),
('b7f04cc1-2060-4312-be49-5a7a1fdf0619','禁中寒蟬','宋庠','宋','宋诗','song-poetry','','[]','何處幽林蛻，來依禁樹鳴。',48,'全唐诗/poet.song.10000.json','["何處幽林蛻，來依禁樹鳴。", "風緌非冒寵，露腹祗知清。", "曉韵飄觚闕，殘嘶逗綵甍。", "秋螳多怒臂，寂寞好全生。"]'),
('15c9bfe2-15ea-49b9-a204-c8a7cad4d9a2','感秋二首  其一','宋庠','宋','宋诗','song-poetry','','[]','夕軒疏雨罷，物物爲秋驚。',48,'全唐诗/poet.song.10000.json','["夕軒疏雨罷，物物爲秋驚。", "病葉先風落，寒蟬趁候鳴。", "西飛愁燕急，左界恨河傾。", "借問三江客，鱸魚底有情。"]'),
('721f4e92-7f17-410b-9ed4-16d8223b032c','感秋二首  其二','宋庠','宋','宋诗','song-poetry','','[]','歲事催人事，榮心伴客心。',48,'全唐诗/poet.song.10000.json','["歲事催人事，榮心伴客心。", "鸞驂收畫扇，螳臂感瑶琴。", "夕露繁將滴，朝雲薄亦陰。", "金貂寓直省，潘興轉難任。"]'),
('814d7a7b-39b6-48ec-aeca-357310a5a73f','甲戌冬屬疾賜告二首  其一','宋庠','宋','宋诗','song-poetry','','[]','行年三十九，病腦劇中乾。',48,'全唐诗/poet.song.10000.json','["行年三十九，病腦劇中乾。", "目界空花眩，脾倉宿滓寒。", "未燈欹夕枕，欲食進朝丸。", "惟有披書樂，依稀及士安。"]'),
('a085f0c4-0eec-48e3-b3fd-985a3081079c','甲戌冬屬疾賜告二首  其二','宋庠','宋','宋诗','song-poetry','','[]','恩告偃衡蓽，年華飛琯灰。',48,'全唐诗/poet.song.10000.json','["恩告偃衡蓽，年華飛琯灰。", "右眠安佛脅，深息養仙胎。", "數犯稽違禁，誰憐遊落材。", "使軺均病粟，更自囅然咍。"]'),
('3333ba71-cb35-47bc-9cf6-690a9162245b','小疾','宋庠','宋','宋诗','song-poetry','','[]','舊疹感春陽，岑岑體正尪。',48,'全唐诗/poet.song.10000.json','["舊疹感春陽，岑岑體正尪。", "雙朧便貉睡，一息寄龜腸。", "味減轑羹釜，心疑照弩觴。", "藥苗行可采，更驗太清方。"]'),
('3adf11af-3fb7-444b-8577-0838e62cb9f8','晚望京邑','宋庠','宋','宋诗','song-poetry','','[]','暮壘初休角，孤譙半掩門。',48,'全唐诗/poet.song.10000.json','["暮壘初休角，孤譙半掩門。", "鴻聲騁寥泬，鴉意戀黄昏。", "遠岫排頭碧，春河徹底渾。", "關東三百里，依約是天閽。"]'),
('15326624-3939-4b67-bcda-638f2927f8b8','候月臺','宋庠','宋','宋诗','song-poetry','','[]','平昔詞林伯，嘗爲右輔來。',48,'全唐诗/poet.song.10000.json','["平昔詞林伯，嘗爲右輔來。", "庾公偏愛月，薛縣未傾臺。", "鑱石雲根斷，臨波水腹開。", "良宵時弭蓋，方信謝莊才。"]'),
('8e30552f-98ac-4596-b6bc-9fe9eefe1db7','過列子觀','宋庠','宋','宋诗','song-poetry','','[]','兩作朱轓守，重登羽客宮。',48,'全唐诗/poet.song.10000.json','["兩作朱轓守，重登羽客宮。", "故墟牆舍壞，塵案酎杯空。", "款戶殊無屨，乘衣尚有風。", "軒游曾駐蹕，高意掩崆峒。"]'),
('b24509d2-a4e6-4a22-b758-d69efd2d1f29','北臺  其一','宋庠','宋','宋诗','song-poetry','','[]','遠日春風外，韶光晚思前。',48,'全唐诗/poet.song.10000.json','["遠日春風外，韶光晚思前。", "短青平野樹，斜碧半樓天。", "芝朮參雲嶺，桑麻冒蕨田。", "詩成無所况，題作詠懷篇。"]'),
('2203783b-6c12-406b-b382-9960fdc9cffe','北臺  其二','宋庠','宋','宋诗','song-poetry','','[]','城堞俯漳湍，關河遠近看。',48,'全唐诗/poet.song.10000.json','["城堞俯漳湍，關河遠近看。", "曉山天外紫，秋日霧中寒。", "短鬢却成葆，孤心轉似丹。", "蕭家窮僻地，歸去養衰殘。"]'),
('6aa8d7f4-3ffc-4a7e-83e9-d213c1a89bbf','善惠師禪齋','宋庠','宋','宋诗','song-poetry','','[]','象馬王城地，禪扃此獨開。',48,'全唐诗/poet.song.10000.json','["象馬王城地，禪扃此獨開。", "漏聲隨葉換，風意繞幡來。", "馴鴿依齋樹，飛花戀講臺。", "朝珂時一集，併爲碧雲才。"]'),
('bbdcb491-7e53-4e52-ba5c-afe3f49c28e5','臨秋三首  其一','宋庠','宋','宋诗','song-poetry','','[]','兀坐臨秋水，悠然到夕霏。',48,'全唐诗/poet.song.10000.json','["兀坐臨秋水，悠然到夕霏。", "蓮叢經雨折，菰米待霜肥。", "有餌潜鱗出，無軒野鶴飛。", "騶呼且勿遽，更待月華歸。"]'),
('acb0a7a1-4ca4-444c-ae9e-ca2bd39cef8b','臨秋三首  其二','宋庠','宋','宋诗','song-poetry','','[]','素潦沙成岸，蒼條柳映津。',48,'全唐诗/poet.song.10000.json','["素潦沙成岸，蒼條柳映津。", "蟬休疑惜己，蜻去似猜人。", "紺幕隨天遠，瓊鉤伴月新。", "清風時一至，吹盡故纓塵。"]'),
('ec742920-68b8-4570-a7a4-df6f0ccafcfe','臨秋三首  其三','宋庠','宋','宋诗','song-poetry','','[]','脫葉金霜罷，滄洲滿目前。',48,'全唐诗/poet.song.10000.json','["脫葉金霜罷，滄洲滿目前。", "林風寒結籟，溪日晚留煙。", "獨木橫官彴，方苞入稻田。", "持麾更吏隠，殊覺主恩偏。"]'),
('4feb3fe1-2dc7-4201-98f5-e2d0d3a33113','次韵和西堂風霾','宋庠','宋','宋诗','song-poetry','','[]','霧氣疑成雨，終風亟挫春。',48,'全唐诗/poet.song.10000.json','["霧氣疑成雨，終風亟挫春。", "祗驚天灑礫，寧是暮吹塵。", "大旆亡空澤，奔車僨要津。", "高樓非可望，偏汗扇中人。"]'),
('c19da4ec-956e-4f57-8f7b-5298b58d16a1','謁龍門無畏師塔祈雨作','宋庠','宋','宋诗','song-poetry','','[]','梵聖遺靈骨，洪緣福故都。',48,'全唐诗/poet.song.10000.json','["梵聖遺靈骨，洪緣福故都。", "慈深雲不斷，法徧雨常俱。", "使節開真槨，天香奉供爐。", "拳拳依帝力，餘潤冀昭蘇。"]'),
('71f2d1b8-ba43-460f-9e26-9d7327d4cdba','過普明禪院二首  其一','宋庠','宋','宋诗','song-poetry','','[]','自昔仁爲里，于今福作田。',48,'全唐诗/poet.song.10000.json','["自昔仁爲里，于今福作田。", "清風殘竹地，寶色故池天。", "繪象成真侶，家聲入梵緣。", "一披龍藏集，無復歎亡篇。"]'),
('ba1b69d1-d033-403c-96c4-2b0be6490bd9','過普明禪院二首  其二','宋庠','宋','宋诗','song-poetry','','[]','軒冕唐年客，溪林洛社坊。',48,'全唐诗/poet.song.10000.json','["軒冕唐年客，溪林洛社坊。", "雖開居士室，未壞魯恭堂。", "佛樹高彌綠，天花落更香。", "惟餘名不滅，來伴法燈長。"]'),
('7d543bc8-0c7b-4fd6-87b4-4662c141a67c','浮橋','宋庠','宋','宋诗','song-poetry','','[]','東潬雙津隘，浮梁古制存。',48,'全唐诗/poet.song.10000.json','["東潬雙津隘，浮梁古制存。", "灘移淤岸勢，標謔漲波痕。", "逆浪船排首，周阿纜植根。", "祀勞如舉典，元凱有英魂。"]'),
('d2f8fbaa-0ef3-4db6-8bb3-509db1d6c191','讀書多所廢忘','宋庠','宋','宋诗','song-poetry','','[]','舊學紛無幾，幽懷斷復尋。',48,'全唐诗/poet.song.10000.json','["舊學紛無幾，幽懷斷復尋。", "蒼茫萬機論，零落九州箴。", "枉嗜韋編讀，猶依槁簡吟。", "時無袁伯業，孤陋任年侵。"]'),
('8a4b6f61-3ecf-432a-87a5-f7909d1b9d92','晨興讀書','宋庠','宋','宋诗','song-poetry','','[]','老病何爲者，陵晨縹帙開。',48,'全唐诗/poet.song.10000.json','["老病何爲者，陵晨縹帙開。", "終無經世略，似有著書才。", "史記金藏匱，春秋玉作杯。", "吾心聊自適，萬事已焉哉。"]'),
('6a65c06b-384b-4533-b0c4-cd29b008dad6','守洛','宋庠','宋','宋诗','song-poetry','','[]','久玷疇咨地，新蒙策免恩。',48,'全唐诗/poet.song.10000.json','["久玷疇咨地，新蒙策免恩。", "往非堪咋舌，來寵夢驚魂。", "病與疑弓釋，身隨散櫟存。", "惟餘太陽照，終不礙孤盆。"]'),
('3334231c-fca5-4250-a390-246eaae7d489','次韵和吳侍郎睡足成詠','宋庠','宋','宋诗','song-poetry','','[]','何處西臺樂，高眠萬慮沈。',48,'全唐诗/poet.song.10000.json','["何處西臺樂，高眠萬慮沈。", "盃盤春席罷，風雨畫堂深。", "氣勝龜調息，魂交蝶伴心。", "有人驚曉漏，顛倒整衣簪。"]'),
('f7194fd4-4e69-4716-9f84-06211c76ba48','晚歲感舊寄永興相國晏公','宋庠','宋','宋诗','song-poetry','','[]','誤知三十載，頑魯寄洪鈞。',48,'全唐诗/poet.song.10000.json','["誤知三十載，頑魯寄洪鈞。", "物比青氈舊，年驚白髮新。", "河冰斜界陝，關樹曲遮秦。", "何日陪師席，孤懷跪自陳。"]'),
('e99b4f0c-a35b-4548-946a-8b45a056a43c','聞安道舍爲鄰火所焚','宋庠','宋','宋诗','song-poetry','','[]','里旅聞遺燎，連甍委夕煨。',48,'全唐诗/poet.song.10000.json','["里旅聞遺燎，連甍委夕煨。", "初無徙薪智，枉被及魚災。", "勺水寧堪救，三車諒未摧。", "天知君自足，聊復寄靈臺。"]'),
('3f61ef15-bc94-4678-80fc-8b83a183ef0d','南軒望雨','宋庠','宋','宋诗','song-poetry','','[]','層靄冒遥城，風長雨足輕。',48,'全唐诗/poet.song.10000.json','["層靄冒遥城，風長雨足輕。", "暗雲依電簇，微日記虹明。", "樹洗連帷出，荷翻百琲傾。", "幸無漂麥慮，舒嘯倚前楹。"]'),
('88e0b2df-2b43-4c61-a1e8-f4b4f548fdb2','夕雨','宋庠','宋','宋诗','song-poetry','','[]','春溜簷聲細，層波幕影斜。',48,'全唐诗/poet.song.10000.json','["春溜簷聲細，層波幕影斜。", "雷車陳后館，雲枕楚王家。", "桂凝霞杯蟻，蓮空蜜炬花。", "莫漂枝上蝶，幽夢在天涯。"]'),
('19d36323-4a7f-4749-a6d1-f0f0fe459c9a','雨歇','宋庠','宋','宋诗','song-poetry','','[]','急澍乘雲度，凉煙落晚留。',48,'全唐诗/poet.song.10000.json','["急澍乘雲度，凉煙落晚留。", "山顔紅露日，田尾濁鳴溝。", "知倦翩翩鳥，來思濕濕牛。", "東菑聊騁望，偏識種瓜疇。"]'),
('208d7cdb-33f9-436e-ada3-80a926f86079','池上觀雨','宋庠','宋','宋诗','song-poetry','','[]','急雨橫塘晚，蕭蕭逼坐隅。',48,'全唐诗/poet.song.10000.json','["急雨橫塘晚，蕭蕭逼坐隅。", "斜津添竹淚，繁點溢荷珠。", "泥重聊休燕，波翻尚浴鳬。", "風霆河外惡，橋卒弗傳呼。"]'),
('30d2975b-b180-4e6b-bd87-f93f4c936d82','送太常魚博士通守漢州','宋庠','宋','宋诗','song-poetry','','[]','春霰霽征塗，離人向蜀初。',48,'全唐诗/poet.song.10000.json','["春霰霽征塗，離人向蜀初。", "還拋博士蕝，貪佐使君旟。", "藻思夸名閣，忠懷慕叱車。", "布刀多計吏，行矣數通書。"]'),
('18b47c9d-50e2-42ef-985f-8913f697387b','冬行西圃溪上','宋庠','宋','宋诗','song-poetry','','[]','故柳樊官圃，新禾上野場。',48,'全唐诗/poet.song.10000.json','["故柳樊官圃，新禾上野場。", "晚煙林外紫，昏日水中光。", "菊晚香猶在，橙寒味不長。", "蕭然成隠趣，況復近山陽。"]'),
('2c9d9850-2350-4e43-ab2e-7c54f52b6deb','四月十五日晚出溪上留連不能去','宋庠','宋','宋诗','song-poetry','','[]','偶來尋晚景，便覺滌囂煩。',48,'全唐诗/poet.song.10000.json','["偶來尋晚景，便覺滌囂煩。", "岸柳相攙綠，風荷各自翻。", "歸雲何處宿，驚鶩或時喧。", "不奈滄波闊，鳩山有故源。"]'),
('30dd4b78-f447-48cb-b009-6a9337b01ee8','譏俗','宋庠','宋','宋诗','song-poetry','','[]','白雪賡歌苦，華顛答難頻。',48,'全唐诗/poet.song.10000.json','["白雪賡歌苦，華顛答難頻。", "寒驚穿履客，餓恥祭墦人。", "洴澼金終賤，胡盧瑣未真。", "原生寧是病，結駟往相親。"]'),
('9c58b777-49bc-4728-894b-0c1ed250d69c','送譚秘校赴江陵理曹掾先過衡陽別墅','宋庠','宋','宋诗','song-poetry','','[]','吾彀飛名早，卿軍補掾新。',48,'全唐诗/poet.song.10000.json','["吾彀飛名早，卿軍補掾新。", "還家雁峰地，趨府鶴袍人。", "樹色圍荆壘，江聲瀉蜀津。", "無輕束矢訟，陰德及斯民。"]'),
('a860fe65-b4ad-4b3b-9b27-7bf967f3fd7e','貧病','宋庠','宋','宋诗','song-poetry','','[]','貧病兩何緣，相將百慮煎。',48,'全唐诗/poet.song.10000.json','["貧病兩何緣，相將百慮煎。", "儲空擔石粟，書貸倍稱錢。", "客訝甘螬李，偷驚昔故氈。", "因聲謝才鬼，擬作送窮船。"]'),
('9b0ae117-e349-400f-bf6a-0fbe12e6b2d2','秋湖上晚景四首  其一','宋庠','宋','宋诗','song-poetry','','[]','小小江山國，輕輕縞紵衣。',48,'全唐诗/poet.song.10000.json','["小小江山國，輕輕縞紵衣。", "波光清作面，天勢碧成圍。", "岸蝶隨人舞，沙鷗掠坐飛。", "此心兼此境，安得不忘機。"]'),
('9bb14521-ffd8-48d3-8025-f542d9c1bb6c','秋湖上晚景四首  其二','宋庠','宋','宋诗','song-poetry','','[]','曲檻堪何倚，幽芳幾獨尋。',48,'全唐诗/poet.song.10000.json','["曲檻堪何倚，幽芳幾獨尋。", "頹雲山露頂，孤月水呈心。", "翹鷺多依淺，驚魚更就深。", "歸懷無晤語，身世兩浮沈。"]'),
('276b5b09-ae4c-4ed6-9e94-367a36d0477a','秋湖上晚景四首  其三','宋庠','宋','宋诗','song-poetry','','[]','春溜來無限，新蒲綠未齊。',48,'全唐诗/poet.song.10000.json','["春溜來無限，新蒲綠未齊。", "蒼煙山带北，紅浪日平西。", "野鶩時孤往，林鸚忽並啼。", "一篇行一曲，依約似青溪。"]'),
('4665c1ba-2231-4dfd-8ab6-e31d1be4ed1b','秋湖上晚景四首  其四','宋庠','宋','宋诗','song-poetry','','[]','浦溆春初滿，風煙晚不銷。',48,'全唐诗/poet.song.10000.json','["浦溆春初滿，風煙晚不銷。", "泛杯橫截竇，通舫小開橋。", "蓮葉抽萍面，藤梢落樹腰。", "此中無駭浪，容易打雙橈。"]'),
('516f6fe5-c41a-45f4-9f3f-ee6c99cc6cdf','北樓晚景','宋庠','宋','宋诗','song-poetry','','[]','脩曲少城偏，臨秋坐眇然。',48,'全唐诗/poet.song.10000.json','["脩曲少城偏，臨秋坐眇然。", "殘陽鴉翅外，新月鳥行邊。", "隠軫齊侵地，蒼茫魯狩田。", "登高何必賦，歸意自悁悁。"]'),
('f4c8704d-9e61-410e-8572-f18aa657921a','寄李端明獻臣','宋庠','宋','宋诗','song-poetry','','[]','學道年嗟晚，知非骨已驚。',48,'全唐诗/poet.song.10000.json','["學道年嗟晚，知非骨已驚。", "世紛誇要路，天意罪浮名。", "汶上朱轓寵，淮南白髮生。", "惟餘方寸地，留貯歲寒情。"]'),
('6cfc8445-0419-4966-bc48-e5b09575d517','次韵和吳侍郎寄致政張郎中以令子倅府迎侍河陽','宋庠','宋','宋诗','song-poetry','','[]','序齒顛毛貴，傳家子綬青。',48,'全唐诗/poet.song.10000.json','["序齒顛毛貴，傳家子綬青。", "蘭芳應作膳，椿老別添齡。", "逸豫鴻排陸，歡心鯉過庭。", "幾時陪雅集，醉弁一俄星。"]'),
('ab66c62c-8ae9-4ace-8495-f99ff9f22c18','奉和御製龍圖等閣觀三聖御書','宋庠','宋','宋诗','song-poetry','','[]','羣玉中天府，珍圖綠錯文。',48,'全唐诗/poet.song.10000.json','["羣玉中天府，珍圖綠錯文。", "叢楹開禹穴，寶畫爛堯雲。", "萬牒真行辨，千題甲乙分。", "聖心尊世烈，披玩不知勤。"]'),
('29e2f4aa-ac31-4c71-b7d9-673d201d8e11','曉入謻門趨殿中馬上作','宋庠','宋','宋诗','song-poetry','','[]','鑰出馳宮路，更餘送曉籌。',48,'全唐诗/poet.song.10000.json','["鑰出馳宮路，更餘送曉籌。", "露盤先得日，溫樹未知秋。", "煙幕昏朱裏，風旂颺綵斿。", "鳴鞘歷宣室，應爲□神休。"]'),
('ffc39fbc-1f32-4a1b-9ed6-cba7fdac7d41','豹隠堂','宋庠','宋','宋诗','song-poetry','','[]','昔日蒸青地，今茲坐嘯居。',48,'全唐诗/poet.song.10000.json','["昔日蒸青地，今茲坐嘯居。", "人瞻分虎出，庭記墮鱣餘。", "蕭墨齋猶寶，莊環室舊虛。", "嘉名傳郡志，寧減武侯廬。"]'),
('05e61e93-6667-40d6-8088-1933b2f150e0','題李洗馬歸歟堂','宋庠','宋','宋诗','song-poetry','','[]','君有誅茅地，重歸一畝宮。',48,'全唐诗/poet.song.10000.json','["君有誅茅地，重歸一畝宮。", "身同巖桂老，心似草堂空。", "昔歎魚隨餌，今歡鶴出籠。", "吾廬嵩潁畔，亦欲狎樵翁。"]'),
('b5478d54-f691-4036-baef-5217322b565e','春晦寓目','宋庠','宋','宋诗','song-poetry','','[]','春序倏云晚，高臺芳意多。',48,'全唐诗/poet.song.10000.json','["春序倏云晚，高臺芳意多。", "花成風地纈，鳥作暝林歌。", "樹氣薰繁幄，池紋疊細波。", "夾城歸騎散，煙絮徧銅駝。"]'),
('3a02e684-8e45-4f90-b514-d17fd841a13a','池鶩','宋庠','宋','宋诗','song-poetry','','[]','野水初盈沼，舒鳬亦伴游。',48,'全唐诗/poet.song.10000.json','["野水初盈沼，舒鳬亦伴游。", "雙膺時沒藻，斜陣或迎舟。", "敢厭吞腥累，真忘續脛憂。", "杜家鄰舍遠，刷羽恣淹留。"]'),
('6f764513-5f22-4430-8494-a6c8929edc7e','赴洛經鄭馬上偶成','宋庠','宋','宋诗','song-poetry','','[]','去國雖傷別，乘軺尚及春。',48,'全唐诗/poet.song.10000.json','["去國雖傷別，乘軺尚及春。", "滎風清翼蓋，鞏樹綠迎人。", "後隊金鐃響，前驅隼旆新。", "衰懷無麗賦，何以詫西賓。"]'),
('226e36cb-c24b-46ac-a7b4-7b9a31ac4f37','晨興春冷','宋庠','宋','宋诗','song-poetry','','[]','玉骨臨風怯，華釘恨带寬。',48,'全唐诗/poet.song.10000.json','["玉骨臨風怯，華釘恨带寬。", "凍醪催卯醉，小雪造春寒。", "錦瑟弦聲潤，山爐蕙炷乾。", "良辰他日意，慎勿怨花殘。"]'),
('2249b37e-08bd-4ffa-abbe-389acf7751b2','時賢多以不才誚我因自詠','宋庠','宋','宋诗','song-poetry','','[]','我本無心士，終非濟世才。',48,'全唐诗/poet.song.10000.json','["我本無心士，終非濟世才。", "虛舟人莫怒，疑虎石曾開。", "蚊負愁山重，葵傾喜日來。", "欲將嘲强解，真意轉悠哉。"]'),
('09f93371-7b30-446a-a536-526ab666b90e','題廣愛寺楞伽山亭','宋庠','宋','宋诗','song-poetry','','[]','誰覆爲山簣，工侔架海形。',48,'全唐诗/poet.song.10000.json','["誰覆爲山簣，工侔架海形。", "神鞭陰助險，佛髻巧分青。", "棟老棲煙濕，禽翻避呪靈。", "會須依定觀，一一訪巖扃。"]'),
('3e4f5e29-01a8-4778-9476-0fb94383daa0','和中丞晏尚書西園晚秋懷寄  其一','宋庠','宋','宋诗','song-poetry','','[]','節物名園晚，風煙亦媚秋。',48,'全唐诗/poet.song.10000.json','["節物名園晚，風煙亦媚秋。", "鈿梢低露竹，珠罅老霜榴。", "塢籟晴先響，窗霞暝自收。", "山楹誰侍坐，正似傅巖幽。"]'),
('575bb9d1-1823-4ca3-864c-772854e0c614','和中丞晏尚書西園晚秋懷寄  其二','宋庠','宋','宋诗','song-poetry','','[]','衆籟日蕭蕭，閒園氣寂寥。',48,'全唐诗/poet.song.10000.json','["衆籟日蕭蕭，閒園氣寂寥。", "風萍難覆水，霜葉易辭條。", "噪鵲繁聲合，寒蟬舊吹飄。", "試尋籬下菊，鄰酒濁盈瓢。"]'),
('89c6cc7d-c377-48e8-b8b7-5a9cb3917db5','城外秋晚','宋庠','宋','宋诗','song-poetry','','[]','澤莽鬰蕭條，憑高不自聊。',48,'全唐诗/poet.song.10000.json','["澤莽鬰蕭條，憑高不自聊。", "水寒陂雁集，城廢冢狐妖。", "野色空秋穫，林聲急暮樵。", "先疇東北路，鄉思託回飈。"]'),
('30e65247-a411-4793-993a-eee4a7010f14','過行慶關','宋庠','宋','宋诗','song-poetry','','[]','洛鄭東西接，河山表裏雄。',48,'全唐诗/poet.song.10000.json','["洛鄭東西接，河山表裏雄。", "嶺回千樹出，天轉兩崖通。", "虎圈周原綠，敖倉漢粟紅。", "今無楊僕恥，四海是關中。"]'),
('5605bfa4-ea78-461c-8d5c-f4fef9a4bda3','再經行慶','宋庠','宋','宋诗','song-poetry','','[]','行李纔踰鄭，關門已及周。',48,'全唐诗/poet.song.10000.json','["行李纔踰鄭，關門已及周。", "山支抱鞏合，洛尾貫河流。", "驛騎迎朱轂，封人訝白頭。", "往來何太數，慚恨見嵩丘。"]'),
('6e4c1ece-2f0f-4353-acea-da005a1597b3','添色紅','宋庠','宋','宋诗','song-poetry','','[]','景淑能藏媚，情多不頓開。',48,'全唐诗/poet.song.10000.json','["景淑能藏媚，情多不頓開。", "初疑香色老，終伴綵煙來。", "夕露濡仙纈，晴陽染醉腮。", "施朱應有意，併爲楚人材。"]'),
('3c3ddcd2-8079-4677-b2a3-23070d0240d7','郡圃觀稻','宋庠','宋','宋诗','song-poetry','','[]','誰取霜禾種，來依郡圃栽。',48,'全唐诗/poet.song.10000.json','["誰取霜禾種，來依郡圃栽。", "芒隨虎掌熟，畦作佛袍開。", "自應蟬鳴候，應無蟹囓災。", "公庖豐甑飯，知免拾顔煤。"]'),
('89ef8df0-4388-446f-a350-426eb39aecf5','歲晏城上北眺','宋庠','宋','宋诗','song-poetry','','[]','萬彙競摇落，臨高傷旅魂。',48,'全唐诗/poet.song.10000.json','["萬彙競摇落，臨高傷旅魂。", "驚飈無定響，寒日有餘昏。", "路轉平臺苑，天降覆盎門。", "惓惓心未已，曷月報君恩。"]'),
('16975403-a3b0-4152-908c-92581de70383','和中丞晏尚書西園石楠紅葉可愛','宋庠','宋','宋诗','song-poetry','','[]','幾歲江南樹，高秋洛涘園。',48,'全唐诗/poet.song.10000.json','["幾歲江南樹，高秋洛涘園。", "碧姿先雨潤，紅意後霜繁。", "影疊光風動，梢迷夕照翻。", "一陪幽興賞，容易到黄昏。"]'),
('d8f49a3c-a50d-402c-ade5-0c9276aedc0d','鸂鶒','宋庠','宋','宋诗','song-poetry','','[]','曲浦江湖漾，文禽伊洛飛。',48,'全唐诗/poet.song.10000.json','["曲浦江湖漾，文禽伊洛飛。", "愛尋芳蓼去，更伴晚霞歸。", "露溽金翹潤，菰香錦臆肥。", "主人真賞厚，慎勿去郊扉。"]'),
('4e3f4714-e7b2-4541-b151-edb25db4f7da','老屋','宋庠','宋','宋诗','song-poetry','','[]','老屋共棲遲，窮年弔影悲。',48,'全唐诗/poet.song.10000.json','["老屋共棲遲，窮年弔影悲。", "宵牀牛誤鬭，晝壁鼠無儀。", "窗北那成隠，家東益自嗤。", "因聲謝巢燕，京洛足華榱。"]'),
('dea661ae-8b71-4f20-8d2a-3e8239f8049b','曉謁城東嶽祠回馬上作','宋庠','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','洚水成災後，霜原落木秋。',48,'全唐诗/poet.song.10000.json','["洚水成災後，霜原落木秋。", "濁河雖自復，寒潦不知收。", "路壞停軺館，城摧却敵樓。", "民廛無黍稷，何術望神休。"]'),
('5636d532-390b-4028-aed0-5d95865db766','小隠春日','宋庠','宋','宋诗','song-poetry','','[]','小隠非吾土，幽懷屬暮春。',48,'全唐诗/poet.song.10000.json','["小隠非吾土，幽懷屬暮春。", "人憂原憲病，鬼笑子龍貧。", "草合看迷路，篁抽欲過鄰。", "俗嘲慵自解，鼷弩惜千鈞。"]'),
('87debc26-8cae-4eea-b9be-5c63608c8ccd','齋中焚香宴坐','宋庠','宋','宋诗','song-poetry','','[]','耳界千聲外，爐薰一室中。',48,'全唐诗/poet.song.10000.json','["耳界千聲外，爐薰一室中。", "妙心那有住，真意本無空。", "香飯凝盂白，天花蔽席紅。", "閒觀色身相，方信幻人工。"]'),
('23b8f7a5-682e-4644-bcea-98a5061fd3e3','送蘇寺丞宰廣德','宋庠','宋','宋诗','song-poetry','','[]','早捧諸侯檄，新登九列丞。',48,'全唐诗/poet.song.10000.json','["早捧諸侯檄，新登九列丞。", "庇身聊製錦，受命更懷冰。", "浦葯薰行櫂，江禾壓翠塍。", "高樓如可望，西北一長凭。"]'),
('19d00146-7df6-4c33-b5ed-7e0ece5b5892','和吳侍郎微雨中與一二親友同登香山石樓','宋庠','宋','宋诗','song-poetry','','[]','伊瀨鳴秋麓，香樓隔雨溪。',48,'全唐诗/poet.song.10000.json','["伊瀨鳴秋麓，香樓隔雨溪。", "天形林罅出，山脊霧中迷。", "岸峻靈龕密，沙平野路低。", "只應觀佛土，物物便堪齊。"]'),
('a331ebc4-6199-4cf9-a23f-32dd1239399e','歲晏感懷寄吳侍郎','宋庠','宋','宋诗','song-poetry','','[]','百慮靜相尋，蕭蕭芳歲陰。',48,'全唐诗/poet.song.10000.json','["百慮靜相尋，蕭蕭芳歲陰。", "感君辭劇日，休我冒榮心。", "歷塊疲東道，巢枝憶故林。", "霜毛秋更短，持底受華簪。"]'),
('398fc71d-eff4-4115-bc4c-7fcca4f0bcc4','同年龐汝弼赴宰臨賀見過敘別因成感詠','宋庠','宋','宋诗','song-poetry','','[]','朋好日寥落，征驂那忍聞。',48,'全唐诗/poet.song.10000.json','["朋好日寥落，征驂那忍聞。", "先成數日惡，更負十年薰。", "客棹秋瀧水，官郵暮嶺雲。", "圖南尚良食，少作弔湘文。"]'),
('d1a3e5b0-15ee-4099-9cf2-e405818c9cf8','齋居有感','宋庠','宋','宋诗','song-poetry','','[]','氣逐薰絃動，春隨畢雨殘。',48,'全唐诗/poet.song.10000.json','["氣逐薰絃動，春隨畢雨殘。", "蠹桃欹廢井，新李礙游冠。", "處晦垂轅驥，干時上坂丸。", "無人憐仲叔，平日憶豬肝。"]'),
('1c3e3cd2-6d79-4ff8-bb6f-6a6aa91179a4','立春','宋庠','宋','宋诗','song-poetry','','[]','底處春來早，依依傍日華。',48,'全唐诗/poet.song.10000.json','["底處春來早，依依傍日華。", "年光隨寶勝，陽律犯鳴笳。", "冰沼應潜坼，風枝已自斜。", "江南無驛騎，何計賞梅花。"]'),
('3d06b564-ae2a-4015-8f0d-01c979e57333','李公佐歸漢東','宋庠','宋','宋诗','song-poetry','','[]','門有聯瓜懿，人傷摻袂分。',48,'全唐诗/poet.song.10000.json','["門有聯瓜懿，人傷摻袂分。", "新篇稽奏牘，故社戀鄉枌。", "桂魄離懷苦，蘭苕夕膳薰。", "芳音毋自寶，西北足歸雲。"]'),
('cd781da8-68a4-45a5-8458-ffba45cf708f','送王秘校嶺南都講學','宋庠','宋','宋诗','song-poetry','','[]','高才嘗負俗，公薦此開榮。',48,'全唐诗/poet.song.10000.json','["高才嘗負俗，公薦此開榮。", "却領淹中學，還爲稷下卿。", "槐依鄉市綠，風入舞壇清。", "稽古方知力，騰飛自有程。"]'),
('07b22e8f-1024-40fc-931b-5d138c74da1c','歲晏思歸五首  其一','宋庠','宋','宋诗','song-poetry','','[]','歲晏坐伊川，孤襟日惘然。',48,'全唐诗/poet.song.10000.json','["歲晏坐伊川，孤襟日惘然。", "無功堪載策，有路即妨賢。", "寵辱丹心寸，年光素髮邊。", "含毫雖躑躅，自欲賦歸田。"]'),
('616a996f-5d48-4b4b-9b4b-6cc9f54fbecf','歲晏思歸五首  其二','宋庠','宋','宋诗','song-poetry','','[]','碌碌真邀寵，容容謝致君。',48,'全唐诗/poet.song.10000.json','["碌碌真邀寵，容容謝致君。", "短鳬生愧脛，狂鹿老思羣。", "急節驚流水，浮名伴薄雲。", "歸歟堪擊壤，況復值唐勳。"]'),
('42c63bc4-2bae-4894-aa25-fc2b354b16d5','歲晏思歸五首  其三','宋庠','宋','宋诗','song-poetry','','[]','昔寵塵三事，今懷念一丘。',48,'全唐诗/poet.song.10000.json','["昔寵塵三事，今懷念一丘。", "稻粱爭鶩飽，章服裹狙愁。", "心與蘧非化，年驚趙語偷。", "欲將知止意，歸謝漢恩侯。"]'),
('212e4d44-7498-4267-beee-6cd3b8723c10','歲晏思歸五首  其四','宋庠','宋','宋诗','song-poetry','','[]','潁曲多成瀨，茨山亦有村。',48,'全唐诗/poet.song.10000.json','["潁曲多成瀨，茨山亦有村。", "不知榮革履，便欲返衡門。", "邵圃瓜疇熟，陶廬菊徑存。", "敢言輕寵祿，知退是酬恩。"]'),
('860fd4af-2bad-47ae-ab11-b01a215712cd','歲晏思歸五首  其五','宋庠','宋','宋诗','song-poetry','','[]','世有功名羨，人將躁靜殊。',48,'全唐诗/poet.song.10000.json','["世有功名羨，人將躁靜殊。", "冥鴻專避弋，鬭鶡喜捐軀。", "駕敗誰矜巧，山移却信愚。", "白雲無誚我，歸意本區區。"]'),
('3a18e2a9-f666-45e4-80a4-c5bfd2a5a51c','主薦後喧訟不已','宋庠','宋','宋诗','song-poetry','','[]','昔賁丘園聘，今嗟勢利趨。',48,'全唐诗/poet.song.10000.json','["昔賁丘園聘，今嗟勢利趨。", "何嘗輕九九，自欲較銖銖。", "鉤百勞筋敗，朝三怒氣粗。", "因聲謝鄉校，真賞愧非夫。"]'),
('05bcb066-6fd2-480a-81af-80b81e090d1b','自寶應踰嶺至潜溪臨水煎茶','宋庠','宋','宋诗','song-poetry','','[]','關塞雲西路，僧廬左右開。',48,'全唐诗/poet.song.10000.json','["關塞雲西路，僧廬左右開。", "過巖逢石坐，尋水到源回。", "天籟吟松塢，雲腴溢茗杯。", "宮城纔十里，導騎莫相催。"]'),
('c41a5d9b-8d79-4c68-a4bc-7a41d9deaa29','致仕得請泛舟歸第','宋庠','宋','宋诗','song-poetry','','[]','輔郡初辭節，孤舟始去官。',48,'全唐诗/poet.song.10000.json','["輔郡初辭節，孤舟始去官。", "橋頭帆影急，枕底浪聲寒。", "好爵云誰寵，危心且自安。", "賜車誠可愛，閒共子孫看。"]'),
('6098cb0a-1aa4-4b75-8313-2638fbceec35','哭子正直講','宋庠','宋','宋诗','song-poetry','','[]','頍弁王門客，橫經胄席師。',48,'全唐诗/poet.song.10000.json','["頍弁王門客，橫經胄席師。", "頻揚四巡頌，屢析六身疑。", "寂寞終嘲白，侏儒詎信饑。", "一朝嗟溘盡，福善亦予欺。"]'),
('9c9a94c7-d087-4355-bbc1-0255cb72ba31','柳嘲竹','宋庠','宋','宋诗','song-poetry','','[]','好在碧檀欒，叢低度歲寒。',48,'全唐诗/poet.song.10000.json','["好在碧檀欒，叢低度歲寒。", "何堪裁鳳律，只好製魚竿。", "拂水烟梢潤，含風鈿葉攢。", "芳陰聊奉庇，君試仰天看。"]'),
('a5deac57-a4f9-47f8-9d4b-53e5f3520bf5','送上元張尉','宋庠','宋','宋诗','song-poetry','','[]','馳譽光英域，糊名限選條。',48,'全唐诗/poet.song.10000.json','["馳譽光英域，糊名限選條。", "州臨建業水，路出廣陵潮。", "歸思刀頭苦，離心旆影摇。", "行聞有薦牘，南闕鬰岧嶢。"]'),
('ba4feb30-46b9-4fd1-92cf-ebd1f9e89af0','送餘姚顧尉','宋庠','宋','宋诗','song-poetry','','[]','昔意青霞遠，新恩黄綬榮。',48,'全唐诗/poet.song.10000.json','["昔意青霞遠，新恩黄綬榮。", "官同吳市隠，賦壓楚鄉平。", "天霽晨帆駛，潮回夜艑輕。", "千巖勝遊近，且莫棄塵纓。"]'),
('45283f7c-84ae-44cf-bdd8-e9bdfd58b3e4','送烏程吳尉','宋庠','宋','宋诗','song-poetry','','[]','千人嘗得儁，再命尚沈僚。',48,'全唐诗/poet.song.10000.json','["千人嘗得儁，再命尚沈僚。", "左右爲容晚，東南作尉遥。", "鄉心烏鵲樹，春醉橐駝橋。", "今夕羈魂枕，前知爲別銷。"]'),
('5b5efa88-cc95-4376-bbcf-3aa2c76b5124','送常熟錢尉','宋庠','宋','宋诗','song-poetry','','[]','吏最三年集，僚英一尉沈。',48,'全唐诗/poet.song.10000.json','["吏最三年集，僚英一尉沈。", "清壺人映玉，勳券廟藏金。", "夕館淮蟾度，春篙楚汰深。", "王孫情幾許，芳草徧天潯。"]'),
('916624f1-af9a-48cc-8b81-b6f6ce767e30','送舒州懷寧尉孫景先省嚴親後赴職','宋庠','宋','宋诗','song-poetry','','[]','鄉書曾擅秀，父任此爲郎。',48,'全唐诗/poet.song.10000.json','["鄉書曾擅秀，父任此爲郎。", "却捧三銓檄，歸稱百歲觴。", "淮山瞻曉堠，皖浦轉春檣。", "無累徒勞歎，廉車竚薦章。"]'),
('70e1bca2-383b-48ee-9973-69925266f938','送高郵葉尉','宋庠','宋','宋诗','song-poetry','','[]','佛塔千名榜，銓臺再調符。',48,'全唐诗/poet.song.10000.json','["佛塔千名榜，銓臺再調符。", "空登拔萃目，未免沒階趨。", "爨桂方辭洛，羹蓴尚及吳。", "振淹知孔邇，華萼映鴻都。"]'),
('148b066d-6273-4898-846c-691cd55edc28','官況','宋庠','宋','宋诗','song-poetry','','[]','久曠三山直，空陪五日趨。',48,'全唐诗/poet.song.10000.json','["久曠三山直，空陪五日趨。", "文無飾羽巧，心有刻舟愚。", "陛戟愁饑死，關門駭寵呼。", "缺然偏自愧，乘馬與雙鳬。"]'),
('81694d12-6ebd-4261-920d-c4165f80ddd0','故歲東園植竹喜今春方芳','宋庠','宋','宋诗','song-poetry','','[]','幾日霜根地，新年綠玉陰。',48,'全唐诗/poet.song.10000.json','["幾日霜根地，新年綠玉陰。", "春來雖換葉，寒去轉虛心。", "乳節烟膏膩，空梢夕籟沈。", "何時殊實老，留遺九苞禽。"]'),
('d6c2b7fb-9ee3-4696-b06d-cf41083e7e85','蔬食','宋庠','宋','宋诗','song-poetry','','[]','何筯空圖貴，潘園且薦羞。',48,'全唐诗/poet.song.10000.json','["何筯空圖貴，潘園且薦羞。", "肥非糠籺飽，炙恥彈鴞求。", "餘薤行堪種，芳葵莫預憂。", "伯陽真意在，鼠壞棄誰收。"]'),
('337ba835-383a-4cb1-a738-f8b3ea875199','浩歎','宋庠','宋','宋诗','song-poetry','','[]','鼻濁哀吟倦，空懷浩歎盈。',48,'全唐诗/poet.song.10000.json','["鼻濁哀吟倦，空懷浩歎盈。", "心同注鉤怯，功比畫墁輕。", "俗態驚狙怒，剛腸謝鶩爭。", "淹回江外客，日夕望堯旍。"]'),
('78a675f6-dabb-42aa-b5cf-cb38f46d0a21','昔歎','宋庠','宋','宋诗','song-poetry','','[]','昔歎桴乘海，今悲澗隠松。',48,'全唐诗/poet.song.10000.json','["昔歎桴乘海，今悲澗隠松。", "連城輕僞璧，畫室畏真龍。", "靜勝將生白，機亡恥合蹤。", "誰談龜手術，洴澼換吳封。"]'),
('f4ea1607-16aa-4f1b-86ac-64fac4ba82af','侍宴集英殿因過學士院舊廬有感','宋庠','宋','宋诗','song-poetry','','[]','昔日金門署，重來素髮臣。',48,'全唐诗/poet.song.10000.json','["昔日金門署，重來素髮臣。", "故詞多削藁，前誡尚銘紳。", "寶翰餘龕鎖，仙山晦壁塵。", "更憐溫室樹，顔色老于人。"]'),
('1d30e9c3-ad3f-497d-b368-eec43119e67a','送殿丞楊備通理睦州','宋庠','宋','宋诗','song-poetry','','[]','引籍淹閨序，監州得海壖。',48,'全唐诗/poet.song.10000.json','["引籍淹閨序，監州得海壖。", "貪隨濤鷺驛，倦趁火城天。", "織紵吳儂富，垂綸漢客賢。", "遥知懷我處，霜月暝樓邊。"]'),
('dcdda94e-5e3b-47e3-8277-5958866b5e3e','讀賈誼新書','宋庠','宋','宋诗','song-poetry','','[]','誰謂賈生學，兼之文帝朝。',48,'全唐诗/poet.song.10000.json','["誰謂賈生學，兼之文帝朝。", "死憂王墜馬，生賦鵩如鴞。", "被召宣溫密，矜功絳灌驕。", "勤勤論五餌，史筆未相饒。"]'),
('d943a828-256a-4b5a-9d88-b9e6f388fd52','行舟漢口','宋庠','宋','宋诗','song-poetry','','[]','澤國風波恨，孤帆日夕征。',48,'全唐诗/poet.song.10000.json','["澤國風波恨，孤帆日夕征。", "山連吳樹綠，江入漢源清。", "鬢亂將成葆，心摇不後旌。", "銷魂千里外，寧是憶蓴羹。"]'),
('174afa4c-bb2f-4824-9026-1ec3a3ff830d','聞胡明遠記室將至','宋庠','宋','宋诗','song-poetry','','[]','昔歎都門別，今聞隴坂還。',48,'全唐诗/poet.song.10000.json','["昔歎都門別，今聞隴坂還。", "風烟背秦塞，陵邑過周關。", "松老忘年契，朱衰玩日顔。", "須君述征賦，方驗此塗艱。"]'),
('9b585b7a-8940-4304-bd76-c0303b192c6d','送謝煜赴無爲主簿','宋庠','宋','宋诗','song-poetry','','[]','懷檄倦遊都，勞勞艤客艫。',48,'全唐诗/poet.song.10000.json','["懷檄倦遊都，勞勞艤客艫。", "秋渠沿莨蕩，春塢見濡須。", "秫齊添賓酌，蘭苕入養厨。", "明年獻文地，南闕倚星榆。"]'),
('be856970-39e3-4c50-afa0-9b6bc93978f9','攝祀出城過西苑馬上作','宋庠','宋','宋诗','song-poetry','','[]','斗柄仙城曉，龍鱗下隰通。',48,'全唐诗/poet.song.10000.json','["斗柄仙城曉，龍鱗下隰通。", "三竿眺羲馭，十里過商中。", "水藉天容碧，塵依驛轍紅。", "喜聞何力語，應爲樂秋豐。"]'),
('ca9cc49c-52f7-4a0e-88e5-ce96d08065ad','關外','宋庠','宋','宋诗','song-poetry','','[]','關外崢嶸歲，河邊寂寞洲。',48,'全唐诗/poet.song.10000.json','["關外崢嶸歲，河邊寂寞洲。", "寒雲能不雨，高柳强先秋。", "野靜狐狸出，沙長雁鶩留。", "登臨雖信美，無賦可銷憂。"]'),
('40a144c4-422b-4a28-b3b5-17b866624f28','和吳侍郎寓趙中令韓王宅','宋庠','宋','宋诗','song-poetry','','[]','平昔元勳第，多年洛水頭。',48,'全唐诗/poet.song.10000.json','["平昔元勳第，多年洛水頭。", "荒池威鳳去，高棟野鴟愁。", "木老爭侵日，花寒各媚秋。", "猶欣賓館在，臨賞寄名流。"]'),
('6adabdd0-eca9-4009-bed4-7a1273a05446','至日圜丘攝事禮畢早歸馬上口占','宋庠','宋','宋诗','song-poetry','','[]','祠館宵燈罷，歸驂曉轡輕。',48,'全唐诗/poet.song.10000.json','["祠館宵燈罷，歸驂曉轡輕。", "天規斜抱苑，斗柄曲臨城。", "路記仙輿轍，林空寶雉聲。", "上元新甲子，休氣接平明。"]'),
('5d6b0f86-1203-405e-a8ee-d0650151056a','郡圃秋日二首  其一','宋庠','宋','宋诗','song-poetry','','[]','閏去秋歸早，開軒灑病襟。',48,'全唐诗/poet.song.10000.json','["閏去秋歸早，開軒灑病襟。", "曉風凌羽扇，商氣襲瑶琴。", "竹雨無情碧，荷煙底事深。", "蕭蕭差可賞，只是恨年深。"]'),
('f063982f-9926-49d1-9f17-f3b2e4da4bf8','郡圃秋日二首  其二','宋庠','宋','宋诗','song-poetry','','[]','累榭孤城側，空陂八月凉。',48,'全唐诗/poet.song.10000.json','["累榭孤城側，空陂八月凉。", "高雲收雨意，淡日作秋光。", "葉落風蟬塢，巢空社燕梁。", "變衰從此始，何術奈羣芳。"]'),
('437c502f-6083-4ec3-ab62-57dc2518748c','次韵和吳侍郎偶至城西一二名園','宋庠','宋','宋诗','song-poetry','','[]','幾曲西園路，幽深隠歲華。',48,'全唐诗/poet.song.10000.json','["幾曲西園路，幽深隠歲華。", "偶乘安道興，直過辟疆家。", "畦脈爭分溜，叢名各記花。", "身閒飛蓋遠，容易到曛霞。"]'),
('ea139baa-f6c3-4a32-b782-17c1920c6f9b','佛嶺','宋庠','宋','宋诗','song-poetry','','[]','鳳谷掩西嶺，鷲宮聯四陬。',48,'全唐诗/poet.song.10000.json','["鳳谷掩西嶺，鷲宮聯四陬。", "山晴巖獨霧，林暑澗常秋。", "風御疏清磬，雲柯抱晚樓。", "瓊芝徧諸崦，歲暮儻來游。"]'),
('2e87eb3d-890c-4c9f-906f-0b62528df184','送慶州安化元處宗主簿','宋庠','宋','宋诗','song-poetry','','[]','黄綬榮新牒，華顛惜美材。',48,'全唐诗/poet.song.10000.json','["黄綬榮新牒，華顛惜美材。", "越心枝上遠，羌思笛中來。", "烽燼和星落，刀環伴月開。", "寄言棲棘地，鸞翮少徘徊。"]'),
('084e5eb8-6a4c-46d0-b3db-896d1d754cff','送潁陰張主簿','宋庠','宋','宋诗','song-poetry','','[]','早服英雄彀，胡爲州縣勞。',48,'全唐诗/poet.song.10000.json','["早服英雄彀，胡爲州縣勞。", "荆璆不自鬻，郢雪向誰高。", "月鼓千聲疊，霜風萬竅號。", "行行星聚國，芳尺慰同袍。"]'),
('3fdde5b9-1fec-41c6-b331-1758c69b42eb','送巢縣梅主簿','宋庠','宋','宋诗','song-poetry','','[]','吳邑神仙系，梁臺英俊游。',48,'全唐诗/poet.song.10000.json','["吳邑神仙系，梁臺英俊游。", "官從鸞棘試，材俟蟻封求。", "堂桂叨聯籍，陔蘭慶奉羞。", "行行離恨苦，淮月一弦秋。"]'),
('f5cc784b-e5fe-4f08-9815-806458c7f07e','孟津歲晚十首  其一','宋庠','宋','宋诗','song-poetry','','[]','我懟流年晚，年將我志違。',48,'全唐诗/poet.song.10000.json','["我懟流年晚，年將我志違。", "終風來北怒，寒日趁西歸。", "野獸求羣騁，離鴻望影飛。", "君恩殊未報，愁憶故山薇。"]'),
('7908a1f5-2813-45fa-be42-064eefc6aa37','孟津歲晚十首  其二','宋庠','宋','宋诗','song-poetry','','[]','地闊山川嶮，風高萬卉乾。',48,'全唐诗/poet.song.10000.json','["地闊山川嶮，風高萬卉乾。", "山煙晨作暝，河氣晚催寒。", "革眼移前带，梁金晦舊冠。", "胡然坐衰靡，無客餉千丸。"]'),
('9a79674c-7ff8-4867-b8c4-94d3f0147269','孟津歲晚十首  其三','宋庠','宋','宋诗','song-poetry','','[]','隠軫分河壤，崢嶸念歲華。',48,'全唐诗/poet.song.10000.json','["隠軫分河壤，崢嶸念歲華。", "關雲沈鞏樹，樓月嘯羌笳。", "要路誰云騁，浮生會有涯。", "高哉羨門子，橫海挹朝霞。"]'),
('63f512eb-cdb3-46b6-a0ad-1ae5cb1045bf','孟津歲晚十首  其四','宋庠','宋','宋诗','song-poetry','','[]','歲籥行周矣，官齋坐悄然。',48,'全唐诗/poet.song.10000.json','["歲籥行周矣，官齋坐悄然。", "脩篁全露節，衰柳不停煙。", "霜苦雲收陣，天斜月控弦。", "寸心如斗柄，常在帝車前。"]'),
('f4a1263b-8d6b-42c6-8971-8f852c5307ac','孟津歲晚十首  其五','宋庠','宋','宋诗','song-poetry','','[]','曲岸羣芳歇，高臺倦目留。',48,'全唐诗/poet.song.10000.json','["曲岸羣芳歇，高臺倦目留。", "晉山青不斷，河潦濁難收。", "世路功名急，天衢歲月遒。", "吾生猶可養，嵩麓是耕疇。"]'),
('9287866d-bff3-464f-ae8c-aa893089740d','孟津歲晚十首  其六','宋庠','宋','宋诗','song-poetry','','[]','戍苦河兼重，星回歲聿悲。',48,'全唐诗/poet.song.10000.json','["戍苦河兼重，星回歲聿悲。", "頹雲埋雪樹，暗水入冰池。", "山疊看疑近，樓高倚更危。", "吞腥何日了，歸去茹華芝。"]'),
('60dac754-649c-471c-a859-90d367fbda48','孟津歲晚十首  其七','宋庠','宋','宋诗','song-poetry','','[]','大室東南望，分明鸞鶴飛。',48,'全唐诗/poet.song.10000.json','["大室東南望，分明鸞鶴飛。", "何嘗無路往，自是有心違。", "隠谷松聲淡，仙區藥甲肥。", "行年六十一，非外更知非。"]'),
('39db6764-6582-4c85-be51-858069bb1ca0','孟津歲晚十首  其八','宋庠','宋','宋诗','song-poetry','','[]','芳序雖摇落，吾生任屈伸。',48,'全唐诗/poet.song.10000.json','["芳序雖摇落，吾生任屈伸。", "日催輕璧士，天赦戴盆人。", "宵雁多號月，冰魚暗待春。", "自憐麋鹿性，晚節頓纓頻。"]'),
('ef7a8953-c492-4471-bef7-bbb19daabe72','孟津歲晚十首  其九','宋庠','宋','宋诗','song-poetry','','[]','昔日山林願，今茲軒冕遊。',48,'全唐诗/poet.song.10000.json','["昔日山林願，今茲軒冕遊。", "祗驚年苒苒，安議政優優。", "小雪煙橫野，殘笳月背樓。", "河邊楊樹老，不是桂淹留。"]'),
('28ac54a3-72a5-4ad4-8f1c-1f35a73cef5c','孟津歲晚十首  其一○','宋庠','宋','宋诗','song-poetry','','[]','渥赭隨顔罷，飛霜入鬢新。',48,'全唐诗/poet.song.10000.json','["渥赭隨顔罷，飛霜入鬢新。", "夜壺寒展刻，冬晷急馳輪。", "名美誠堪徇，身閒我獨親。", "聊持一樽酒，不爲畫蛇人。"]'),
('ef30f4d8-6b54-4f39-82fb-c367a2863a12','歲晚感事  其一','宋庠','宋','宋诗','song-poetry','','[]','息偃君恩厚，崢嶸歲律遷。',48,'全唐诗/poet.song.10000.json','["息偃君恩厚，崢嶸歲律遷。", "若驚曾爲寵，見嫉不因賢。", "白日孤盆外，蒼蠅尺璧前。", "東隅雖已失，忠意尚惓惓。"]'),
('ed5801d2-6403-4263-be43-b16ebff447d6','歲晚感事  其二','宋庠','宋','宋诗','song-poetry','','[]','榮路冥煩客，單車寂寞州。',48,'全唐诗/poet.song.10000.json','["榮路冥煩客，單車寂寞州。", "野氛連市漲，寒水夾城流。", "塞上真亡馬，江邊獨信鷗。", "不知芳歲晚，霜雪上人頭。"]'),
('e69645ee-cd6a-4cc6-bc29-19abf863c291','歲晚感事  其三','宋庠','宋','宋诗','song-poetry','','[]','積水千陂會，孤城一角存。',48,'全唐诗/poet.song.10000.json','["積水千陂會，孤城一角存。", "鳥烏喧晝霽，蛇虺喜冬溫。", "地夐荒民屋，天高思國門。", "楚優歌舞拙，何處强持樽。"]'),
('88764285-a8d0-42c5-b8aa-af075fd68b9c','初憩河陽郡齋三首  其一','宋庠','宋','宋诗','song-poetry','','[]','河洛周郊會，風烟晉部鄰。',48,'全唐诗/poet.song.10000.json','["河洛周郊會，風烟晉部鄰。", "人傳種花縣，地記躍魚津。", "梨棗知秋晚，桑麻驗俗淳。", "惟憂三載課，無術效臣恂。"]'),
('13ddddcb-1a66-4960-93e8-282ab5419688','初憩河陽郡齋三首  其二','宋庠','宋','宋诗','song-poetry','','[]','積晦雲初罷，餘光火尚流。',48,'全唐诗/poet.song.10000.json','["積晦雲初罷，餘光火尚流。", "疏桐凋晚日，孤扇避高秋。", "令尹何妨仕，將軍不必侯。", "此心機息轉，只好弄羣鷗。"]'),
('959a1457-62b0-4642-8553-91a2561fab94','初憩河陽郡齋三首  其三','宋庠','宋','宋诗','song-poetry','','[]','郊圃連官圃，秋陰半歲陰。',48,'全唐诗/poet.song.10000.json','["郊圃連官圃，秋陰半歲陰。", "亂流橫掠野，殘日倒穿林。", "雪擁承簪髮，丹藏戀闕心。", "思歸誰作引，從古怨瑶琴。"]'),
('10485fd4-87b1-4300-b35b-57865f830208','曉汲','宋庠','宋','宋诗','song-poetry','','[]','曉汲過春畦，高梧待鳳欹。',48,'全唐诗/poet.song.10000.json','["曉汲過春畦，高梧待鳳欹。", "甕思閒鑿隧，瓶險畏居湄。", "照影香釵墜，蠲煩素綆垂。", "寂寥無醉轄，瓢飲共棲遲。"]'),
('bd10d742-00e5-4eb0-ab5a-4691f56493f4','遲明出都','宋庠','宋','宋诗','song-poetry','','[]','曉出西郊道，回瞻北闕天。',48,'全唐诗/poet.song.10000.json','["曉出西郊道，回瞻北闕天。", "城頭雲斂蓋，關外月低弦。", "委佩辭朝紱，鳴笳逐使旃。", "老臣三去國，憑軾淚潺湲。"]'),
('ab40774e-6aa4-417f-bda1-cbc27e02bb16','次韵和吳侍郎以余偶名新花爲壓叢春見貺','宋庠','宋','宋诗','song-poetry','','[]','異草來何許，低昂曲沼濱。',48,'全唐诗/poet.song.10000.json','["異草來何許，低昂曲沼濱。", "不勝叢上意，翻作葉中春。", "逗蕊清香遠，銜跗絳彩勻。", "芳心如有屬，宜在賦詩人。"]'),
('42eee2d0-b890-4049-9bc3-0a67c9bb2c53','淮南早春風雨連日俗以爲宜','宋庠','宋','宋诗','song-poetry','','[]','淮海歲方新，層陰便浹辰。',48,'全唐诗/poet.song.10000.json','["淮海歲方新，層陰便浹辰。", "山山能作雨，物物解呈春。", "野鳥千聲異，江蕪一色勻。", "農區田溜滿，偏慰守藩臣。"]'),
('447a645d-31f8-4d47-84fe-022302e3cb08','和柴天休鄭舍人奉祠太一見懷之作','宋庠','宋','宋诗','song-poetry','','[]','初啟冬冥琯，知祠亳忌壇。',48,'全唐诗/poet.song.10000.json','["初啟冬冥琯，知祠亳忌壇。", "雲璈賡夜曲，瓊蕊供朝餐。", "真御扶飈遠，僊威抱斗寒。", "勞君懷晤語，此夕宿坡鑾。"]'),
('f6b80eaf-042b-4df1-92d8-e9231dcafc75','春晦小雨','宋庠','宋','宋诗','song-poetry','','[]','節晦春蕪歇，天高暮雨空。',48,'全唐诗/poet.song.10000.json','["節晦春蕪歇，天高暮雨空。", "輕雷遥應電，斜日倒成虹。", "陰綠苔浮水，幽光蕙轉風。", "何須俗士駕，三徑有蒿蓬。"]'),
('438e8105-9ae6-4c9a-87fd-6c0c861ac921','春夕','宋庠','宋','宋诗','song-poetry','','[]','暝色蔽孤齋，空軒向夕開。',48,'全唐诗/poet.song.10000.json','["暝色蔽孤齋，空軒向夕開。", "花低應露下，月暗覺雲來。", "燭牖輕蛾聚，風枝倦鳥猜。", "無言聊隠几，萬境一靈臺。"]'),
('afbaa5dc-1ccf-4295-a8ed-6a564183bc81','有將獨鶴行都市道上者左右奔迫野態憔悴因成短韵','宋庠','宋','宋诗','song-poetry','','[]','明心本霄漢，此路極喧埃。',48,'全唐诗/poet.song.10000.json','["明心本霄漢，此路極喧埃。", "何意鳴臯罷，翻同舞市來。", "波魚憂轍涸，海鳥避風災。", "寄語昂昂質，非君羽獨摧。"]'),
('521b3f9b-63bc-410c-b5d5-ce145fe5088d','郡齋多疾','宋庠','宋','宋诗','song-poetry','','[]','歌召非周陝，褎黄謝漢台。',72,'全唐诗/poet.song.10000.json','["歌召非周陝，褎黄謝漢台。", "名將恩共忝，衰與疾俱來。", "素髮慚犀導，朱顔藉玉杯。", "勳勞真索莫，出處尚徘徊。", "且脫平津粟，誰憂長孺灰。", "淮陽安敢薄，卧治恐非才。"]'),
('df45a595-3055-46c1-a573-ea7515b15a69','和通判刁博士屬疾次韵','宋庠','宋','宋诗','song-poetry','','[]','退食仍移疾，消煩尚偃牀。',72,'全唐诗/poet.song.10000.json','["退食仍移疾，消煩尚偃牀。", "玉姿經燬潤，松色貫寒芳。", "潄液仙池滿，觀心慧炬光。", "清魂同鶴警，妙數喜龜長。", "且答毗城問，休回楚客腸。", "定知靈氣復，新句有風霜。"]'),
('5f48af6a-4376-42cc-aa5d-e33179d448c8','進讀唐書終帙','宋庠','宋','宋诗','song-poetry','','[]','隋室重氛極，唐家景命新。',120,'全唐诗/poet.song.10000.json','["隋室重氛極，唐家景命新。", "地歸裂殘壤，天洗戰餘塵。", "遂納諸戎貢，爭陪二月巡。", "瀛洲登俊老，煙閣盡名臣。", "輕重非關鼎，興亡要在人。", "舊都紛秀麥，前事徧書筠。", "哲后疑圖暇，西廂訪古頻。", "終篇見成敗，摘句屢諮詢。", "青史嘉遺直，元龜遺聖辰。", "願將稽古意，萬一助堯仁。"]'),
('1e698390-3987-4d39-b832-defe0b2d48af','楊寺丞掌務西洛訪別','宋庠','宋','宋诗','song-poetry','','[]','長安久羈宦，門巷絕卿輿。',168,'全唐诗/poet.song.10000.json','["長安久羈宦，門巷絕卿輿。", "朝綬徒云忝，賓綦日已疏。", "何爲趨玉趾，乃肯眷蓬廬。", "九棘歷華選，四環承慶餘。", "頻叨范叔贈，時取長卿書。", "清晤輒窮景，高談寧爨蘇。", "夫何苦吏役，忽爾愴離居。", "交臂願從子，盍簪嗟棄予。", "梁郊春草後，鞏樹夏雲初。", "安石訪吟社，少游乘澤車。", "一官方效智，萬里乍紆途。", "雅節鄙時尚，高才凌太虛。", "奏篇希乙覽，刷羽遲南圖。", "行矣姑自愛，漢家方向儒。"]'),
('fbb392e4-584c-417c-8bfc-072052d07093','中秋禁林對月','宋庠','宋','宋诗','song-poetry','','[]','素籥中分夜，祥蓂對滿辰。',96,'全唐诗/poet.song.10000.json','["素籥中分夜，祥蓂對滿辰。", "千門迎皓彩，一氣洗空輪。", "凈失金釭影，寒生露掌津。", "仙京全是玉，佛界即成銀。", "宮瓦收蒼霧，天淵減翠淪。", "網珠聊借媚，紈扇枉迷真。", "爽籟通鳷鵲，斜光淡結鄰。", "孤懷無晤賞，長嘯待清晨。"]'),
('41adadeb-d5c4-4eec-9d33-fecf4ab9264d','寓宿南宮言懷','宋庠','宋','宋诗','song-poetry','','[]','始寓南臺直，偏驚素籥霜。',120,'全唐诗/poet.song.10000.json','["始寓南臺直，偏驚素籥霜。", "悲秋真騎省，出沐愧山郎。", "自許鷗機息，誰矜鶴脛長。", "塵緇洛客袂，枌老漢人鄉。", "篝燭沈幽幔，繙經襲隠囊。", "杯醪冰餘淥，硯滴瀉寒光。", "歲晚凋蘭佩，風乾裂芰裳。", "星烏繞枝倦，瑶草蔽庭荒。", "道爲虛心勝，情緣感物傷。", "勞歌少悽惻，夷路即騰驤。"]'),
('24945503-6b74-4299-8d47-312b9a2ed3e6','樞密東院秋日','宋庠','宋','宋诗','song-poetry','','[]','試問山林客，胡然廊廟中。',120,'全唐诗/poet.song.10000.json','["試問山林客，胡然廊廟中。", "借籌終不效，數馬亦何功。", "䆗窱荀池北，回環漢壘東。", "繒雲高幕潤，瑶草半庭空。", "乍失蒼門燕，初聞上苑鴻。", "凉催珍簟卷，氣襲碧簾通。", "虬箭天邊漏，烏竿物外風。", "心傾徒類藿，髮短更驚蓬。", "自諗非真相，其誰恨禿翁。", "婆娑君勿誚，併爲主恩隆。"]'),
('e10df968-b59c-4498-8563-e251cb9607bc','贈傳法光梵二大卿兼述譯場之盛','宋庠','宋','宋诗','song-poetry','','[]','梵劫扶皇歷，高才會聖門。',144,'全唐诗/poet.song.10000.json','["梵劫扶皇歷，高才會聖門。", "五天真釋種，三國舊王孫。", "譯詁生知慧，卿聯萬戶恩。", "齋熏光漢邸，結集盛秦園。", "交照無殊俗，多聞屬上根。", "學徒紛霧委，經錄燦星繁。", "妙義觀心德，華音置使翻。", "祝場千偈出，空境一燈存。", "列聖文垂象，旁行筆記源。", "院碑鰲抃島，御榜鷲巢軒。", "地倚區中勝，人緣物外尊。", "十年參凈職，于此愧忘言。"]'),
('e85d5cd8-5299-4240-ba63-b033a58bc897','寄長安端明王左丞','宋庠','宋','宋诗','song-poetry','','[]','綱轄尊華省，旌麾鎮舊秦。',168,'全唐诗/poet.song.10000.json','["綱轄尊華省，旌麾鎮舊秦。", "州榮朱轂守，公待黑頭人。", "從橐荷中密，仁風扉外春。", "才包揚馬思，政續趙張神。", "鼎餁終調鵠，天文尚翦鶉。", "山光函谷曉，柳色渭橋新。", "勒隊良家子，邀歡代舍賓。", "聲華今絕擬，事業古難倫。", "顧我非賢宰，惟朝念老臣。", "官銜溫室殿，城壘富平津。", "有秩皆踰分，無功可活民。", "餐霞聊却疾，面壁更求真。", "野屐茨峰路，漁竿潁水濱。", "拳拳知止誡，行及謝交親。"]'),
('0e3e4f7d-6d66-4e8e-b6db-57058ecf23c1','講詩徹章置酒崇政殿講官兩府宗室近臣皆預會奏御','宋庠','宋','宋诗','song-poetry','','[]','經藝尊詩學，書林眷講臣。',96,'全唐诗/poet.song.10000.json','["經藝尊詩學，書林眷講臣。", "禮將恩並渥，道與日俱新。", "聖問臨篇裕，王風即席淳。", "妙談開寶帙，高宴寵華紳。", "朝笏儀庭鷺，宗藩瑞世麟。", "天漿聊挹斗，帝曲豫回春。", "惠洽需占象，歡留景駐輪。", "諸儒稽古力，千載頌逢辰。"]'),
('f5276874-acbc-4d74-a805-b33611f68d99','次韵和觀文王尚書謝余寄示新詩','宋庠','宋','宋诗','song-poetry','','[]','久免台階重，頻遷郡守優。',120,'全唐诗/poet.song.10000.json','["久免台階重，頻遷郡守優。", "朱輪真冒寵，白髮自驚秋。", "事往情多感，年衰氣失遒。", "徘徊河裏望，凋落漢庭游。", "俚曲聊成唱，真筌不暇搜。", "空思益者友，安議賦家流。", "心町都遺跡，辭林幸見庥。", "豐謠連井甸，華札滿輕郵。", "已許瓊爲報，何妨漆更投。", "濟川毋謔我，歸夢在漁舟。"]'),
('6a2b1e80-2e04-4cab-b2af-a9ee4c08e9a1','都下燈夕','宋庠','宋','宋诗','song-poetry','','[]','火樹欝岧嶢，山車切絳霄。',72,'全唐诗/poet.song.10000.json','["火樹欝岧嶢，山車切絳霄。", "層樓移旦闕，複道借星橋。", "花散非因雨，霞多不爲朝。", "聲來知佩近，香去惜車遥。", "遇扇還聞曲，逢臺即聽簫。", "更籌且莫盡，綵月正飄颻。"]'),
('2f4b12e0-c003-4b27-954e-211ba585770a','元會觀禮呈僕射相國呂公','宋庠','宋','宋诗','song-poetry','','[]','乾歷端辰啟，王庭慶禮昭。',144,'全唐诗/poet.song.10000.json','["乾歷端辰啟，王庭慶禮昭。", "虞篇五端輯，漢句九賓朝。", "物象開蒼陸，聲明薄絳霄。", "寒依朱燎盡，春入綵旗遥。", "舞翟凌干密，蟠螭壓陛驕。", "晨光生劍珮，和氣引咸韶。", "寶極瞻垂衮，星階集珥貂。", "班時先正夏，拜祝故尊堯。", "山獻稱觴壽，雷傳浹宇謠。", "燕需雲布象，恩瀝斗回杓。", "任土虔方騁，居鄉列瑞條。", "須知容典盛，畫一頼曹蕭。"]'),
('8abc82b2-79e0-45c2-844c-e8a162186202','冬至觀兩宮盛禮奏御','宋庠','宋','宋诗','song-poetry','','[]','帝運姚華協，天元漢曆長。',288,'全唐诗/poet.song.10000.json','["帝運姚華協，天元漢曆長。", "三正來復旦，萬壽此稱觴。", "洛宅均中景，塗山采舊章。", "禮文窮竹素，歡意動梯航。", "稷野茅聯位，軒筠縠向陽。", "中天倚華闕，大火敞明堂。", "交鎩髬髵隊，填街隠轔裝。", "九關凝協氣，複道竚清光。", "子事蒸蒸極，宸儀穆穆揚。", "母慈尊莫二，君拜祉無疆。", "飾喜仙園奏，薰空佛土香。", "含飴先侑宴，襲衮始賓王。", "䆗窱宮門狄，誰何陛楯郎。", "長紳紛拱著，珍珮藹森璋。", "樹次天開帟，儲恩斗具漿。", "風烏迎細轉，霞燎儼相望。", "辨御辰承蓋，呼鞭輦出房。", "雲咸薄金石，星日上旂常。", "逸綴朱干動，多儀的馬驤。", "麟題公有姓，鷺羽客分行。", "上宰陳瑶爵，黎賢抃繡裳。", "祈齡後天老，介福委山穰。", "翼翼心同竭，渠渠澤載霶。", "詩弦滿坑谷，庖味益圓方。"]'),
('01348ddc-8afa-4657-adf7-34a0f75a40d1','出都赴鄭作','宋庠','宋','宋诗','song-poetry','','[]','初免鴻樞任，無庸白髮身。',72,'全唐诗/poet.song.10000.json','["初免鴻樞任，無庸白髮身。", "衰年雖去國，榮路尚妨人。", "官借荀池舊，恩加漢節新。", "鳴鐃先繡幰，彀騎挾朱輪。", "梁雪初收臘，滎波漸溢春。", "且持寬大詔，行及勸耕民。"]'),
('135d743d-1b09-4bad-88df-83001d823280','明堂大饗慶成奏御','宋庠','宋','宋诗','song-poetry','','[]','盛節嚴周配，宏模軼漢儀。',168,'全唐诗/poet.song.10000.json','["盛節嚴周配，宏模軼漢儀。", "還因大庭敞，就展合宮祠。", "揆序乘霜籥，涓辰襲寶龜。", "重檐開䆗窱，綴牖列參差。", "蒼邸尊圓覆，嘉牲接厚祇。", "五精均帝饗，三聖侑靈嬉。", "備物先昭德，長言各奏詩。", "美光浮羽戚，休氣冒尊彝。", "虛次天彌健，還衡斗輒隨。", "禮成無墜典，神醉答繁釐。", "解作初占雨，恩濃遂浹肌。", "歡心偕岳抃，赦驛與星馳。", "載瑞催麟筆，包鋒促虎皮。", "具臣何以報，拜首百工熙。"]'),
('547227cb-9688-4fe7-8805-d1fd6f5e5796','次韵和州府吳大資病愈後見寄之作','宋庠','宋','宋诗','song-poetry','','[]','冠蓋山川舊，星灰五載餘。',96,'全唐诗/poet.song.10000.json','["冠蓋山川舊，星灰五載餘。", "辭榮唐院使，麾守舊尚書。", "弓影臨觴悟，舟心觸物虛。", "塵埃題宇壁，汙潦汎杯渠。", "世事多榮悴，天均任慘舒。", "交情非苟合，筆力自雄攄。", "蒲坂軍旄重，河橋驛轍疏。", "歸耕年漸逼，鄉思滿柴車。"]'),
('90300b65-4813-4f21-844a-d87db8b15ba5','訪李生郊居','宋庠','宋','宋诗','song-poetry','','[]','林下一逢迎，幽人此養生。',72,'全唐诗/poet.song.10000.json','["林下一逢迎，幽人此養生。", "歌嬉入堯壤，種樹漏秦坑。", "歲晏農囷實，賓歡野饌盈。", "松黄浮晚酒，薇葉芼晨羹。", "霜樹榴房綻，陽畦藥甲榮。", "歸軒且莫駕，孤月在山楹。"]'),
('ab8a7836-82a6-4a23-aa1a-a051c8bbcc94','皇子慶誕奏御','宋庠','宋','宋诗','song-poetry','','[]','積德皇階厚，詒孫寶訓長。',96,'全唐诗/poet.song.10000.json','["積德皇階厚，詒孫寶訓長。", "祺宮前祝祉，猗殿此開祥。", "即夕銅吹律，先時日抱光。", "由來七鬯主，更重室家王。", "瑞莢隨辰滿，仙蘭備浴芳。", "已知周卜永，方驗宋宗彊。", "京甸歡餘霈，宸帷溢慶觴。", "史臣雖弱翰，行及紀元良。"]'),
('e2a491ed-ced3-4de2-ac2b-61d6ab21a4a7','初春宿雨','宋庠','宋','宋诗','song-poetry','','[]','泱漭朝雲簇，凄迷暮澍繁。',96,'全唐诗/poet.song.10000.json','["泱漭朝雲簇，凄迷暮澍繁。", "光生斷冰水，色暗夕陽原。", "牧㹀隨歸笠，棲雞占鑿垣。", "雲輜寒未發，鴻弋暝逾喧。", "庭狹坳堂隘，簷高綆溜翻。", "泥塗采薪徑，煙火緯蕭門。", "桂偃幽巖蓋，蘭滋舊畹根。", "撫柯兼擷秀，併是憶王孫。"]'),
('980b0d93-2dc8-4f34-be0b-f2b5199848bd','洛城秋雨','宋庠','宋','宋诗','song-poetry','','[]','霜月兼寒雨，高齋伴寂寥。',96,'全唐诗/poet.song.10000.json','["霜月兼寒雨，高齋伴寂寥。", "已能陰漠漠，更自韵蕭蕭。", "宮迥天低闕，津長霧失橋。", "蘆灰迷桂暈，梁屋掩霞朝。", "煙重蘭摧葉，風凄柳勁條。", "遠沉緱鶴唳，輕送洛鴻飄。", "甕圃應餘汲，芝巖定長苗。", "有人思舊隠，歸駕不須招。"]'),
('0a000145-ab97-487e-ad43-a49522f5739f','從幸化誠殿觀芝草奏御','宋庠','宋','宋诗','song-poetry','','[]','協氣流羣卉，華芝茂禁庭。',72,'全唐诗/poet.song.10000.json','["協氣流羣卉，華芝茂禁庭。", "蟺蜎蔽珍搆，囷蠢合祥經。", "霞彩滋瓊理，雲葩矗蓋形。", "周仁慚道葦，堯德讓階蓂。", "被曲宸章爛，傳芳信策青。", "從臣叨寓目，歡意浹三靈。"]'),
('437e1111-feb7-44ca-9a04-c334c207c35b','崇政殿試御試貢士中昃不暇食因私賦','宋庠','宋','宋诗','song-poetry','','[]','曩聖勤周日，虛懷軫睿思。',72,'全唐诗/poet.song.10000.json','["曩聖勤周日，虛懷軫睿思。", "方圖天輯命，詎恤食踰時。", "坐誡繁機壅，居忘側景疲。", "眷賢資德飽，詢善慰調饑。", "事帝心還小，康功服更卑。", "巍巍七百祚，歸報諒由斯。"]'),
('94412191-6049-469a-9100-b7ec63c1fe8d','寄題滑臺龍圖梅君新作西溪','宋庠','宋','宋诗','song-poetry','','[]','遥羨西溪境，鳴笳從賞頻。',72,'全唐诗/poet.song.10000.json','["遥羨西溪境，鳴笳從賞頻。", "蒲蓮應得地，魚鳥更留人。", "樹密藏川雨，隄長截路塵。", "清移嚴瀨月，歡陋習家春。", "按曲吳歈伎，酬篇禊帖賓。", "太平三輔樂，須信屬才臣。"]'),
('6654f4b2-0292-47c8-b6fd-a3a8a13d7d30','奉詔賦後苑諸殿牡丹','宋庠','宋','宋诗','song-poetry','','[]','靈囿先春啟，聯跗應候開。',72,'全唐诗/poet.song.10000.json','["靈囿先春啟，聯跗應候開。", "根隨一元毓，瑞協兩宮來。", "吐艷迎丹旭，揚芬散薄埃。", "歛煙交鈿合，側露並霞杯。", "耀彩珠翻樹，薰空蕙借煤。", "化工殫巧意，不爲翦刀催。"]'),
('6f21c8b9-02cf-45b5-baf8-dcd79bd037ea','遊大明寺','宋庠','宋','宋诗','song-poetry','','[]','總轡出西坰，寥寥旭宇明。',192,'全唐诗/poet.song.10000.json','["總轡出西坰，寥寥旭宇明。", "叢岡森地秀，飛塔恍神行。", "惠味霑仙露，疲心識化城。", "遠香來不斷，空梵過猶清。", "坐惜忘機晚，居慚緤組榮。", "撫懷今古恨，高世友僚情。", "顧慕羣芳歇，徘徊極野平。", "低雲參駐蓋，寒木隠前旌。", "風轉松添韵，霜餘菊挫英。", "碧垂天勢匝，紅上日華輕。", "壘廢麏䴥樂，池荒雁鶩鳴。", "宮垣除濞國，臺址畏軒兵。", "勝踐欣同適，沈憂悔自嬰。", "理融無物我，神照罷將迎。", "絢藻春供麗，投珍佩合聲。", "莫嗤三嘆拙，聊謝兩心傾。"]'),
('c6c63e7e-2225-4d15-b126-a7b30f5e6745','正月四日侍宴紫宸殿契丹使預會','宋庠','宋','宋诗','song-poetry','','[]','黼座披天幄，朝簪集玉除。',120,'全唐诗/poet.song.10000.json','["黼座披天幄，朝簪集玉除。", "人來重塞表，年是上皇初。", "萬岫移神島，千門敞徼廬。", "春雲低借幕，瑶斗近臨車。", "露渥仙杯溢，風和法曲徐。", "劍丸爭獻巧，橦索競凌虛。", "老柘優詞麗，交竿舞態舒。", "盤豐行炙數，冠重賜花餘。", "瑞境儀韶鳳，歡心在鎬魚。", "太平同樂意，應有史臣書。"]'),
('04ad7fcb-aafa-4a2c-a59f-d8d1141c261e','季冬立春日侍宴垂拱殿契丹使預會','宋庠','宋','宋诗','song-poetry','','[]','臘破寒猶在，春融氣已回。',72,'全唐诗/poet.song.10000.json','["臘破寒猶在，春融氣已回。", "千祥隨寶勝，萬壽入天杯。", "燕駿戎輸賮，虞韶律應灰。", "樓前風著柳，殿裏雪裝梅。", "妙戲魚龍出，歡心鳬藻催。", "欲知邦好永，奕世會鈞臺。"]'),
('0a29b5a1-f58e-4a79-81ec-110e292cb923','郡樓望嵩少作','宋庠','宋','宋诗','song-poetry','','[]','曠蕩三河闊，東西二室連。',144,'全唐诗/poet.song.10000.json','["曠蕩三河闊，東西二室連。", "埋雲峰樹短，抱日嶺霞鮮。", "黛壓周南野，嵐薰鞏右天。", "崢嶸元氣外，磅礴太虛前。", "斜麓橫包壑，傾崖碧逗煙。", "巢荒堯客隠，笙斷洛儲仙。", "夙尚臨風結，幽懷傃里縣。", "功名青史後，才器散樗邊。", "整頓登山屐，簽題煉藥篇。", "采芝應有路，種玉得無田。", "喻指存真契，如灰息世緣。", "寄聲鸞鶴侶，千載共來旋。"]'),
('a43872a4-88ab-4490-9bfc-cc06a57e4c0b','和參政丁侍郎從駕出獵','宋庠','宋','宋诗','song-poetry','','[]','詔蹕承冬令，郊畿闢狩場。',120,'全唐诗/poet.song.10000.json','["詔蹕承冬令，郊畿闢狩場。", "鈎陳來作衛，袀服正騰裝。", "表野千旌合，舒圍萬騎張。", "清塵風效職，捧轡日呈祥。", "寶畤遥驚翟，天弧即射狼。", "林空平陸險，雲斷見鷹揚。", "猛圈聊夸漢，恩羅遂祝湯。", "數功浮白飲，均惠割鮮嘗。", "別苑黄山外，仙城北斗傍。", "輔臣忠力盛，餘思滿雕章。"]'),
('883c632c-4439-4485-810c-0e1a85342514','見白髮有感','宋庠','宋','宋诗','song-poetry','','[]','昔人三十二，已賦二毛悲。',72,'全唐诗/poet.song.10000.json','["昔人三十二，已賦二毛悲。", "況乃踰强仕，何能怨始衰。", "星星簪外出，冉冉鑑中垂。", "顔負前丹渥，心驚故石移。", "袁公憂漢室，蜀客問湘纍。", "此際重搔首，孤懷君詎知。"]'),
('f2d10174-e8bb-47a9-ba08-5367510908e7','賦風','宋庠','宋','宋诗','song-poetry','','[]','噫氣含朝籟，離星動夕躔。',96,'全唐诗/poet.song.10000.json','["噫氣含朝籟，離星動夕躔。", "威靈隨漢筑，煦嫗上虞弦。", "清拂蘭臺客，徐飄鄭圃仙。", "來應憑虎嘯，去不待蛇憐。", "塞外凄天馬，林端飽露蟬。", "入松和韵古，轉蕙逐光妍。", "黄落汾睢地，悲歌易水天。", "如何箕潁上，獨取一飄捐。"]'),
('b22b0595-79cd-4076-bbc1-281f86e5e8f8','新晴','宋庠','宋','宋诗','song-poetry','','[]','夕霧休殘雨，霏霞側半輪。',72,'全唐诗/poet.song.10000.json','["夕霧休殘雨，霏霞側半輪。", "溪河雖早夏，隴麥尚餘春。", "灰月收全暈，泥龍落故鱗。", "高花樹端濕，芳篠籜梢新。", "雷去壺猶電，風來扇未塵。", "橫琴聊坐嘯，何必墊游巾。"]'),
('e78769e2-1ae7-4f8e-95cf-7912135184db','大寒夜坐有感','宋庠','宋','宋诗','song-poetry','','[]','河洛成冰候，關山欲雪天。',96,'全唐诗/poet.song.10000.json','["河洛成冰候，關山欲雪天。", "寒燈隨遠夢，殘曆卷流年。", "杯共芳醪凍，簪依短髮偏。", "毫釐九牛畔，頭角兩蝸前。", "冶外金休躍，山阿溜或穿。", "飄人誰怨瓦，使鬼尚須錢。", "招隠芝巖路，盟真玉笈篇。", "何當坐清潁，閒洗世中緣。"]'),
('831cc2fd-066c-4df9-83cb-fcd0c0b7ebea','留臺吳侍郎時泛小舟臨玩清洛輒成拙詩奉寄','宋庠','宋','宋诗','song-poetry','','[]','聞有滄洲尚，時時清洛濱。',72,'全唐诗/poet.song.10000.json','["聞有滄洲尚，時時清洛濱。", "烟波能弄檝，沙鳥不驚人。", "佛髻寒排岫，星橋晚跨津。", "湍鳴知亂石，漪碎覺跳鱗。", "玉匕停餘劑，華纓濯故塵。", "今無李元禮，仙袂許誰親。"]'),
('114350f0-2464-487d-9cfa-08a2f0529957','輦下寒食','宋庠','宋','宋诗','song-poetry','','[]','舊節雖龍忌，中都富物華。',120,'全唐诗/poet.song.10000.json','["舊節雖龍忌，中都富物華。", "有行官戶柳，無數苑牆花。", "飲市喧銀管，優場隘幰車。", "街塵盤馬燥，樹日鬭雞斜。", "蹋鞠將軍第，吹簫貴主家。", "金丸隨落宿，絲障亂朝霞。", "水暖船爭旆，風長鼓應笳。", "池邊人酩酊，殿裏客伊亞。", "畫卵賓盤盛，香糜賜品嘉。", "只應王澤厚，行樂徧天涯。"]'),
('83c33ca4-8288-4eb0-adb3-1366d61d970c','過留臺吳侍郎新葺菜市小園','宋庠','宋','宋诗','song-poetry','','[]','解選幽棲地，園居壓野開。',72,'全唐诗/poet.song.10000.json','["解選幽棲地，園居壓野開。", "清風無近至，雙派即同來。", "度彴幽人屐，臨渠醉客杯。", "倒根檉擁岸，初籜筍穿苔。", "溪石行堪釣，沙鷗已罷猜。", "宵游應更好，長負月徘徊。"]'),
('48e95bbb-2004-473b-bf8e-b1a566b47a0b','小園','宋庠','宋','宋诗','song-poetry','','[]','節物過芳苞，幽奇勝近郊。',96,'全唐诗/poet.song.10000.json','["節物過芳苞，幽奇勝近郊。", "先秋蟬棄甲，背歲鵲營巢。", "池小萍周岸，筠低露泣梢。", "摽梅資宴豆，賜臛佐晨庖。", "夕塢禽聲亂，芳蹊屐齒交。", "茂叢羅宅菊，長柄庾園匏。", "尸竊虞官謗，嘉肥愧遯爻。", "披襟時一至，未塞學心茅。"]'),
('0a5d97d0-e8fa-497a-8540-883ba3f53481','次韵和吳侍郎佳雪應祈豐年有望','宋庠','宋','宋诗','song-poetry','','[]','使節馳羣望，神休答帝祈。',144,'全唐诗/poet.song.10000.json','["使節馳羣望，神休答帝祈。", "同雲先北合，餘霰遂西飛。", "近野銀開界，遥山玉吐輝。", "梅飄知臘破，絮舞誤春歸。", "謝市人驚麵，曹風客比衣。", "稍添波面白，併作土膏肥。", "苑闊沈蒼霧，川明失素磯。", "獵場漫獸迹，農畝罷民欷。", "興覺龍沙接，寒將裸壤違。", "光迷梁日曉，潤息甕畦機。", "仙氅誰連袂，幽蘭更撫徽。", "恐應緣麗唱，歡意徹天扉。"]'),
('677da70a-c4a5-4b7d-a0c2-029895b528da','次韵和張丞相攝南郊喜王畿大稔','宋庠','宋','宋诗','song-poetry','','[]','上衮躬祠節，鳴騶出禁城。',144,'全唐诗/poet.song.10000.json','["上衮躬祠節，鳴騶出禁城。", "傅霖前灑潤，堯壤徧深耕。", "野色華兼實，歡謠斷復賡。", "民依大鈞播，政絕侈心萌。", "秋斂蠲徭版，鄉酺竚醉罌。", "露黄開徑菊，霜紫落園荆。", "蹲芋連區熟，飴荼蔽隰榮。", "日圍銜漢苑，天極抱秦京。", "聖旦千齡會，時功萬寶成。", "福釐前席問，元首載歌明。", "亮采神龜合，摛文瑞鵲驚。", "徒慚下里曲，仰頌泰階平。"]'),
('5f371bcf-e06d-4e0a-a4c4-e3146295c7a9','從幸翠芳亭觀橙','宋庠','宋','宋诗','song-poetry','','[]','祕苑羣芳歇，仙橙瑞實黄。',96,'全唐诗/poet.song.10000.json','["祕苑羣芳歇，仙橙瑞實黄。", "根非淮枳變，味冠禹苞嘗。", "宮掌遥分露，卿雲別護霜。", "金垂枝杪重，星隠葉中光。", "土效無偏色，天吹不斷香。", "臨觀回羽葆，交薦佇瑶觴。", "給客誰矜蜀，論都謾記穰。", "堯仁均異賜，休氣滿簪裳。"]'),
('f7d88808-321b-48d2-ba28-c100267ac1a1','從幸飛山教場閱武奏御','宋庠','宋','宋诗','song-poetry','','[]','武節遵時訓，神鑣御素秋。',120,'全唐诗/poet.song.10000.json','["武節遵時訓，神鑣御素秋。", "天風掃閶闔，星氣射旄頭。", "士肅先庚令，民歡載路謳。", "雷車翻藺石，蝱矢裂熊侯。", "旍首疏千隊，金聲勒萬騶。", "較能觀樹槊，超力賞亭樓。", "爽氣生威武，皇歡入宴羞。", "垂紳參注靺，凱樂間鳴球。", "雲夢誰夸獵，岐陽枉議蒐。", "欲知神武世，七德共凝猷。"]'),
('bb5efcb9-6c21-4ed0-8b4d-b6debb44305e','集賢張相國誕辰頌德十韵','宋庠','宋','宋诗','song-poetry','','[]','顥印傳侯刻，圯編翊帝圖。',120,'全唐诗/poet.song.10000.json','["顥印傳侯刻，圯編翊帝圖。", "還生王國佐，來煥泰階符。", "瑞紱雙嬰觡，祥蓬四射弧。", "從龍參震邸，附鳳入星樞。", "嗣正調元席，宏開造物爐。", "儀刑瞻魏采，勵翼矢臯謨。", "穆穆資同體，拳拳避碩膚。", "誠雖貫霜雪，誡甚勒盤孟。", "師石岡爲壽，仙春道有腴。", "欲知難老意，八柱與天俱。"]'),
('4843a8a6-6308-41da-a7aa-16e48c8b12c4','參政東平侍郎誕辰紀德','宋庠','宋','宋诗','song-poetry','','[]','帝業資寅亮，鴻鈞翊太寧。',120,'全唐诗/poet.song.10000.json','["帝業資寅亮，鴻鈞翊太寧。", "天開釣璜胄，家襲降崧靈。", "復九萌陽管，生三瑞砌蓂。", "毓賢茲表日，衛世遂傳經。", "覽德重光旦，參機茂宰庭。", "羣生倚舟檝，萬化入丹青。", "坐納藏山史，追論象服刑。", "前籌罄中悃，吉棟石基扃。", "國竚汾陽考，人祈衛武齡。", "孤心知所嚮，帝座六符星。"]'),
('617b89ab-2644-4e1b-b29c-f0465d8fe55a','故相國沂公建設學官實寵茲土近聞生徒寖盛姑復慰懷因成拙詩一章奉呈州學官因以勉導來者','宋庠','宋','宋诗','song-poetry','','[]','舊學開宏構，斯文聳奧區。',144,'全唐诗/poet.song.10000.json','["舊學開宏構，斯文聳奧區。", "由來漢丞相，善教魯諸儒。", "自昔升堂訓，于今避席趨。", "照函經滿帙，繪壁禮成圖。", "集講占庭鱣，懷賢詠谷駒。", "道存終拾芥，聲濫或逃竽。", "一簣宜無止，連城莫自沽。", "育材真孟樂，希聖乃顔徒。", "寸晷堪輕璧，繁英慎奪朱。", "霧蒸還作市，風至即名雩。", "曉圃林如泮，春郊水是洙。", "從茲弦誦地，不復歎榛蕪。"]'),
('dd4da86b-59b3-4fbe-8c16-a145931a0bf9','講讀春秋徹篇侍宴崇政殿奏御','宋庠','宋','宋诗','song-poetry','','[]','睿覽凝星璧，才儒集露門。',72,'全唐诗/poet.song.10000.json','["睿覽凝星璧，才儒集露門。", "披經窮魯記，摘句辯堯言。", "曩例褒成衮，先猷化啟源。", "香雲收寶袠，甘醑灧慈樽。", "飾喜韶音縱，均和玉色溫。", "史臣叨偉觀，炙行願殫論。"]'),
('4e3a4b24-6fcb-485d-8d2a-256e66925765','正月望夜侍宴宣德門呈昭文富丞相','宋庠','宋','宋诗','song-poetry','','[]','帝闕開金狄，仙輿下玉京。',120,'全唐诗/poet.song.10000.json','["帝闕開金狄，仙輿下玉京。", "建春天上斗，不夜海邊城。", "佛火依山出，星榆夾道明。", "清塵隨漢蹕，紫氣護軒營。", "皓月樓前近，鮮風仗裏經。", "煙雲供瑞色，簫鼓獻歡聲。", "梵宇千花落，祠光衆雉驚。", "宸儀收寶扇，台座冠朝纓。", "客守宮門燎，鷄傳徼署更。", "皇杯頻矚勸，應爲泰階平。"]'),
('00d1c23b-8c4d-46e1-8eac-d4ce55420bfc','下元日扈蹕朝拜景靈宮','宋庠','宋','宋诗','song-poetry','','[]','令月開真館，宸游薄太霄。',72,'全唐诗/poet.song.10000.json','["令月開真館，宸游薄太霄。", "躬行原廟禮，更作蕊宮朝。", "寶扇森排羽，仙輪恍御飈。", "霞觴浮桂液，瓊饌薦芝苗。", "日霽樓先曉，天深樹不凋。", "繁禧將浩劫，世世會楊寥。"]'),
('dd26f759-83b5-48eb-b4d3-9c66a0a75cb2','苦熱','宋庠','宋','宋诗','song-poetry','','[]','溽暑南方候，貞光大火天。',72,'全唐诗/poet.song.10000.json','["溽暑南方候，貞光大火天。", "流金空畏日，墮水忽驚鳶。", "掌露凉難挹，心瓜疾未蠲。", "鵩妖卑濕地，魃虐藴隆年。", "虛谷全收籟，焦原欲出烟。", "洪爐方扇物，何處預陶甄。"]'),
('356be805-5386-4a2f-920d-79be79cde2a4','庚午春觀新進士錫宴瓊林苑因書所見','宋庠','宋','宋诗','song-poetry','','[]','秘苑儀星地，羣英得雋年。',288,'全唐诗/poet.song.10000.json','["秘苑儀星地，羣英得雋年。", "飛緌鯨浦右，供帳斗城偏。", "表道槐陰直，凌氛柞影圓。", "叢楹開玉宇，華組會瓊筵。", "湛湛融君渥，渠渠奬士賢。", "銀璫尊右席，綠幘佐雙籩。", "飾喜優坊伎，均恩醵禮錢。", "沼浮澠酒淥，坻聚舜庖羶。", "場迥歌聲合，風迴舞節妍。", "柳疑添紺幄，鸚解啄鳴弦。", "臣藿心傾日，需雲象在天。", "綈囊齎睿什，鈿軸照儒篇。", "寶思垂霓爛，歡聲抃岳傳。", "珍臺紛蹇産，翠氣浩宛延。", "池訝陽烏浴，橋疑漢鵲填。", "千夫拔河索，三令奪標船。", "帳殿滄波匝，鉤梯複道連。", "瑶甍軒鳳羽，雲島壓鼇顛。", "犧觡馴靈囿，天麰蔽大田。", "江頭拔蘭紫，林下摘櫻鮮。", "玉藻初盈沼，神芝欲冒廛。", "陽溝連禹洫，陰石駭秦鞭。", "冰靜恩魚出，園空瑞鵠旋。", "繚垣包井落，別渚上風烟。"]'),
('370a7748-6c2e-41b3-afbd-f1ca45ce544b','初夏三司直宿','宋庠','宋','宋诗','song-poetry','','[]','薰序更朱籥，宵弦落翠蓂。',120,'全唐诗/poet.song.10000.json','["薰序更朱籥，宵弦落翠蓂。", "人同散騎直，天與大夫醒。", "鞅掌曹留事，羈孤坐刻銘。", "整冠誰辨謗，隠几獨忘形。", "夜色先歸樹，凉飈欲破櫺。", "鎖扉來疊鼓，卷幔入疏星。", "綷羽依枝倦，飛花墜席馨。", "憂沈雙蝶夢，病學一熊經。", "道有支離粟，心無屈曲屏。", "汰沙如未及，擬殺著書青。"]'),
('1bada5c7-b897-4528-86d5-22d28d8c1f0a','漢上春雪','宋庠','宋','宋诗','song-poetry','','[]','繁霧乘陰結，寒英匝宇飄。',72,'全唐诗/poet.song.10000.json','["繁霧乘陰結，寒英匝宇飄。", "風催洛妃舞，春伴郢人謠。", "逗浦添珠媚，縈叢掩柳嬌。", "樓空先月白，野闊助天遥。", "稍傍魚冰合，還依雉隴銷。", "一樽無與晤，幽思滿蘭苕。"]'),
('139dbffd-c640-4231-b47c-75c20f722f06','從幸儀鳳閣觀雙竹奏御','宋庠','宋','宋诗','song-poetry','','[]','曲密叢楹地，檀欒瑞植場。',72,'全唐诗/poet.song.10000.json','["曲密叢楹地，檀欒瑞植場。", "靈姿紛並秀，圓節儼相當。", "聯景知宗茂，同根識幹彊。", "翠浮睢苑日，寒待帝園霜。", "合響天供籟，分枝玉薦蒼。", "即看蕃寶實，儀鳳就徊翔。"]'),
('5c2ea62a-426d-4b67-a480-bc910608fda3','送司馬待制守河中','宋庠','宋','宋诗','song-poetry','','[]','久貳甘泉計，新陪丹府游。',72,'全唐诗/poet.song.10000.json','["久貳甘泉計，新陪丹府游。", "天深巢鶠閣，地重鑿龍州。", "驅弩軍裝盛，依蓮客藻遒。", "別魂驚黯黯，循政佇優優。", "舊畤連睢遠，長汾抱晉流。", "劭農知俗美，虞畔記耕疇。"]'),
('73ee4096-4d23-4a6f-a302-c9debb7c3752','夙退禁廬','宋庠','宋','宋诗','song-poetry','','[]','晝訪殊無補，晨趨敢憚勞。',72,'全唐诗/poet.song.10000.json','["晝訪殊無補，晨趨敢憚勞。", "官班唐內使，文牘漢諸曹。", "公吏何嘗案，邊兵久罷鏖。", "驛沈書插羽，朝絕法吹毛。", "殿樹秋陰薄，仙盤旭景高。", "君恩如許重，聊此戴山鼇。"]'),
('275b826c-ec9e-4d70-b697-df2db32ada19','度支蘇員外耆以再續翰林志見遺輒成酬贈','宋庠','宋','宋诗','song-poetry','','[]','先烈光朝右，英才出慶餘。',72,'全唐诗/poet.song.10000.json','["先烈光朝右，英才出慶餘。", "公卿太丘世，父子馬談書。", "首牘標宸藻，聯篇敘禁廬。", "摛華毛得鳳，刊畫魯無魚。", "當備芸籤目，俄光甕牖居。", "漢家求異說，高致掩虞初。"]'),
('8bf7c765-584e-4e04-b3c4-151dd7ab2456','宿鹿門寺','宋庠','宋','宋诗','song-poetry','','[]','寶剎翔鴛地，靈祠刻鹿門。',96,'全唐诗/poet.song.10000.json','["寶剎翔鴛地，靈祠刻鹿門。", "天風奏林籟，海日破巖昏。", "轉眩三休閣，莊嚴兩足尊。", "峰回徒覺秀，瀑遠不知源。", "花拂談經席，蓮沈記漏盆。", "道場欣象伏，心境息猿奔。", "逗理機如電，觀空性復根。", "三車俱有路，何處駐歸轅。"]'),
('710f6dd6-494b-4124-88c4-b9a1dcd8fc4d','自訟一首','宋庠','宋','宋诗','song-poetry','','[]','右輔朱轓守，南宮革履臣。',147,'全唐诗/poet.song.10000.json','["右輔朱轓守，南宮革履臣。", "孤螢難助日，病木獨依春。", "暗懦疑蛇客，愚忠數馬人。", "誰知溫省樹，自誡魯堂紳。", "監令車中席，江山扇外塵。", "何當能浼我，初不彊均茵。", "事往方成悔，猜除且瑩神。", "由來矜百鍊，從此惜千鈞。", "素髮慚華冕，虛舟謝要津。", "洗心良有謂，佞佛不無因。", "案上仙書{冫弓}，齋中梵㲲巾。", "更須窮僻地，香火報昌辰。"]'),
('35d15beb-c565-4a75-b259-03ff81424bb6','郊報紀事奏御','宋庠','宋','宋诗','song-poetry','','[]','陽燎修鴻報，齋居祓至誠。',96,'全唐诗/poet.song.10000.json','["陽燎修鴻報，齋居祓至誠。", "還登八觚畤，親用一元牲。", "瑞月隨黄屋，鮮雲抱紫營。", "天香浮玉帛，霄籟避咸英。", "陟配文交舉，來同福備成。", "均休敷愷澤，冠朔讓尊名。", "喜動吹莩氣，歡流浹宇聲。", "空參堯壤末，試頌泰階平。"]'),
('a4a5dab2-de76-4ba1-964f-5c2824d1c5da','大禮慶成','宋庠','宋','宋诗','song-poetry','','[]','帝揆三微曆，郊嚴七里壇。',192,'全唐诗/poet.song.10000.json','["帝揆三微曆，郊嚴七里壇。", "對修清廟饗，來接上神歡。", "閶闔開金狄，鉤陳扈玉鑾。", "軒游葩蓋密，漢兆紫營寬。", "電策千騶躍，雲柯萬戟攢。", "清塵風命伯，占表日名官。", "瑞羽叢齋邸，仙瓊飲露盤。", "啟毛牲辨栗，啐爵醑浮蘭。", "合樂迎天籟，高煙破夕寒。", "六飛回左御，雙闕敞南端。", "雍鷺翔賓紱，星鷄集赦竿。", "即時恩作解，先此化勝殘。", "善頌康衢溢，鴻名寶牒刊。", "貢圖包禹計，王業詠豳難。", "戶有更錢復，朝無賞印刓。", "史臣叨從祀，宣美愧濡翰。"]'),
('ca1f917e-c3a8-4580-b6a7-0891d85a46dc','後園秋物','宋庠','宋','宋诗','song-poetry','','[]','秋水清能淺，秋聲斷復尋。',72,'全唐诗/poet.song.10000.json','["秋水清能淺，秋聲斷復尋。", "衰荷欹似扇，新菊碎于金。", "匏熟猶垂格，藤乾倒附林。", "日光寒轉淡，山色遠彌深。", "索索羣芳歇，幽幽妙慮沉。", "薄言謝病晚，悵望丘中琴。"]'),
('04bafd5e-0dab-498f-b048-404d073d6017','寶鑑','宋庠','宋','宋诗','song-poetry','','[]','寶鑑鸞沉影，仙軿鳳翼輈。',120,'全唐诗/poet.song.10000.json','["寶鑑鸞沉影，仙軿鳳翼輈。", "腰輕時待舞，眉細不藏愁。", "洛館迷羅襪，秦桑露桂鉤。", "電微開笑靨，珠滑入歌喉。", "百子宮池暮，千絲越網稠。", "生香徒辟惡，纖草未蠲憂。", "燭短鴛鴦被，更闌翡翠幬。", "月寒喧藥杵，海闊漾霞舟。", "公子常逢燕，星姬鎮問牛。", "彫胡容一薦，溝水自分流。"]'),
('433e5d32-f366-4fe7-8184-71bf409d5152','河上歲晏','宋庠','宋','宋诗','song-poetry','','[]','久覺宦情薄，何堪星歲徂。',168,'全唐诗/poet.song.10000.json','["久覺宦情薄，何堪星歲徂。", "冰魚寒不動，沙鶴晚相呼。", "日短揮戈舍，天閒造物爐。", "河澄諸浦涸，山禿萬林枯。", "感爲中來遠，心因不倚孤。", "虛名三品祿，懦政五州符。", "稷契熙媯祚，蕭張翼漢圖。", "曩賢真命世，今忝劇非夫。", "狐偃腥臊肉，隨何腐爛儒。", "是非均一馬，多少任雙鳬。", "念老歸歟嘆，銘恩蕞爾軀。", "風聲猶栗烈，酒意近屠蘇。", "薛縣能琴客，桓家善笛奴。", "歌吟聊自適，何必矢嘉謨。"]'),
('93b02cb8-cd93-464d-9a82-74e682e7e4de','詔下有感','宋庠','宋','宋诗','song-poetry','','[]','釐席思賢久，公車下詔新。',144,'全唐诗/poet.song.10000.json','["釐席思賢久，公車下詔新。", "金酬燕市骨，蒲裹漢家輪。", "署行鄉論秀，觀光國有賓。", "臺招能賦客，關識賣符人。", "三府催偕計，諸儒待聘珍。", "掞天持筆距，連袂照袍銀。", "丹穴皆來鳳，靈淵羣躍鱗。", "請行多下客，答策有平津。", "榮路爭高足，孤生最濫巾。", "一鳴方及旦，六律肯遺春。", "類鵠猶煩刻，成龍不懼真。", "縱無清夜誦，猶繼壤歌民。"]'),
('45c21a60-e623-43c0-904c-ada02617ef8a','次韵和吳侍郎自號樂城居士','宋庠','宋','宋诗','song-poetry','','[]','世有生賢運，人歸得性場。',120,'全唐诗/poet.song.10000.json','["世有生賢運，人歸得性場。", "朝端慕安石，民里祝庚桑。", "蛇影逢真悟，龜靈取數長。", "仙畦種芝圃，佛室雨花牀。", "寄傲多行樂，觀心或坐忘。", "柳溪能作瞑，竹塢別供凉。", "慧露霑僧飯，幽霞照客觴。", "臯夔真有自，箕潁更相望。", "留務尊臺簡，私游費橐裝。", "側聆圖任切，安得久彷徉。"]'),
('79ba43a2-5d47-4ba6-a331-305dee191047','祫饗禮成','宋庠','宋','宋诗','song-poetry','','[]','孝饗邦儀重，親祠祏室開。',144,'全唐诗/poet.song.10000.json','["孝饗邦儀重，親祠祏室開。", "推尊二祧合，獻力九賓來。", "寶蔡前涓日，祥霙近弭災。", "鈎陳嚴法仗，綿蕝謹容臺。", "祓坐皇爲邸，登車斗轉魁。", "三辰隨藻衮，百末湛雲罍。", "徧祼靈心像，終歌帝祉隤。", "華紳紛嶽抃，端闕儼天回。", "蠅筆言絲慎，雞場赦鼓催。", "好生先祝網，作解遂成雷。", "賁有戔丘帛，刑無棄道灰。", "須知蒙福意，萬事入康哉。"]'),
('9a87b3df-fce0-424f-9f14-eb488c7bb2df','西都官屬咸備尹政得以仰成暇日池圃便同塵外因書所見以志一時之幸仍以東園吏隠命篇云','宋庠','宋','宋诗','song-poetry','','[]','誰謂留都劇，翻同小隠年。',168,'全唐诗/poet.song.10000.json','["誰謂留都劇，翻同小隠年。", "沐頭休吏日，閉閣讀書天。", "竹町能依沼，山樓解納煙。", "癭牀閒擁腫，茅棟自連蜷。", "岸闊沙留鳥，波平樹繫船。", "雨荷朝橐重，霜果佛脣鮮。", "玉甃浮杯地，冰涵給釀泉。", "處陰靈蔡老，背塢晚䴥眠。", "弈思纔知路，琴歡肯要弦。", "扇聲方樾外，屐齒野橋邊。", "宮鑰雖尸寵，巖廊合避賢。", "有恩淪骨髓，無術效埃涓。", "圭祀田供粟，公餐月費錢。", "不知瓜代滿，癡尹戀山川。"]'),
('1e61a455-4f22-46f5-a6b3-0000e83bb6e6','正月望日車駕謁會靈觀置酒祝禧殿','宋庠','宋','宋诗','song-poetry','','[]','上月神燈節，年康警蹕游。',96,'全唐诗/poet.song.10000.json','["上月神燈節，年康警蹕游。", "蒲池渭陽廟，銀闕海中洲。", "羽扇排雲出，飈輪抱日流。", "徧升均瑞祝，合宴寵靈休。", "畫扆霞明坐，春山彩作樓。", "鸞歌參帝樂，麟脯助皇羞。", "斟酌堯衢飲，驚呼漢殿優。", "天襟知衆樂，處處駐宸斿。"]'),
('d3cf54f7-0a6d-44b6-b9dc-ff0938d24361','求遺書','宋庠','宋','宋诗','song-poetry','','[]','政革秦餘暴，文興漢德優。',72,'全唐诗/poet.song.10000.json','["政革秦餘暴，文興漢德優。", "中經雖並集，逸典更旁求。", "使節褒遺訓，儒林補大猷。", "家無藏壁恨，人弭挾書憂。", "探穴資遐覽，燃藜竚對讎。", "因斯流略盛，終古冠緹油。"]'),
('52fb1248-fb9d-435f-9eef-8d924d5dd5f1','醜石','宋庠','宋','宋诗','song-poetry','','[]','磊落離幽壤，沈潜莫記年。',120,'全唐诗/poet.song.10000.json','["磊落離幽壤，沈潜莫記年。", "支機形迥出，藴玉勢相連。", "空穴雲猶抱，坳紋溜欲穿。", "虎蹲休怯射，羊叱待逢仙。", "峭拔希千仞，參差異一拳。", "詎聞輕宋璞，可要逐秦鞭。", "翠峙晴軒影，寒生曉檻烟。", "到公棋未勝，張顥印虛傳。", "齊碣思閒館，圯橋意舊編。", "何當成五色，鍊質補媧天。"]'),
('273cd641-140d-4338-b7c9-910798b8d295','登龜山上方寺','宋庠','宋','宋诗','song-poetry','','[]','雙樹遺真宇，青鴛切紫氛。',72,'全唐诗/poet.song.10000.json','["雙樹遺真宇，青鴛切紫氛。", "路盤千嶺出，鐘逼九天聞。", "林影隨崖斷，泉聲遇石分。", "曉風先得日，春崦易藏雲。", "佛果當軒落，仙苗護砌薰。", "客塵聊自拂，稽首貝多文。"]'),
('41fba425-d0ce-4c37-81b7-aaed031f73a1','官況','宋庠','宋','宋诗','song-poetry','','[]','發策非鄉秀，瘝官玷郡聯。',120,'全唐诗/poet.song.10000.json','["發策非鄉秀，瘝官玷郡聯。", "恩深育莪沚，技薄戴盆天。", "病骨三鍾粟，銛鋒一割鉛。", "懷能真鼫鼠，惜己甚寒蟬。", "吏笑移書卧，人譏面壁禪。", "曹符憂倥傯，邑教昧平鎸。", "席上巾釃酒，齋中易絕編。", "隙塵吹曉日，甕隧引春泉。", "戒養聊馨膳，將蕪敢命篇。", "區區犬馬志，何術謝陶甄。"]'),
('7d0a1b74-81ad-47bc-bd7d-75bd32ba0312','次韵和侍讀梅學士秋雪','宋庠','宋','宋诗','song-poetry','','[]','秋宇霜華極，翻成暮雪飄。',72,'全唐诗/poet.song.10000.json','["秋宇霜華極，翻成暮雪飄。", "影迷霄桂滿，氣助海鐘調。", "梅蘤裝宮樹，蘆花著浦苕。", "喜延梁客酒，愁敝洛人貂。", "碧瓦千溝麗，銀塘一色消。", "雅篇工狀物，精思入參寥。"]'),
('5d3bb049-f929-4c59-bd99-9cfa8f9a2478','對雪有寄','宋庠','宋','宋诗','song-poetry','','[]','芳歷崢嶸歲，平臺沆漭天。',120,'全唐诗/poet.song.10000.json','["芳歷崢嶸歲，平臺沆漭天。", "初驚飛礫集，坐覺雨花妍。", "未夜珠還乘，非春玉作田。", "何嘗甘絮後，正是占梅前。", "亂影都難擬，幽光只自鮮。", "辟寒金貯屋，障淖錦裁韉。", "回旋凌波舞，輕明飲露仙。", "去應迷粉水，來欲助瓊筵。", "有浦皆捐珮，何窗不列錢。", "幽蘭君自許，儂意怯么弦。"]'),
('86e9be5e-48e4-49f5-b5c4-a339a62070f7','郡齋對雪','宋庠','宋','宋诗','song-poetry','','[]','節晚雲雖暗，年豐氣自嘉。',120,'全唐诗/poet.song.10000.json','["節晚雲雖暗，年豐氣自嘉。", "乘寒初集霰，向夕遂韜霞。", "緩舞先縈洛，妍歌不待巴。", "無聲來物表，一色共天涯。", "露失仙人掌，春驚驛使花。", "拂簾珠淅瀝，裝樹玉查牙。", "護石雲慚素，開樓月讓華。", "海邊鷗誤客，遼左鶴迷家。", "粉液塘冰厚，瓊苗隴麥斜。", "中邦盈尺喜，何必問龍沙。"]'),
('10796434-77c2-492b-9a42-9acbac8be0f8','夏日出池上','宋庠','宋','宋诗','song-poetry','','[]','節候春雖往，年華暑未殘。',72,'全唐诗/poet.song.10000.json','["節候春雖往，年華暑未殘。", "蓮香開佛座，竹老退劉冠。", "戲渚藏赬尾，鳴臯濯素翰。", "堇葵紅不一，蒲稗綠多端。", "宜物心無對，深根氣自完。", "功名俱畫餠，虛玷擁旄官。"]'),
('d65e5436-b4df-4593-9704-54b4e9fd2b25','清輝殿雙頭牡丹','宋庠','宋','宋诗','song-poetry','','[]','禁籞含暉地，春英浥露天。',72,'全唐诗/poet.song.10000.json','["禁籞含暉地，春英浥露天。", "萬柯蒸協氣，雙蘤應祥篇。", "傃日香彌酷，乘風艷欲然。", "聯葩宸屋外，交影帝觴前。", "詠掩華跗秀，名均紫脫妍。", "朝緌歌茂貺，聲冠億斯年。"]'),
('ee73df31-64e0-45b2-a9aa-c104a0d0fcce','瑶津亭同窠雙頭牡丹','宋庠','宋','宋诗','song-poetry','','[]','太宇星津曲，靈葩帝囿中。',72,'全唐诗/poet.song.10000.json','["太宇星津曲，靈葩帝囿中。", "丹房忽三出，寶艷更雙融。", "采絢仙囊露，香翻沛筑風。", "柔祇寧愛寶，元化自爲工。", "草讓中唐瑞，蘭嗤下畹叢。", "甘泉宸象洽，無獨賦青葱。"]'),
('21f303fd-a719-4db8-a30b-8abd26f95265','送荆南李學士','宋庠','宋','宋诗','song-poetry','','[]','逢旦光華盛，登賢命數優。',168,'全唐诗/poet.song.10000.json','["逢旦光華盛，登賢命數優。", "郎星太微後，史局道山頭。", "違咫堯心屋，疏藩禹貢州。", "使旟飛隼出，臺劄偃波留。", "舊賜薰蘭被，新裝彍弩騶。", "陝分歌召伯，屠餞寵韓侯。", "澤國龍爲節，桑郊鹿並輈。", "齋中無煨酒，鈴下識輕裘。", "鹵簿分賓帟，江山入宴樓。", "蜀波餘柹盡，楚野惡氛收。", "後乘追文學，先春召督郵。", "暫稽華黼賜，聊聽昔襦謳。", "父子雲屏隔，鹽梅寶鉉求。", "歸來循吏政，終古冠緹油。"]'),
('bb623c21-ce9f-4888-aab7-7ab3e9497b44','夏日對雨','宋庠','宋','宋诗','song-poetry','','[]','岑寂省廬幽，諸曹吏始休。',72,'全唐诗/poet.song.10000.json','["岑寂省廬幽，諸曹吏始休。", "空煙催樹晚，急雨借庭秋。", "暮影層波動，簷聲萬綆流。", "縹牆明疊蘚，坳徑聚浮漚。", "亂濕緣虛隙，微凉襲翠幬。", "拙艱兼寓直，潘鬢怯搔頭。"]'),
('c9414271-186b-4c8b-aac6-de6bcd3d3bd3','從幸親稼殿觀新秧稻奏御','宋庠','宋','宋诗','song-poetry','','[]','宸扆尊農扈，滮池入禁廛。',72,'全唐诗/poet.song.10000.json','["宸扆尊農扈，滮池入禁廛。", "耨區周耜熟，分墢禹溝連。", "苒苒香塍色，油油瑞畝煙。", "弭災消暴蟘，迎稔嘒鳴蟬。", "國佇曾孫稼，天臨近署田。", "叨陪凝蹕賞，慚乏夢魚篇。"]'),
('632800bd-c257-46fc-b046-53748d508812','送刑部葉郎中出牧姑蘇','宋庠','宋','宋诗','song-poetry','','[]','星紀吳開國，雲司漢望郎。',72,'全唐诗/poet.song.10000.json','["星紀吳開國，雲司漢望郎。", "新陪豹尾乘，便襲虎頭囊。", "竹箭分兵契，鍾官辦使裝。", "苑鶑留祖席，江鶴避歸檣。", "世往高臺露，春餘野徑香。", "欲知民樂意，訟樹接維桑。"]'),
('85114bec-ec59-46d4-a38f-5baf782cb03c','訪宋氏溪園','宋庠','宋','宋诗','song-poetry','','[]','偶作城隅逝，居然物外期。',72,'全唐诗/poet.song.10000.json','["偶作城隅逝，居然物外期。", "林風瓢易覺，山雨石先知。", "藤老猶依格，溝斜更會池。", "看蟬琴誤曲，過樹路成歧。", "節近吹花酒，歡留敗襖棋。", "主人名族後，嘯竹客忘疲。"]'),
('e2472b0b-287a-4568-9dd4-e98b3b1b419f','仲微殿丞以余多難退居洊貽誨問復緘新什以勉病軀扶力牽課聊抒謝懇','宋庠','宋','宋诗','song-poetry','','[]','樸遬參邦彥，幽憂負主恩。',96,'全唐诗/poet.song.10000.json','["樸遬參邦彥，幽憂負主恩。", "投身采樵路，脫籍上車門。", "病肘垂楊老，塵眸覆鑑昏。", "於陵三咽味，楚澤九升魂。", "喘甚吳牛憊，名非衛鶴尊。", "簞瓢舍桑客，井臼寄孥村。", "引重繄心照，銜哀託涕痕。", "餘生何足問，姑學牧雞豚。"]'),
('58963165-8822-4d72-93d1-7539be9fbd73','秋日出沐感懷','宋庠','宋','宋诗','song-poetry','','[]','落落窮閻靜，蕭蕭晚歲昏。',120,'全唐诗/poet.song.10000.json','["落落窮閻靜，蕭蕭晚歲昏。", "臣饑徒索米，童小未應門。", "清世爲塵誚，私家出沐恩。", "斗回非挹酒，天遠詎兼盆。", "腐爛翔鵷鼠，青黄斷木樽。", "容容誰覬福，栩栩自交魂。", "衰柳空烟穗，寒苔疊雨痕。", "鳴蛙沈故沼，噪雀戀空園。", "有客嘲黔突，無人賞負暄。", "終期六百石，初服卧丘樊。"]'),
('c9f434ce-cc95-4a08-8fd0-ee9b1f9af288','夜出芙蓉堂','宋庠','宋','宋诗','song-poetry','','[]','北沼凉歸早，西軒火正流。',72,'全唐诗/poet.song.10000.json','["北沼凉歸早，西軒火正流。", "螢光偏愛夜，蛩語最知秋。", "好月因雲暗，清風爲樹留。", "烟來昏翠幕，霧下失滄洲。", "河轉疑天側，星回恨歲遒。", "惟餘雙鶴唳，不減到林丘。"]'),
('fb18277c-5c52-4aea-af5f-4a00bb34e421','夏日久雨','宋庠','宋','宋诗','song-poetry','','[]','澤國梅蒸早，郊雲泄雨多。',72,'全唐诗/poet.song.10000.json','["澤國梅蒸早，郊雲泄雨多。", "陰泉湧階穴，重霧宿庭柯。", "月魄藏仙馭，山頭洗佛螺。", "朝虹飲江曲，夜電發巖阿。", "纖箑清初暑，香藭辟舊疴。", "官閒門自靜，不爲翟公羅。"]'),
('5203557b-4c5f-44ae-a9b4-4e0d42ed98d9','參政李侍郎宿齋中書累日不陪歸馭因成拙句奉獻','宋庠','宋','宋诗','song-poetry','','[]','攝饗蠲祠令，精心屬輔臣。',72,'全唐诗/poet.song.10000.json','["攝饗蠲祠令，精心屬輔臣。", "齋房貪結佩，歸軾阻均茵。", "鵠鼎庖羞潔，鷄枝殿樹春。", "坐凝虛室白，行祓大宮神。", "政佇疇咨若，朝瞻已事竣。", "三秋懷盛德，方信採蕭人。"]'),
('5ad191b4-a687-46ff-b3e4-2192798105f8','和運使王密學見賞公醖','宋庠','宋','宋诗','song-poetry','','[]','公秫豐秋釀，兵厨絜燕罍。',72,'全唐诗/poet.song.10000.json','["公秫豐秋釀，兵厨絜燕罍。", "如何勤使傳，不許釂離杯。", "蟻甕方涵液，鴟幐幸載醅。", "歡游雖暫隔，飛藻已先回。", "左手螯初美，東籬菊尚開。", "故人寬禮分，一笑佇行臺。"]'),
('72942b1f-c1dd-4c70-be73-77c1decb349a','陳州獻瑞麥圖奉詔作','宋庠','宋','宋诗','song-poetry','','[]','堯壤環中甸，周麰冠百昌。',72,'全唐诗/poet.song.10000.json','["堯壤環中甸，周麰冠百昌。", "時均十雨潤，天報兩歧祥。", "善氣滋繁粒，薰風擁翠芒。", "初疑禾異畝，更覺黍非香。", "獻狀宸襟悅，披圖國頌颺。", "史臣誰汗簡，休應譜斯箱。"]'),
('e4f818a7-ff75-4559-82f1-4dbc44cd5459','太一奉祠夜即事','宋庠','宋','宋诗','song-poetry','','[]','天極三元會，星精五福游。',96,'全唐诗/poet.song.10000.json','["天極三元會，星精五福游。", "神光來集夜，邦祝此迎秋。", "導獻森威節，嚴真默翠幬。", "醴觴瓊借液，牲俎麵爲羞。", "蕊簡空歌續，金支寶焰流。", "宰衣紛曳繡，僊䙱儼居樓。", "降格雲頹席，歸歡電翼輈。", "種祠知漢德，時介萬靈休。"]'),
('8ab261e0-d68d-4486-badd-c6dab59ae47f','送給事俞學士知宣州','宋庠','宋','宋诗','song-poetry','','[]','駮議東曹重，修書秘府榮。',72,'全唐诗/poet.song.10000.json','["駮議東曹重，修書秘府榮。", "緣何厭廬久，便作偃藩行。", "戒道熊文戟，騰裝鶴膝兵。", "堯雲迷闕曙，淮雨破舟程。", "竹契將恩遠，江波共政清。", "向愁窗岫好，誰賞謝宣城。"]'),
('92c37327-0238-4afc-8d05-b4f457cf9ed5','舍人院觀御篆紫微閣榜賜宴奏御','宋庠','宋','宋诗','song-poetry','','[]','近署新層構，仙跗錫寶題。',72,'全唐诗/poet.song.10000.json','["近署新層構，仙跗錫寶題。", "凝章下天漢，布畫儼星奎。", "榜勢虬檐負，繒華鳳押棲。", "崇儒推宴豆，觀象聳朝閨。", "九張需雲洽，三休賀雀迷。", "從茲河洛奧，併在紫垣西。"]'),
('0d9ec37b-daea-4bff-ad6a-da43ce97134d','重陽節玉津園錫宴','宋庠','宋','宋诗','song-poetry','','[]','紀節符陽序，承恩出上闌。',96,'全唐诗/poet.song.10000.json','["紀節符陽序，承恩出上闌。", "厨均堯脯膳，優集漢觴歡。", "紫菊吹花酎，丹萸辟惡丸。", "秋光浮翠帟，雜蘤珥華冠。", "宮樹遥分柞，林苕且辨蘭。", "神池翻瑞鵠，帝竹隠歌鸞。", "煙闕雲中見，嚴城斗外看。", "欲知人意悅，霏霧滿歸鞍。"]'),
('6c669212-6f62-4253-937e-06da33b0cfeb','池上春物已爛漫寄東甫','宋庠','宋','宋诗','song-poetry','','[]','春物昌昌曲沼門，已宜留客置芳樽。',64,'全唐诗/poet.song.10000.json','["春物昌昌曲沼門，已宜留客置芳樽。", "柳絲到地烟無力，花臉迎陽露有痕。", "歌待瑶箱驚幕燕，舞留紈袖付庭鵾。", "清明元巳俱堪會，莫遣香槽玉液渾。"]'),
('3e64bfdb-dced-49a5-bc80-de0ece75c737','漢上春雪呈郡太守','宋庠','宋','宋诗','song-poetry','','[]','春草江南瑞霰霏，溪山千疊共清輝。',64,'全唐诗/poet.song.10000.json','["春草江南瑞霰霏，溪山千疊共清輝。", "林繁不辨妝梅落，川秀空疑月蚌歸。", "夕苑縈叢聊自舞，橫塘拂水更低飛。", "民疇脈僨農祥近，壤有堯歌絕晉饑。"]'),
('a1da7c9d-3fa8-4538-9c19-bca1ad4f73b5','贈職方齊員外','宋庠','宋','宋诗','song-poetry','','[]','霄極郎星護帝垣，出分魚竹誇歌喧。',64,'全唐诗/poet.song.10000.json','["霄極郎星護帝垣，出分魚竹誇歌喧。", "郵通五尺秦人道，吏擁雙朱漢守轓。", "粉闥荀香虛舊帳，鈴齋渝舞釂清樽。", "歸來何處應嚴召，振鷺神庭鑄馬門。"]'),
('740b53b8-625c-455f-8cbe-f4dbe89b6b0f','春季開無畏靈塔祈雨至夏初霶洽','宋庠','宋','宋诗','song-poetry','','[]','春晦西峰雁塔開，香雲清梵徹昭回。',64,'全唐诗/poet.song.10000.json','["春晦西峰雁塔開，香雲清梵徹昭回。", "初疑咒鉢降龍出，終似軍持注水來。", "百穀根莖流慧潤，四郊氛祲卷暘災。", "守臣無狀均靈貺，如驗元非贊燮才。"]'),
('686b7aa2-5ab7-4bff-854a-b085c94e501d','五鼓度洛水謁九龍祠禱雨馬上作','宋庠','宋','宋诗','song-poetry','','[]','跨陌津橋十里亭，前騶橫絕犯嚴更。',64,'全唐诗/poet.song.10000.json','["跨陌津橋十里亭，前騶橫絕犯嚴更。", "銀河蕩漾斜垂地，瑶斗闌干倒倚城。", "苑闊樹頭迷闕影，川長烟外認灘聲。", "農疇閔雨心祈切，上盡叢祠日未明。"]'),
('375b4fb3-22bd-4742-b699-2f79bde3ea87','未曉出城陪州長考功李員外禱雨大悲禪剎','宋庠','宋','宋诗','song-poetry','','[]','城上繁星五鼓初，江臯申禱訪精廬。',64,'全唐诗/poet.song.10000.json','["城上繁星五鼓初，江臯申禱訪精廬。", "林回半隠翔鴛剎，野闊平飛畫隼旟。", "十地真容陪合掌，百城甘澍待隨車。", "先秋閔雨農心樂，宜在麟編直筆書。"]'),
('04f463dc-4889-49b3-981f-f3f00a4e35fe','次韵和龍圖何學士以榮憩鄉州有感舊見存之作','宋庠','宋','宋诗','song-poetry','','[]','昔歲西都餞使旗，今茲何幸復相依。',64,'全唐诗/poet.song.10000.json','["昔歲西都餞使旗，今茲何幸復相依。", "潁川士族占星聚，遼海鄉人看鶴歸。", "乘塞惠風消戰略，論文精辯破談圍。", "衰翁不敢言恩舊，但惜匆匆別袂揮。"]'),
('95d53938-0f21-4a01-b2c2-543b2f2022d8','題酇城張氏林亭','宋庠','宋','宋诗','song-poetry','','[]','里占西豪族望雄，一隅幽概掩隆中。',64,'全唐诗/poet.song.10000.json','["里占西豪族望雄，一隅幽概掩隆中。", "彩鴛戢翼高梧在，蔚豹成章舊霧空。", "冷接安齋投轄井，細生吟榭快襟風。", "謝庭羅宅資真賞，蘭有清芬菊有叢。"]'),
('6fe187a7-2986-4c5d-b378-78d76eaffee1','夏日北溪亭上','宋庠','宋','宋诗','song-poetry','','[]','羲輪亭午爍炎威，溪上軒窗匝翠微。',64,'全唐诗/poet.song.10000.json','["羲輪亭午爍炎威，溪上軒窗匝翠微。", "野澤蒲深初類堞，壞垣苔老半成衣。", "爭花晚蝶縈叢住，避弋驚禽截浦飛。", "一袵雄風消內熱，高門無意事輕肥。"]'),
('0b615003-605b-450b-8e58-1cd19d4c92a1','次韵和吳侍郎洊貺雅篇','宋庠','宋','宋诗','song-poetry','','[]','儁輔西還玉體痊，銀臺歸興且陶然。',64,'全唐诗/poet.song.10000.json','["儁輔西還玉體痊，銀臺歸興且陶然。", "談經寶序常迎日，膝席清司最近天。", "君拂翠緌朝右貴，我驚華髮鑑中鮮。", "洛都巴俚雖求舊，莫累陽春一種傳。"]'),
('50dc1b0c-54dd-46d4-a8b8-db298a25543c','次韵和資政吳育侍郎見贈','宋庠','宋','宋诗','song-poetry','','[]','台階抽得冒榮身，且喜西都見故人。',64,'全唐诗/poet.song.10000.json','["台階抽得冒榮身，且喜西都見故人。", "儀世瑞鵷曾接翼，論交寒柏不知春。", "樽前高意青雲舊，鑑裏流年白髮新。", "爭奈詔書催上道，談犀從此日生塵。"]'),
('11b9a050-902b-4d31-bc60-064dbf3fc193','次韵和新命留臺吳侍郎自適之作','宋庠','宋','宋诗','song-poetry','','[]','謝病彌年歎偃牀，知君靈氣本無傷。',64,'全唐诗/poet.song.10000.json','["謝病彌年歎偃牀，知君靈氣本無傷。", "論筌自識忘筌意，失馬終爲得馬祥。", "心到不貪方是寶，物歸何有即名鄉。", "西都老尹歡迎近，預喜遥臨照席光。"]'),
('904c67cc-b97b-4a2a-a270-a10a2a03a929','送竇員外失職掌廩于沙苑牧監','宋庠','宋','宋诗','song-poetry','','[]','平臺飛雪欲成花，有客西征感鬢華。',64,'全唐诗/poet.song.10000.json','["平臺飛雪欲成花，有客西征感鬢華。", "內史江蓴空入夢，下邽羅雀此還家。", "鴻聲不斷關雲黑，角弄初休隴月斜。", "駉牧未妨稱吏隠，田園自有故侯瓜。"]'),
('826353ee-416f-4e7c-b67c-4aa58d206878','送謝屯田徙治富順監','宋庠','宋','宋诗','song-poetry','','[]','綠髮仙郎冠譽髦，墾田分土漢家曹。',64,'全唐诗/poet.song.10000.json','["綠髮仙郎冠譽髦，墾田分土漢家曹。", "詔頒紫檢瓊芝熟，歌闋青天劍棧高。", "巴蒟溢盤馨晝饌，郫筒環席薦春醪。", "西征自叱忠臣馭，千古王尊直筆褒。"]'),
('5b757bc4-52ad-4460-86ac-2576bb4200bb','坐舊州驛亭上作','宋庠','宋','宋诗','song-poetry','','[]','廢壘孤亭四面風，座疑身世五湖東。',64,'全唐诗/poet.song.10000.json','["廢壘孤亭四面風，座疑身世五湖東。", "長天野浪相依碧，落日殘雲共作紅。", "漁缶回環千艇合，巷蒲明滅百帆通。", "恍然歸興無人會，閒向青冥數塞鴻。"]'),
('29b712ca-92a0-441f-b198-f6b330718bb6','送石舍人賜告還鄉','宋庠','宋','宋诗','song-poetry','','[]','內史清班近侍臣，過家恩告曰俞新。',64,'全唐诗/poet.song.10000.json','["內史清班近侍臣，過家恩告曰俞新。", "郵中別夜星催曉，殿裏歸年樹約春。", "幾日詞垣棲健筆，九秋朝橐冒征塵。", "西州歸馬歡迎處，定有臨邛負弩人。"]'),
('3f1c1097-e949-4a01-9b4c-28e4e3972c3a','和吳侍郎自陝歸闕','宋庠','宋','宋诗','song-poetry','','[]','幾日星催召節飛，迎車千蓋溢郊畿。',64,'全唐诗/poet.song.10000.json','["幾日星催召節飛，迎車千蓋溢郊畿。", "秦城璧返蠅休汙，軒閣巢高鳳始歸。", "兩憩甘棠歌美化，重攀溫樹悵流暉。", "因君更感忠虔意，夕夢翩翩遶帝闈。"]'),
('8b5b6a3c-8ca2-429a-9900-e03595ce9e95','送伯中尚書學士歸闕','宋庠','宋','宋诗','song-poetry','','[]','故人同省復同班，且喜先歸奉帝鑾。',64,'全唐诗/poet.song.10000.json','["故人同省復同班，且喜先歸奉帝鑾。", "居守乍拋留宅鑰，造朝重拂寶梁冠。", "仙楹夕靄通飈馭，祕廡晨暉轉露盤。", "我有寸心空戀主，捫膺難把向君看。"]'),
('7bdcbce8-cc7e-42b2-9e91-6f776c30b6e5','酬王拱辰侍郎歸闕見贈','宋庠','宋','宋诗','song-poetry','','[]','儁譽由來服搢紳，更煩餘略霽邊塵。',64,'全唐诗/poet.song.10000.json','["儁譽由來服搢紳，更煩餘略霽邊塵。", "威留玉帳時無戰，班入金華地最親。", "昔看草辭知大筆，今榮除館識嘉賓。", "一章求舊人知否，媮俗都融郢曲春。"]'),
('883a0d0c-5c83-4f78-906c-47d8bc0399d7','送虞部元員外赴闕','宋庠','宋','宋诗','song-poetry','','[]','泥檢封香矞露濃，漢庭新冊潁川功。',64,'全唐诗/poet.song.10000.json','["泥檢封香矞露濃，漢庭新冊潁川功。", "朱轓按俗麟符郡，青被爲郎斗籍宮。", "儉幕卷雲賓履隔，郢樓翻雪餞壺空。", "明光伏奏前期近，備對芳蘭溢握紅。"]'),
('123da29c-c0e0-457d-a89a-b3ed44025e83','送苗郎中出漕江西','宋庠','宋','宋诗','song-poetry','','[]','幾夕燒熏歇被綾，東南使部望前旌。',64,'全唐诗/poet.song.10000.json','["幾夕燒熏歇被綾，東南使部望前旌。", "武泥給板言如綍，漢庾臨波粟似京。", "露橘千頭豐歲籍，江鱸百尾飫盤鯖。", "計籌暫爾煩經畫，囊橐行看用老成。"]'),
('7ca297a1-494c-4f6f-8501-92455afa38bb','和致政王子融侍郎喜昭文龐相公登庸','宋庠','宋','宋诗','song-poetry','','[]','感會由來屬儁賢，誰知出處更相先。',64,'全唐诗/poet.song.10000.json','["感會由來屬儁賢，誰知出處更相先。", "蒲且卷弋冥鴻日，荀令開池浴鳳年。", "佚老疏金催具酒，濟時商楫正橫川。", "高風盛德俱難狀，留與名山信史傳。"]'),
('0905a97d-04f7-4153-87c1-504259376657','送職方張員外領荆湖北漕','宋庠','宋','宋诗','song-poetry','','[]','粉闥仙郎鬢未秋，懿文精力允僉求。',64,'全唐诗/poet.song.10000.json','["粉闥仙郎鬢未秋，懿文精力允僉求。", "新榮亳忌祠神館，更按喬卿露冕州。", "楚匭貢茅紛騎置，蜀艘移粟蔽江流。", "富人緩役承平士，肯學研桑苦運籌。"]'),
('cc8f90d9-9ae1-4170-bc7d-8fa2799d4c5e','送孫刑部領漕并部','宋庠','宋','宋诗','song-poetry','','[]','百舍星文動使軒，漢家初賜辦裝錢。',64,'全唐诗/poet.song.10000.json','["百舍星文動使軒，漢家初賜辦裝錢。", "犀株衛帳并兒勇，鵠髮迎塗絳老賢。", "歲稔萬箱資轉粟，時平三策罷開邊。", "中宸圖舊恩方渥，幾日從容武帳前。"]'),
('d739581b-17a0-429f-8988-9e13451b5d37','九日南陽與諸公會','宋庠','宋','宋诗','song-poetry','','[]','憭慄霜華六幕空，丹萸成佩菊芬叢。',64,'全唐诗/poet.song.10000.json','["憭慄霜華六幕空，丹萸成佩菊芬叢。", "香浮彭澤仙巾酒，影落龍山宴帽風。", "詩筆娛情真泣豆，舞腰回節更驚鴻。", "夕陽嶢榭愁重顧，不見舂陵舊鬰葱。"]'),
('eac0a5e5-ae19-4c14-84aa-49abd3e304ea','無題','宋庠','宋','宋诗','song-poetry','','[]','西峙東流意欲分，紫簫呼鳳隔煙聞。',64,'全唐诗/poet.song.10000.json','["西峙東流意欲分，紫簫呼鳳隔煙聞。", "書因屢答機無素，夢爲頻驚峽費雲。", "羽帳枕寒晨未轉，玉樓衣冷夜還薰。", "琴烏一曲何曾聽，七十鴛鴦失舊羣。"]'),
('3aa26b41-1953-4dfb-afdd-d70d2a390daf','詩寄河陽夏侍中','宋庠','宋','宋诗','song-poetry','','[]','勤勤書札問青氈，鄖水逢知似曩緣。',64,'全唐诗/poet.song.10000.json','["勤勤書札問青氈，鄖水逢知似曩緣。", "海燕不忘棲厦日，霜松寧有改柯年。", "陪京玉節諸侯上，坐省華貂百辟先。", "朝夕公歸領冠劍，定應偏作故簪憐。"]'),
('5c1a8bf8-674e-4a65-b3f7-6dac43eb7a7b','和答并州經略太尉相公元日見寄','宋庠','宋','宋诗','song-poetry','','[]','邊亭春色感離居，猶記衰齡本命餘。',64,'全唐诗/poet.song.10000.json','["邊亭春色感離居，猶記衰齡本命餘。", "樽味阻陪曹相國，带圍空老沈尚書。", "軍中鼓吹千蹄馬，物外風煙一壑魚。", "幹棟不材須適分，願公容我作莊樗。"]'),
('d5fcc7fd-55f5-4dd4-b6ba-4484d12e20a2','贈潯州朱祠部','宋庠','宋','宋诗','song-poetry','','[]','粉署郎潜已十年，囊毫奏議委千篇。',64,'全唐诗/poet.song.10000.json','["粉署郎潜已十年，囊毫奏議委千篇。", "恥論頗牧雲中級，去詠齊夷海國泉。", "路控驛疆逢瑞翟，氣收炎浦見飛鳶。", "鈴齋宴坐真腴盛，幾種天花落帳前。"]'),
('e4049017-6824-47e5-b683-d21e293a2323','次韵和判曹韓學士見賞湖山','宋庠','宋','宋诗','song-poetry','','[]','西溪本慰寂寥人，何幸開樽枉勝賓。',64,'全唐诗/poet.song.10000.json','["西溪本慰寂寥人，何幸開樽枉勝賓。", "一岸仙山平壓野，兩陂官柳綠圍春。", "我雖酩酊能騎馬，君自風流偶墊巾。", "更愧和篇尋故筆，試開荷橐久生塵。"]'),
('9b58454b-197a-42dc-8525-471585886b5e','小園秋思','宋庠','宋','宋诗','song-poetry','','[]','年華摇落自騷騷，衰境牽人更畔牢。',64,'全唐诗/poet.song.10000.json','["年華摇落自騷騷，衰境牽人更畔牢。", "月裏驚烏愁夜永，篋中團扇恨風高。", "煙霏曲霤蜘蛛織，氣襲空階蟋蟀號。", "恩重才疏歸計晚，可憐身世一鴻毛。"]'),
('8074b56a-d546-428d-a63f-6e03e94a818b','三月晦日夜坐有感','宋庠','宋','宋诗','song-poetry','','[]','城頭吹角亂昏鴉，坐敞空樓感歲華。',64,'全唐诗/poet.song.10000.json','["城頭吹角亂昏鴉，坐敞空樓感歲華。", "遥電不知何處雨，狂風還送一年花。", "洛橋禊席隨流水，箕嶺仙巢倚暮霞。", "出處半生雖未决，歸心常傍故侯瓜。"]'),
('932ddae2-8937-4eb8-8edf-01dbbdfc5aeb','送廣州劉掾','宋庠','宋','宋诗','song-poetry','','[]','督府迢迢瘴海城，掾曹三語藹蘭馨。',64,'全唐诗/poet.song.10000.json','["督府迢迢瘴海城，掾曹三語藹蘭馨。", "歸郵託信梅華暖，仙劑蠲疴薏子靈。", "蚌月射樓吟思苦，雞潮驚枕醉魂醒。", "外臺誰舉沈僚俊，編著黄堂有政經。"]'),
('e9274782-68dd-46af-9c89-43ba1b32598f','溪齋春日','宋庠','宋','宋诗','song-poetry','','[]','問君何事拙謀身，竹塢溪齋養鈍人。',64,'全唐诗/poet.song.10000.json','["問君何事拙謀身，竹塢溪齋養鈍人。", "白鷺儀形閒照水，野鶑言語亂嘲春。", "半生已悔嬰朝紱，萬境方將付客塵。", "自笑經旬無宴具，對花孤坐嚥瓊津。"]'),
('1f922b11-54e8-431c-9c50-36190e9a786c','奉和御製賞花釣魚次韵私賦','宋庠','宋','宋诗','song-poetry','','[]','祕苑神池帳殿開，鈎陳遥衛斗車來。',64,'全唐诗/poet.song.10000.json','["祕苑神池帳殿開，鈎陳遥衛斗車來。", "柳舒瑞霧迎僊蹕，花獻天香入壽杯。", "戀藻文鱗爭聚散，聽韶丹翼剩徘徊。", "朝簪盡慶千齡會，薰曲汾歌即席陪。"]'),
('769503d6-04ca-494a-ad00-10be0e444194','送齊進士奉章闕下','宋庠','宋','宋诗','song-poetry','','[]','傾坐仙姿掩石麟，奉章車府應觀賓。',64,'全唐诗/poet.song.10000.json','["傾坐仙姿掩石麟，奉章車府應觀賓。", "謝庭早占芝蘭族，禹會初陪玉帛臣。", "削牘西清催筆距，賜衣中禁換袍銀。", "東歸待看榮鄉品，年似終童祿及親。"]'),
('4f794c22-1899-4355-9588-06981567a1e8','送將作監丞張唐卿通理陝州','宋庠','宋','宋诗','song-poetry','','[]','春風祕殿翳華芝，親見枚臯作賦時。',64,'全唐诗/poet.song.10000.json','["春風祕殿翳華芝，親見枚臯作賦時。", "秀色並開棠樹萼，雋科先賞桂林枝。", "漢郵給傳蕃恩告，蜀醑浮觴薦壽祺。", "幾日陝郊迎郡副，車前懸弩雜軍麾。"]'),
('ecc6b28c-6f8b-41ff-b689-795578d7bcc0','郡齋感懷寄呈參政給事同年','宋庠','宋','宋诗','song-poetry','','[]','老持藩印守河衝，苟祿惟知戀軾熊。',64,'全唐诗/poet.song.10000.json','["老持藩印守河衝，苟祿惟知戀軾熊。", "游舊最叨青眼客，埏陶今仰黑頭公。", "巢由逸躅心空斷，儒墨常談耳欲聾。", "自笑晚年經濟業，焚香靜坐習元功。"]'),
('23689513-b208-4e9b-8759-632f1f089cdd','郡齋無訟春物寂然書所見','宋庠','宋','宋诗','song-poetry','','[]','閣鈴無響晝輝遲，短髮山巾盡日欹。',64,'全唐诗/poet.song.10000.json','["閣鈴無響晝輝遲，短髮山巾盡日欹。", "戰蟻羣行開蟄後，暝禽相語欲棲時。", "遥通竇水添新溜，密數庭花記落枝。", "訟息寬條恩莫報，晚年餘有白雲期。"]'),
('877e3939-cd0e-4241-8d83-9e476ea052f9','自洛移許初至郡齋作','宋庠','宋','宋诗','song-poetry','','[]','忝司宮鑰忽三年，恩借閒州得潁川。',64,'全唐诗/poet.song.10000.json','["忝司宮鑰忽三年，恩借閒州得潁川。", "楚北蒼茫軒后野，國南膏沃許人田。", "漢臺褒鳳今難繼，荀里占星俗尚傳。", "更頼鴨陂能慰我，鈴齋西畔似江天。"]'),
('d90ad71b-5cec-415d-ab3a-f9f24946fedd','待罪書館無所自效客有以尸素爲謔者因成答詠','宋庠','宋','宋诗','song-poetry','','[]','本愧虛名類斗箕，更堪華閣玷纓緌。',64,'全唐诗/poet.song.10000.json','["本愧虛名類斗箕，更堪華閣玷纓緌。", "海邊不覺飛鳬少，天外寧知嚇鼠饑。", "倦客風霜嗟右席，故巢煙雨老南枝。", "新年定有澄清劾，歸守東岡固未遲。"]'),
('9e5beacc-d933-4920-90de-9f13fa369f3f','喜晴晚歸','宋庠','宋','宋诗','song-poetry','','[]','八月高空卷斷霓，落霞殘照掖門西。',64,'全唐诗/poet.song.10000.json','["八月高空卷斷霓，落霞殘照掖門西。", "仙城氣暖猶藏霧，輦路塵清不雜泥。", "殿裏風回聞禁漏，闕邊雲斂見丹梯。", "迎寒便立甘泉仗，扈從應無七聖迷。"]'),
('178de025-fd0a-46a7-ac6a-67867b8a79b6','醉枕','宋庠','宋','宋诗','song-poetry','','[]','楚辭虛美獨醒賢，左手香螯伴醉眠。',64,'全唐诗/poet.song.10000.json','["楚辭虛美獨醒賢，左手香螯伴醉眠。", "國器載歸壺似腹，江萍興罷幕爲天。", "雪樓珠麗巴人曲，芝館塵生洛浦田。", "晝枕蝶魂方適興，莫教痟意傍鵾絃。"]'),
('ea73eddb-df23-40b3-911b-0bcb8a5c0f17','贈石龍趙山人','宋庠','宋','宋诗','song-poetry','','[]','衰鬢星星倦折腰，十年歸就故山樵。',64,'全唐诗/poet.song.10000.json','["衰鬢星星倦折腰，十年歸就故山樵。", "臨江徑壞茅圍屋，潁水風清樹厭瓢。", "防蠹舊編裁竹牒，蠲疴珍劑訪芝苗。", "鬻文謀食機心盡，試爲勞生諭炙鴞。"]'),
('59a06c43-969c-473c-9eaa-904a54c3832b','晚坐高明臺','宋庠','宋','宋诗','song-poetry','','[]','悔倚危欄望夕霏，臨高無事亦依依。',64,'全唐诗/poet.song.10000.json','["悔倚危欄望夕霏，臨高無事亦依依。", "天長去鳥幾時返，風罷孤雲何處歸。", "一世功名慚擊節，百年耕鑿願忘機。", "銜恩感舊誰能免，猶喜荒洲在日圍。"]'),
('1a7d96f7-68e3-4dfa-b2fc-56e043eceb32','明堂宿齋賜貢茶珍果上樽御膳','宋庠','宋','宋诗','song-poetry','','[]','太寢陪祠宿斗城，寵頒通夕助齋明。',64,'全唐诗/poet.song.10000.json','["太寢陪祠宿斗城，寵頒通夕助齋明。", "吳包瑞果金衣潤，閩焙春團寶月盈。", "滿腹鴟幐催御酒，溢杯羊䘓識君羹。", "甘滋飽德殊無寐，坐數章溝肅唱聲。"]'),
('6736cb56-5be6-42d4-b388-1f2638342b5a','季秋侍宴中闕與諸公憩學士院作','宋庠','宋','宋诗','song-poetry','','[]','冠劍中休會禁扃，暫欹孤枕拂雲屏。',64,'全唐诗/poet.song.10000.json','["冠劍中休會禁扃，暫欹孤枕拂雲屏。", "漢臣責重非真醉，楚客秋高恨獨醒。", "寶墨喜窺前賜榜，華絛猶記舊呼鈴。", "詔催終宴簫韶動，更學鶢鶋子細聽。"]'),
('32c319ce-2235-4a46-87c6-595eda118107','屏居春日','宋庠','宋','宋诗','song-poetry','','[]','初服仍從洛涘居，鳴蛙鐃吹滿前除。',64,'全唐诗/poet.song.10000.json','["初服仍從洛涘居，鳴蛙鐃吹滿前除。", "露園柘彈愁逢雀，磻渚璜鈎枉餌魚。", "蠟屐幽懷高下齒，斲輪真想古今書。", "漢人尚自嘲頻解，猶得凝神守泊如。"]'),
('875f3b56-7765-4caa-8982-2b7e2437b489','休日','宋庠','宋','宋诗','song-poetry','','[]','彌旬出沐道山頭，僦廡蕭蕭避俊游。',64,'全唐诗/poet.song.10000.json','["彌旬出沐道山頭，僦廡蕭蕭避俊游。", "枉是胸中無塊壘，可能皮裏有陽秋。", "駕車款段慚鄉品，託乘鴟夷笑客愁。", "曲突無烟賓坐冷，時聞庭雀一啁啾。"]'),
('20499cb2-8bf3-4582-9c73-24627482444e','晚坐觀風亭三首  其一','宋庠','宋','宋诗','song-poetry','','[]','戍樓西北最凌空，倦客憑闌八月風。',64,'全唐诗/poet.song.10000.json','["戍樓西北最凌空，倦客憑闌八月風。", "一曲黄河連野濁，半規殘日背人紅。", "山林枉負沉冥志，刀筆終無尺寸功。", "猶喜不迷存闕地，絳英瑶斗虎牢東。"]'),
('7be6db84-bc65-4370-8ecb-5b1fcea121fe','晚坐觀風亭三首  其二','宋庠','宋','宋诗','song-poetry','','[]','百尺空臺河上城，遠波虛籟助秋聲。',64,'全唐诗/poet.song.10000.json','["百尺空臺河上城，遠波虛籟助秋聲。", "過窮旅雁書難得，啼殺饑烏曲未成。", "急節何當容白髮，流塵只欲傍華纓。", "臨高莫訝頻東顧，憂國思君不爲名。"]'),
('9eff6ac4-9a1c-46d3-a85b-8e33e6bb065f','晚坐觀風亭三首  其三','宋庠','宋','宋诗','song-poetry','','[]','我來秋色逼霞曛，更作憑闌遠望人。',64,'全唐诗/poet.song.10000.json','["我來秋色逼霞曛，更作憑闌遠望人。", "山口遠銜遥白渡，水頭斜略小平津。", "年華有恨驚心去，世事無端刺眼新。", "深愧具茨芝朮在，掛冠終擬狎堯民。"]'),
('bde4a4f9-4689-48bf-bf7b-27b59e763df2','謝齊屯田見惠詩什','宋庠','宋','宋诗','song-poetry','','[]','東家華衮屢垂褒，傾耳幽蘭郢唱高。',64,'全唐诗/poet.song.10000.json','["東家華衮屢垂褒，傾耳幽蘭郢唱高。", "雪苑曳裾慚賦客，春塘飛筆見詩豪。", "千金秦市文終貴，九奏鈞天夢自勞。", "他日海槎如犯斗，願將孤跡託星曹。"]'),
('dd0fbeda-e096-4039-9f72-e20d97448aa5','和答越州呂鄉見贈之作兼以爲別','宋庠','宋','宋诗','song-poetry','','[]','綠髮仙郎得郡新，潁川重喜拂征塵。',64,'全唐诗/poet.song.10000.json','["綠髮仙郎得郡新，潁川重喜拂征塵。", "樽前道舊情無改，馬上裁篇筆有春。", "萬里江山迎使旆，九門冠劍別朝紳。", "請君更讀韋平傳，莫把家聲苦讓人。"]'),
('e4c1b1a1-4914-4d85-b834-8d0a307c7be4','次韵和宮保龐丞相見貺之作','宋庠','宋','宋诗','song-poetry','','[]','歲陰誰不感摧頹，更值亨衢出處催。',64,'全唐诗/poet.song.10000.json','["歲陰誰不感摧頹，更值亨衢出處催。", "根柢只堪陪櫟社，功名何足玷雲臺。", "覽窮文史篇章倦，過盡榮華老病來。", "宮衮裁詩褒意厚，昏瞳刮膜喜重開。"]'),
('bdc250b6-8cf3-428a-92d2-83ce2ac05846','次韵和太常韓博士寄獻留臺吳侍郎之作','宋庠','宋','宋诗','song-poetry','','[]','藥匕蠲疴去近班，主臺西邑借餘閒。',64,'全唐诗/poet.song.10000.json','["藥匕蠲疴去近班，主臺西邑借餘閒。", "梢雲翠色凌霜罷，巢閣仙姿瑞世還。", "秋沼縈心林下水，曉樓供目雨餘山。", "更逢酬唱俱清潤，冰玉相輝戚苑間。"]'),
('3a26d7b6-3b72-42f1-bb1d-a7123de94080','和吳侍郎答汝州諸官唱酬之作','宋庠','宋','宋诗','song-poetry','','[]','青管裁篇屬舊僚，賡歌奇意亦飄飄。',64,'全唐诗/poet.song.10000.json','["青管裁篇屬舊僚，賡歌奇意亦飄飄。", "橫徽曲妙誰逃賞，過物風清盡應簫。", "此路煙霞催入洛，他年簪笏慶歸朝。", "乘秋不奈多高興，重取蘭薰答楚謠。"]'),
('a64cfddb-828c-4f4c-bf4d-68b32bfb7f53','府齋秋日','宋庠','宋','宋诗','song-poetry','','[]','卷帷收扇暮凉初，秋意盈襟小疾除。',64,'全唐诗/poet.song.10000.json','["卷帷收扇暮凉初，秋意盈襟小疾除。", "池面宿煙荷蓋老，階脣漏日竹陰疏。", "虛舟觸物真無意，高枕論才似有餘。", "學道知非堪自哂，眼昏方讀貝多書。"]'),
('44d1df23-f248-4dba-b6d3-ee58f39b4d51','梅','宋庠','宋','宋诗','song-poetry','','[]','花落亭亭素臉開，忍寒剛欲背春來。',64,'全唐诗/poet.song.10000.json','["花落亭亭素臉開，忍寒剛欲背春來。", "已迷江令瓊花樹，更傍周王璧水臺。", "楚館嬌雲愁夢斷，洛廛香雪待風回。", "一枝寄遠真何益，費盡南朝陸凱才。"]'),
('c6675c06-8caa-487a-97d7-60c5f53a9af2','趙奉禮見過','宋庠','宋','宋诗','song-poetry','','[]','經年掩卧席凝塵，載喜西都接賦賓。',64,'全唐诗/poet.song.10000.json','["經年掩卧席凝塵，載喜西都接賦賓。", "照坐仙姿嵇玉冷，醉心英氣瑾醪醇。", "斑衣就養垂華組，葆髮傷秋岸幅巾。", "更謝妍談殊未已，肯將車駟誚原貧。"]'),
('380c5636-b30a-46f6-ab35-e6bc9af3c6d0','歲暮答趙奉禮','宋庠','宋','宋诗','song-poetry','','[]','蜀痟平日掩芳樽，星籥年凋景易奔。',64,'全唐诗/poet.song.10000.json','["蜀痟平日掩芳樽，星籥年凋景易奔。", "天遠斷蘆催序雁，庭空飛雪妬離鵾。", "顔瓢枉樂堪憂巷，漢履猶思待詔門。", "月署仙郎多麗唱，苦嗟池草久迷魂。"]'),
('e9b12922-8b4a-41c7-b3d2-5a75f1f4f887','送趙奉禮','宋庠','宋','宋诗','song-poetry','','[]','日出東郊郢路分，斑騅嘶斷悵離羣。',64,'全唐诗/poet.song.10000.json','["日出東郊郢路分，斑騅嘶斷悵離羣。", "漢庭習蕝仙曹遠，楚驛攀梅使綬薰。", "蟻酎百壺凝桂溢，鵠歌三闋轉珠聞。", "登臨如賦蘭臺事，十二峰前盡有雲。"]'),
('3186f36c-9f9c-469c-a21d-ce652eb31eec','朝謁應天神御瞻仰壯麗退憩齋房作','宋庠','宋','宋诗','song-poetry','','[]','雲構崔嵬敞梵筵，皇家基運此興先。',64,'全唐诗/poet.song.10000.json','["雲構崔嵬敞梵筵，皇家基運此興先。", "如存不改當陽坐，善護常開種福田。", "四徹金繩規寶所，九衢瓊樹宿非煙。", "須知補舊延洪意，重數仙人拂石年。"]'),
('761d2bfc-4f40-42d8-965b-a14c5623521a','晨謁感懷','宋庠','宋','宋诗','song-poetry','','[]','早拂華簪謁冕旒，五更殘點便鳴騶。',64,'全唐诗/poet.song.10000.json','["早拂華簪謁冕旒，五更殘點便鳴騶。", "星沈長樂鐘聲外，月掛觚稜闕影頭。", "弱翮詎堪儀振鷺，孤懷終欲信羣鷗。", "更慚晨坐鴻樞府，容鬢先于省樹秋。"]'),
('5d00d4db-84ec-40cf-a2ec-3655a6522c76','晨謁書所見','宋庠','宋','宋诗','song-poetry','','[]','紺幰鳴珂萬蓋翔，九門冠劍擁晨光。',64,'全唐诗/poet.song.10000.json','["紺幰鳴珂萬蓋翔，九門冠劍擁晨光。", "城連南北長安斗，殿倚東西太極堂。", "雲裏銅烏風作籟，天邊金掌露成霜。", "微生備位如葵藿，只有傾心奉聖王。"]'),
('6c0df33a-e4b1-468f-905b-7a5f2a7819fa','受詔同編修敕令終篇例賜勳一轉謝參預東平會稽二公','宋庠','宋','宋诗','song-poetry','','[]','法家高議集朝緌，成績連茅被帝暉。',64,'全唐诗/poet.song.10000.json','["法家高議集朝緌，成績連茅被帝暉。", "均賞已知羊胃爛，銘恩偏覺鼠肝微。", "泥塗枉入鴻鈞用，腹背還憑逸翮飛。", "天祿半生瘨眩病，猶堪持帚掃朱扉。"]'),
('4f341ac8-d6a0-4e8d-8732-fa683e978ce0','送巢邑孫簿兼過江南家墅','宋庠','宋','宋诗','song-poetry','','[]','楚客才多不奈秋，長安赴集苦淹留。',64,'全唐诗/poet.song.10000.json','["楚客才多不奈秋，長安赴集苦淹留。", "半綸綬采緇塵化，十幅帆陰素潦收。", "離恨枉能寬带眼，歸期猶喜詠刀頭。", "督租勾簿真沈俊，終冀梁臺一召鄒。"]'),
('85bcb8a0-ee0e-4aae-ae4f-1152417ac91a','流杯小宴偶成拙詩奉呈運使王密學紫微韓舍人','宋庠','宋','宋诗','song-poetry','','[]','溪齋元巳得嘉賓，曲曲煙渠逗翠淪。',64,'全唐诗/poet.song.10000.json','["溪齋元巳得嘉賓，曲曲煙渠逗翠淪。", "潑火乍經三月雨，泛觴重記九年春。", "風前小舞驚餘雪，梁外清歌落暗塵。", "此會貴交應絕擬，斗樞星掖兩賢臣。"]'),
('dc81349c-38e6-40f8-8f68-b568d407f6b7','春晚獨遊沂公園','宋庠','宋','宋诗','song-poetry','','[]','幾曲鳴溪抱嘯臺，陰陰野氣壓浮埃。',64,'全唐诗/poet.song.10000.json','["幾曲鳴溪抱嘯臺，陰陰野氣壓浮埃。", "林間幽鳥自相語，水上落花何處來。", "逃相故畦無廢汲，封侯修竹是元栽。", "三川病尹妨賢久，終卜鄰扉養不才。"]'),
('2b6c879d-99d2-4f01-bb05-597c8ac1da20','送李祕校赴太平法掾','宋庠','宋','宋诗','song-poetry','','[]','沈臂驚秋肉減分，曉波衰柳對離羣。',64,'全唐诗/poet.song.10000.json','["沈臂驚秋肉減分，曉波衰柳對離羣。", "臣饑枉索中都米，卿事猶參下國軍。", "三襲賦臺拋苑雪，一廛鄉樹辨江雲。", "坐曹少茹徒勞歎，南闕干霄遲獻文。"]'),
('2a760513-ef85-4814-8d69-0e59cf99c027','送黄秀才歸淮西','宋庠','宋','宋诗','song-poetry','','[]','驪駒黄鵠兩成歌，即席愁顔慘未酡。',64,'全唐诗/poet.song.10000.json','["驪駒黄鵠兩成歌，即席愁顔慘未酡。", "舊客仙壇紅遶杏，怨魂春水綠生波。", "締交英域銀袍麗，宴族詩庭玉樹多。", "簡牘三千行自鬻，漢家鼇闕鬰嵯峨。"]'),
('ebf4f183-4c74-4220-82f3-a38e66203fa7','歎張縡','宋庠','宋','宋诗','song-poetry','','[]','嶠外歸來白髮新，胸中無物有經綸。',64,'全唐诗/poet.song.10000.json','["嶠外歸來白髮新，胸中無物有經綸。", "局當轅下驊騮足，倚著門邊骯髒人。", "風雪又殘梁苑歲，煙蘿誰管楚山春。", "由來榮悴多如此，莫爲前薪怨後薪。"]'),
('d28dc437-2371-4403-a3bd-5ad0e7df5be3','洛京王尚書學士寄惠牡丹十品五十枝因成四韵代書答','宋庠','宋','宋诗','song-poetry','','[]','十種仙葩各有名，相逢暫似到周京。',64,'全唐诗/poet.song.10000.json','["十種仙葩各有名，相逢暫似到周京。", "簪端珥萼頭雖白，酒面含華眼更明。", "風暖天香吹不斷，露深宮綵洗初成。", "慇懃數盡千重葉，未抵銜恩感舊情。"]'),
('650699b1-8f31-424b-90cd-a5657902d39b','和運使王密學西亭未開牡丹','宋庠','宋','宋诗','song-poetry','','[]','新年西圃带輕寒，芳意含華洽客歡。',64,'全唐诗/poet.song.10000.json','["新年西圃带輕寒，芳意含華洽客歡。", "瑞露只知催濯錦，朝霞猶欲隠乘鸞。", "暗期玉蕊蜂窠潤，偷裛天香蝶粉乾。", "應爲主人恩不淺，併留顔色占春闌。"]'),
('850ac2e7-352b-4221-a99b-f740f1c89637','小園春晝','宋庠','宋','宋诗','song-poetry','','[]','日永春殘陋巷深，四鄰蕭寂小山林。',64,'全唐诗/poet.song.10000.json','["日永春殘陋巷深，四鄰蕭寂小山林。", "張羅門外人驚爵，仰秣槽中馬聽琴。", "燕坐角巾移竹影，野談爭席占牆陰。", "灌園本是三公事，俋俋閒舒傲世心。"]'),
('6e63d19b-a35d-430b-b752-11a7b6a559d1','和中丞晏尚書圓丘觀禮','宋庠','宋','宋诗','song-poetry','','[]','三襲觚壇夜未央，金支蟾彩共熒煌。',64,'全唐诗/poet.song.10000.json','["三襲觚壇夜未央，金支蟾彩共熒煌。", "鳳輿遥憩壝門次，翟尾交分褥路香。", "星魄媼神聯紺席，文宗武祖侑瑶觴。", "萬靈醉止純休集，方信周家駿命長。"]'),
('ea8b0fce-87f7-4f3e-b626-5709056e1dd5','陰晦殘春可惜二首  其一','宋庠','宋','宋诗','song-poetry','','[]','園林春去自無歡，宴幕經旬掩客盤。',64,'全唐诗/poet.song.10000.json','["園林春去自無歡，宴幕經旬掩客盤。", "霧野關河非意失，曉樓風雨不時寒。", "空梁燕濕休矜舞，曲沼蛙鳴且爲官。", "嵩少歸心堪悵望，紫芝赬桂老瓊巒。"]'),
('2962394d-c8d7-4ddd-abaf-ebe2fb813d6f','陰晦殘春可惜二首  其二','宋庠','宋','宋诗','song-poetry','','[]','柳長花歇夏雲初，幽圃尋芳但綠蕪。',64,'全唐诗/poet.song.10000.json','["柳長花歇夏雲初，幽圃尋芳但綠蕪。", "不分伯勞隨阿母，生憎蛺蝶效當塗。", "昏沈嶺霧吞斜日，寂寞溪煙壓翠蒲。", "欲拂琴徽銷客恨，啞啞城曲已啼烏。"]'),
('7d1bc9c8-ce9b-4e62-a665-567aac493142','同萬秀才讌楊侯別墅','宋庠','宋','宋诗','song-poetry','','[]','苑路輕驂拂曉霞，斗城南畔列侯家。',64,'全唐诗/poet.song.10000.json','["苑路輕驂拂曉霞，斗城南畔列侯家。", "臨邛貴客傾中坐，漳水詞人記後車。", "一石蒲桃先載酒，萬株金谷正交花。", "風光不減蘭亭會，醉墨憑君紀歲華。"]'),
('b43baf6d-3372-44a1-86f2-fe50813ab319','過漢洛陽故城','宋庠','宋','宋诗','song-poetry','','[]','漢家遺堵滿山川，六里東西遂渺然。',64,'全唐诗/poet.song.10000.json','["漢家遺堵滿山川，六里東西遂渺然。", "寒日似愁圭影地，秋風真作黍離天。", "五株杏發陵無邑，一項茅荒井失田。", "更歎道邊多棄骨，可能猶爲直如弦。"]'),
('3412a23a-87ed-4dcd-ac40-4eb1643c573d','送紫微夏舍人徙治洪州','宋庠','宋','宋诗','song-poetry','','[]','方底丁寧細札書，豫章都會冠全吳。',64,'全唐诗/poet.song.10000.json','["方底丁寧細札書，豫章都會冠全吳。", "垂腰三品龜銜綬，衛帳千兵虎刻符。", "藥省樹翻拋賜筆，練江波靜見還珠。", "西山五色多仙餌，鈴閣無聲道有腴。"]'),
('220535c4-8b13-4af8-a797-013941313e17','立春前二日嘉雪應祈呈昭文相公','宋庠','宋','宋诗','song-poetry','','[]','皇心精禱動昭回，嘉雪乘時弭歲災。',64,'全唐诗/poet.song.10000.json','["皇心精禱動昭回，嘉雪乘時弭歲災。", "先作飛霙隨臘舞，便含膏澤趁春來。", "天淵百頃移星漢，禁籞千枝傲嶺梅。", "一曲巴人雖下里，願持歡意助康哉。"]'),
('b5f76192-952b-41c0-9d58-772bf6979d0c','北臺','宋庠','宋','宋诗','song-poetry','','[]','古丘危磴接雲梯，遠目臨高意自迷。',64,'全唐诗/poet.song.10000.json','["古丘危磴接雲梯，遠目臨高意自迷。", "千里綠蕪平野北，半邊紅日亂峰西。", "臺傾鄴苑多殘瓦，鳳沒漳河失故隄。", "近塞春郊無勝事，跛䍧風馬滿山溪。"]'),
('51090841-e841-406f-ac19-3a8c84d51a13','曉出城祀風師壇馬上作','宋庠','宋','宋诗','song-poetry','','[]','風穴靈壇背漢臯，肅將祀典會諸曹。',64,'全唐诗/poet.song.10000.json','["風穴靈壇背漢臯，肅將祀典會諸曹。", "城頭五鼓催關鑰，席上雙籩薦沼毛。", "冠嶺昕霞迎霽旭，冒疇農橛漬春膏。", "箕揚畢好宜流惠，江外刀耕楚俗勞。"]'),
('779e0177-e9fe-478b-bee1-00298d09e870','漕渠春臺','宋庠','宋','宋诗','song-poetry','','[]','縹陂春色極晴虛，新水遥連六輔渠。',64,'全唐诗/poet.song.10000.json','["縹陂春色極晴虛，新水遥連六輔渠。", "沙上釣歸人獲鷸，梁邊觀罷客知魚。", "蒼浮樹影煙生後，紅皺溪紋日側初。", "刮目暫成江海趣，狂奴終憶越灘居。"]'),
('b522f6db-788a-49ea-88d2-a5d753a4078f','和朱舅暮春積雨','宋庠','宋','宋诗','song-poetry','','[]','沮洳江雲寂寞春，一軒風雨歎彌旬。',64,'全唐诗/poet.song.10000.json','["沮洳江雲寂寞春，一軒風雨歎彌旬。", "灰殘淮館蟾韜暈，石去湘陵燕濕身。", "委路落花紅罷舞，傍樓低柳綠爭顰。", "蕭蕭枉結年華恨，愁煞西州掩鼻人。"]'),
('c9d8e127-d275-432c-b508-46a9da681f38','得許六書','宋庠','宋','宋诗','song-poetry','','[]','車笠論交夙契深，文麒江海獲歸音。',64,'全唐诗/poet.song.10000.json','["車笠論交夙契深，文麒江海獲歸音。", "流光過隙偏驚駟，危睫沾衣不爲琴。", "甯扣幾勞歌白石，莊昏猶欲注黄金。", "無因一答瑶華問，南國洪喬牘易沈。"]'),
('ca210028-1ac3-459e-87b9-8f7e6f46a6fe','馳賀監稅齊都','宋庠','宋','宋诗','song-poetry','','[]','溫詔封芝出帝居，祕曹星秩示優除。',64,'全唐诗/poet.song.10000.json','["溫詔封芝出帝居，祕曹星秩示優除。", "舜庭已茂三年績，魏謗初銷一篋書。", "丹地拾遺思汲黯，中宸批草待相如。", "前期雀厦無因戀，歸從清塵六尺輿。"]'),
('3b9a8c54-65e0-46cc-a4c6-70a5044a7132','次韵和吳侍郎任宗伯貳卿沖卿領天官南局皆世職有感','宋庠','宋','宋诗','song-poetry','','[]','斗宮分局敞星闈，伯仲登賢士論歸。',64,'全唐诗/poet.song.10000.json','["斗宮分局敞星闈，伯仲登賢士論歸。", "奕世弓裘方善續，先春跗萼更相依。", "孤鴻暫作雲衢騁，三鳳行看帝閣飛。", "戚苑好書餘慶事，一門仙橐映朝衣。"]'),
('9ed95466-6622-492f-8cec-b1a9965ec130','西齋見雪寄呈靖彥惠','宋庠','宋','宋诗','song-poetry','','[]','歲陰休沐坐空齋，集霰飄霙次第來。',64,'全唐诗/poet.song.10000.json','["歲陰休沐坐空齋，集霰飄霙次第來。", "仙粉有痕緣幌入，亂花無數覓叢開。", "故裘禦濕便羔袖，凍醴扶衰藉藥杯。", "向暮紛紛何所擬，謝家兒姪有清才。"]'),
('71e26052-1e17-457e-b892-b4fea83d2fd8','和中丞晏尚書和答十二兄夜歸遇雪之作','宋庠','宋','宋诗','song-poetry','','[]','有客天街夜轡還，霰花無數拂雕鞍。',64,'全唐诗/poet.song.10000.json','["有客天街夜轡還，霰花無數拂雕鞍。", "路疑西極瑶池近，人似南朝鶴氅寒。", "漏鼓傳聲催暝色，麴車迷轍寄餘歡。", "塤箎雅韵皆多感，偏覺陽春再和難。"]'),
('440b5104-a827-4e12-9ffa-d1772a199630','和中丞晏尚書乘輿宿殿致齋日巡仗遇雪','宋庠','宋','宋诗','song-poetry','','[]','十里甘泉鹵簿新，即時天借雪清塵。',64,'全唐诗/poet.song.10000.json','["十里甘泉鹵簿新，即時天借雪清塵。", "光含九陌疑無暝，花拂千旗旋作春。", "夾路綵樓偏著粉，中天嶢闕更成銀。", "絳騶案仗傳呼盛，寧似梁王不悅辰。"]'),
('57e77797-4597-4433-a032-927feff7c35c','初春夙興','宋庠','宋','宋诗','song-poetry','','[]','戍城官柝應營笳，愁枕無眠感曙鴉。',64,'全唐诗/poet.song.10000.json','["戍城官柝應營笳，愁枕無眠感曙鴉。", "料峭風頭猶助凍，蒼凉天角欲成霞。", "離離弈局殘星墜，脈脈刀環片月斜。", "尚喜初年輕病骨，半簪蓬影况蒼華。"]'),
('90e78495-e217-4aea-8647-072176c1a530','送令狐揆南游','宋庠','宋','宋诗','song-poetry','','[]','楚澤離愁不避春，柳梢梅萼送行人。',64,'全唐诗/poet.song.10000.json','["楚澤離愁不避春，柳梢梅萼送行人。", "綠波易蕩銷魂水，紫陌難遮拂面塵。", "道困秦儀猶掉舌，歧多楊阮始沾巾。", "劍緱髀肉無窮恨，羞向耕疇獨問津。"]'),
('1e7c3309-410f-4925-9027-d29431e4b5d6','己巳孟春二十六日作','宋庠','宋','宋诗','song-poetry','','[]','糾纏空驚禍福頻，沈舟未拯更摧輪。',64,'全唐诗/poet.song.10000.json','["糾纏空驚禍福頻，沈舟未拯更摧輪。", "山頭枉是輕廷尉，天上何容著蹇人。", "南國祭犧堪畏楚，東門獵犬尚尤秦。", "當塗莫竦支離誚，坐受朝家十束薪。"]'),
('210d8ab3-797a-4739-8b0f-36752342ea50','致政張郎中惠親畫墨竹二𭘻以詩爲報','宋庠','宋','宋诗','song-poetry','','[]','南宮仙老本多才，素幅珍紈繪境開。',64,'全唐诗/poet.song.10000.json','["南宮仙老本多才，素幅珍紈繪境開。", "高節自緣心匠出，野叢還擁筆端來。", "挂餘粉籜疑飄席，玩久風枝欲掃苔。", "俗眼莫驚無藻麗，歲寒顔色抵瓊瑰。"]'),
('1a5bd5e8-e6c8-4f29-aa04-ea13b8323289','送孫記堂出宰歸安','宋庠','宋','宋诗','song-poetry','','[]','當年璧馬上荆臺，曾識長離婉婉來。',64,'全唐诗/poet.song.10000.json','["當年璧馬上荆臺，曾識長離婉婉來。", "巧智忍隨司馬宦，沈酣終屈廣都才。", "蓴鱸薦俎朝豐饌，稻蟹藏波歲絕災。", "鄉梓汀蘋鷄犬地，孫郎藻思若爲裁。"]'),
('211817d4-3119-47d4-b428-f0039170c1dd','榴花','宋庠','宋','宋诗','song-poetry','','[]','孤根西土幾時傳，絳蕊緗趺早夏天。',64,'全唐诗/poet.song.10000.json','["孤根西土幾時傳，絳蕊緗趺早夏天。", "艷發雖慚李桃後，子成猶占雪霜前。", "醖餘霞醑香應在，染殺綃裙色未鮮。", "一種芳心耐風雨，敢辭重疊奏君筵。"]'),
('7c8ca533-be24-439b-9b29-5cddab08da7f','晚臺','宋庠','宋','宋诗','song-poetry','','[]','霽色秋空送目勞，小臺摇落更平臯。',64,'全唐诗/poet.song.10000.json','["霽色秋空送目勞，小臺摇落更平臯。", "紅垂海樹烏棲日，清溢江沱鷺浴濤。", "天勢暮圍鱗隰闊，雁行斜轉翼雲高。", "楚風摵摵迷魂地，可在揚雄獨廣騷。"]'),
('b21b6fd6-7233-4221-b3a9-df5e4efa1069','提刑張司封同年垂訪別郡以詩爲謝','宋庠','宋','宋诗','song-poetry','','[]','天聖光華第二春，與君同日脫凡鱗。',64,'全唐诗/poet.song.10000.json','["天聖光華第二春，與君同日脫凡鱗。", "何知素領分符地，却見青雲共榜人。", "千重使移行府重，一觴歡伯故儔親。", "言詩擊節兼風義，且欲因聲附翠珉。"]'),
('519e1e37-9031-44a5-851f-eef79cec08d6','送廷評沈先輩宰江山兼過吉席','宋庠','宋','宋诗','song-poetry','','[]','東陽世系出翹英，刮目神膚兩共清。',64,'全唐诗/poet.song.10000.json','["東陽世系出翹英，刮目神膚兩共清。", "洛紙文雄錢萬選，郄堂科美佛千名。", "春風適館仙軿密，海曲夸鄉縣綬輕。", "上最三年歸路穩，中阿芳意滿菁菁。"]'),
('8725a5a4-10f9-43e9-bfc2-db89a095c777','淳之太尉相公寄示赴鎮小編三復成誦研味之餘理當酬繼但難于徧和輒取首題賦成拙句一首既伸高山仰止之願并以爲謝','宋庠','宋','宋诗','song-poetry','','[]','西北遮胡晉部疆，更煩儒將下文昌。',64,'全唐诗/poet.song.10000.json','["西北遮胡晉部疆，更煩儒將下文昌。", "久調玉鉉三司貴，出倚金城萬里長。", "唐畝歲豐禾自合，汾波秋景草應黄。", "須知外警從茲罷，閒殺邊郵赤白囊。"]'),
('56c67ef1-46a8-4d18-b06c-e52ecbad6dde','新春雪霽坐郡圃池上二首  其一','宋庠','宋','宋诗','song-poetry','','[]','鈴齋西北小池臺，漠漠年光病眼開。',64,'全唐诗/poet.song.10000.json','["鈴齋西北小池臺，漠漠年光病眼開。", "水面綠深知凍解，柳梢黄淺覺春來。", "啁啾野雀遺寒毳，撥剌潜魚露戲鰓。", "物物惱人俱入詠，使君爭奈乏天才。"]'),
('1f36f15e-9892-4e3d-a663-27808acff420','新春雪霽坐郡圃池上二首  其二','宋庠','宋','宋诗','song-poetry','','[]','溪上危堂堂下橋，臘餘春意卷寒飈。',64,'全唐诗/poet.song.10000.json','["溪上危堂堂下橋，臘餘春意卷寒飈。", "煙催樹色全疑染，暖逼禽聲自學調。", "封徑老苔翻敗錦，抱城空水皺輕綃。", "茨山小隠歸心動，坐想瓊芝幾隴苗。"]'),
('329e9ebe-e5d0-46d1-b022-bab2c85e4401','淮南自訟','宋庠','宋','宋诗','song-poetry','','[]','偶然人乏貳中樞，賜罷猶專督府居。',64,'全唐诗/poet.song.10000.json','["偶然人乏貳中樞，賜罷猶專督府居。", "髮白自傷聞道晚，心丹誰識報恩餘。", "淮天目極風帆駛，韓野魂銷宰樹疏。", "却顧病身何所用，只堪歸釣潁灘魚。"]'),
('34268dd3-6400-4d12-9f94-376ebda956bd','春社日置酒示客','宋庠','宋','宋诗','song-poetry','','[]','欣欣春色上高臺，一雨關河宿霧開。',64,'全唐诗/poet.song.10000.json','["欣欣春色上高臺，一雨關河宿霧開。", "洛浦宓妃鴻已去，漢家皇后燕初來。", "山爐馥郁熏歌扇，錦瑟丁寧侑客杯。", "秉燭尋芳君莫倦，歡游纔散便徘徊。"]'),
('460d0632-f5ce-408b-ab52-be006d2e907f','暮春感興','宋庠','宋','宋诗','song-poetry','','[]','九十芳期去不留，解痟何計貰珍裘。',64,'全唐诗/poet.song.10000.json','["九十芳期去不留，解痟何計貰珍裘。", "爐殘晉俗清明火，水冷山陰祓禊洲。", "風徑舞花催暮色，雨梁歸燕說春愁。", "離歸莫問年華事，賦筆悲于宋玉秋。"]'),
('3ee663cf-8e51-47ac-a04b-1dce2b59dd0a','去秋九日置酒今秋復喜茲會詩呈通判比部並諸幕府','宋庠','宋','宋诗','song-poetry','','[]','城上凌氛百尺臺，晚秋重喜宴樓開。',64,'全唐诗/poet.song.10000.json','["城上凌氛百尺臺，晚秋重喜宴樓開。", "汎樽露菊疑相識，吹帽霜風是再來。", "寶瑟丁寧催客飲，丹萸爛漫辟誰災。", "莫驚銀燭先爲具，天際殘陽喚不回。"]'),
('2507e921-7d28-4dd2-8cdb-5148d70fd72e','孤坐北齋因懷出處之難偶成感詠','宋庠','宋','宋诗','song-poetry','','[]','白頭榮路念何之，出處空驚未得宜。',64,'全唐诗/poet.song.10000.json','["白頭榮路念何之，出處空驚未得宜。", "劉放老于宮裏樹，莊生愁煞廟中犧。", "嵩巖桂塢堪休影，潁曲芝廛好療饑。", "但願天心從爾欲，敢言歸赴赤松期。"]'),
('29db8370-e1a5-4752-b6cf-3d691413e328','謀退','宋庠','宋','宋诗','song-poetry','','[]','家家臯稷會亨辰，老醜無謀念孰親。',64,'全唐诗/poet.song.10000.json','["家家臯稷會亨辰，老醜無謀念孰親。", "自樂一麾稱外守，恥將三物詛讒人。", "灌園路僻蒼烟曉，洗耳灘長碧溜春。", "此地敢言逃楚相，他年終擬作堯民。"]'),
('0f6b1366-9c9f-4052-afc8-ee218ef5c4ae','赴鄭出國門經西苑池上','宋庠','宋','宋诗','song-poetry','','[]','十里商中抱帝畿，苑煙宮霧共霏微。',64,'全唐诗/poet.song.10000.json','["十里商中抱帝畿，苑煙宮霧共霏微。", "長楊獵近寒熊吼，太液歌餘瑞鵠飛。", "碧護斗城天倚蓋，光銜蓬島日舒圍。", "樓船法從年年盛，借問孤臣何歲歸。"]'),
('f29f7662-6fdd-4717-a992-b74e29ccbe2e','府齋歲晏節物感人輒成拙詩二篇上寄昭文相公樞密太尉雖俚調無取亦盍各斐然之義也  其一','宋庠','宋','宋诗','song-poetry','','[]','曉拂青銅感歲闌，蕭蕭華髮强扶冠。',64,'全唐诗/poet.song.10000.json','["曉拂青銅感歲闌，蕭蕭華髮强扶冠。", "病憎蛇影能爲怪，老愛松心不受寒。", "世務焦頭機已息，主恩淪髓報應難。", "鏌鋣自躍非吾意，且作洪鑪舊物看。"]'),
('c8d9a1bf-5d1c-4f93-8a22-ef8c459e8126','府齋歲晏節物感人輒成拙詩二篇上寄昭文相公樞密太尉雖俚調無取亦盍各斐然之義也  其二','宋庠','宋','宋诗','song-poetry','','[]','處世何嘗盡值才，虛名高位自驚猜。',64,'全唐诗/poet.song.10000.json','["處世何嘗盡值才，虛名高位自驚猜。", "千重浪裏隨流出，百尺竿頭試險回。", "衰鬢不徒欺曉雪，孤心兼欲伴寒灰。", "嵩陽潁曲風煙接，已仗歸雲作隠媒。"]'),
('0c4ae610-9eb6-474b-8653-6d505ae6a855','後池春水初滿','宋庠','宋','宋诗','song-poetry','','[]','水從雲表濟祠來，春凍初消舊堰開。',64,'全唐诗/poet.song.10000.json','["水從雲表濟祠來，春凍初消舊堰開。", "岸側淺黄先映柳，石邊新綠便成苔。", "就深整頓吳歈槳，因曲安排洛禊杯。", "莫道使君無野興，把竿常到月中回。"]'),
('05c8a52b-eddd-4f92-a60d-fe2a86eb9119','池上雨過','宋庠','宋','宋诗','song-poetry','','[]','蕭蕭殘雨過橫塘，翠幕生波入坐凉。',64,'全唐诗/poet.song.10000.json','["蕭蕭殘雨過橫塘，翠幕生波入坐凉。", "淡日映雲微透脚，暖風翻葉更成光。", "牆頭早杏青丸小，水面新蒲紺尾長。", "魚鳥沈浮齋吏散，恍驚身世在濠梁。"]'),
('302492dd-8eeb-494f-af77-39f6527645f4','因覽鏡照見衰年狀貌有感','宋庠','宋','宋诗','song-poetry','','[]','拂檻清晨念老餘，只堪丘壑便懸車。',64,'全唐诗/poet.song.10000.json','["拂檻清晨念老餘，只堪丘壑便懸車。", "暗圍廓落頻移眼，坐况蒼華不滿梳。", "綟綬轉慚龜鈕印，土膏空負鶴頭鋤。", "人生出處真難决，羨殺賢哉漢二疏。"]'),
('6a01b0d7-132d-4c6c-a4fe-daf06dac4234','郎中胡君出守三衢特枉長韵一篇曲敘故人之契且有嘉命別督餞章牽課所成老拙多愧聊以奉揚高節爾','宋庠','宋','宋诗','song-poetry','','[]','南宮仙客欲歸休，更領銅符越絕州。',64,'全唐诗/poet.song.10000.json','["南宮仙客欲歸休，更領銅符越絕州。", "郎位雖嗟三不遇，友聲偏喜兩相求。", "朝端引籍辭羣鷺，天外忘機信白鷗。", "行矣松喬君自愛，虛名官職壓人頭。"]'),
('0a5167cb-3f16-46c1-a506-26dded40ad9b','落花','宋庠','宋','宋诗','song-poetry','','[]','一夜春風拂苑牆，歸來何處剩凄凉。',64,'全唐诗/poet.song.10000.json','["一夜春風拂苑牆，歸來何處剩凄凉。", "漢臯佩冷臨江失，金谷樓危到地香。", "淚臉補痕勞獺髓，舞臺收影費鸞腸。", "南朝樂府休賡曲，桃葉桃根盡可傷。"]'),
('e66451c9-6395-4232-9968-33dda265e5d8','春晦','宋庠','宋','宋诗','song-poetry','','[]','曉雨廉纖僅壓塵，落花長草小平津。',64,'全唐诗/poet.song.10000.json','["曉雨廉纖僅壓塵，落花長草小平津。", "十千酒美空留客，九十春歸不戀人。", "有恨剛腸隨指繞，無情華髮撲頭新。", "憑誰與射踆烏翼，免向西嵫送日輪。"]'),
('13e4a043-ed65-4347-8874-ef0ca4c00723','恩忝西掖垣','宋庠','宋','宋诗','song-poetry','','[]','賢路塵消篋謗殘，蕭蕭衰鬢得生還。',64,'全唐诗/poet.song.10000.json','["賢路塵消篋謗殘，蕭蕭衰鬢得生還。", "久叨鴟尾三重閣，却趁蛾眉五日班。", "傷翼再來仍繞樹，行雲何處不思山。", "坐揮拙筆無文甚，正被中郎笑拙艱。"]'),
('92f87828-de31-4791-9b21-6b620a50ce43','新晴','宋庠','宋','宋诗','song-poetry','','[]','清明初過雨初收，春意重因霽景留。',64,'全唐诗/poet.song.10000.json','["清明初過雨初收，春意重因霽景留。", "風定草煙還壓野，雲開山色始歸樓。", "邙陰高樹藏低嶺，河曲新波沒故洲。", "點檢叢花猶半在，應須秉燭爲君游。"]'),
('821e947c-bbb4-4653-9277-ab95d5587962','清明日東歸舟次滯雨','宋庠','宋','宋诗','song-poetry','','[]','月弦離畢破芳辰，舟子招招數問津。',64,'全唐诗/poet.song.10000.json','["月弦離畢破芳辰，舟子招招數問津。", "壓岸晚陰雲著野，蘸渠春色柳隨人。", "煙疇雊雉逢誰歎，風磧驚鷗莫我親。", "賜告有程歸棹急，赧然歸水愧游鱗。"]'),
('9249f72e-0345-4283-9cfc-ffa8319bbd0c','都官謝員外今年春榜舟奉使予餞別于東亭孟夏之初不幸卒于中道其孤迎喪還都予又出弔于餞所俯仰陳迹因爲詩以寄哀','宋庠','宋','宋诗','song-poetry','','[]','溝水新傷摻袂人，何言便作死生分。',64,'全唐诗/poet.song.10000.json','["溝水新傷摻袂人，何言便作死生分。", "地中玉樹無期見，琴上牙絃忍再聞。", "幾日離觴成漬酒，平時芳札代遺文。", "東亭哭罷愁回首，落照銘旌隔野氛。"]'),
('35182849-689b-4286-beb3-9484e4a88b14','寄延州經略龐龍圖','宋庠','宋','宋诗','song-poetry','','[]','驛騎傳書拂塞塵，開緘長跪墨猶新。',64,'全唐诗/poet.song.10000.json','["驛騎傳書拂塞塵，開緘長跪墨猶新。", "霜餘且喜青松在，火盡誰矜白璧真。", "嵇阮交遊思舊隠，臯夔功業記名臣。", "年來更嗜無生學，笑殺關西仗鉞人。"]'),
('2f17d05c-8a50-4d71-b9a8-4ca10e23c2a7','清明','宋庠','宋','宋诗','song-poetry','','[]','前旬風雨逼清明，柳色天高雪絮輕。',64,'全唐诗/poet.song.10000.json','["前旬風雨逼清明，柳色天高雪絮輕。", "冷落介推藏火月，寂寥潘令種花城。", "軍中蹋鞠人穿域，門外吹箎客詫餳。", "今日太官還直具，多年私邸隔朝纓。"]'),
('ee100e18-85ad-40e7-878a-c9875ae69f44','和吳侍郎謝余洎諸朝客見過亭沼','宋庠','宋','宋诗','song-poetry','','[]','碧瓦新堂壓素波，主人歡意駐鳴珂。',64,'全唐诗/poet.song.10000.json','["碧瓦新堂壓素波，主人歡意駐鳴珂。", "風清共覺煩襟快，觴急都忘醉弁俄。", "江葦有情侵岸出，野鷗無事掠船過。", "西牆墨妙須珍護，皇祐高秋勝永和。"]'),
('8ca050ac-0063-4232-b790-e1f458871fb6','胥集賢復舊官','宋庠','宋','宋诗','song-poetry','','[]','鸞鵲驚飛詔檢開，唐家僊殿育英才。',64,'全唐诗/poet.song.10000.json','["鸞鵲驚飛詔檢開，唐家僊殿育英才。", "毫端誤墨讒蠅盡，塞上求羣故馬來。", "咄咄書空徒有意，冥冥避弋本無猜。", "孤生舊辱知人舉，一夕聞風釋九回。"]'),
('cdcb1991-b19f-4342-b665-39e3b949fa45','從獵晚歸馬上默成奉呈承旨端明王學士','宋庠','宋','宋诗','song-poetry','','[]','天子乘冬校獵回，鈎陳平野轉瑶魁。',64,'全唐诗/poet.song.10000.json','["天子乘冬校獵回，鈎陳平野轉瑶魁。", "萬蹄未暮先追日，疊鼓非春已作雷。", "得儁風毛隨禁仗，犒勤霞液出仙杯。", "詞臣定有長楊賦，翰墨能銷幾許才。"]'),
('35f603a5-079b-4b5f-961f-67f863744469','次韵和度支蘇員外覆考進士文卷鎖宿景福殿','宋庠','宋','宋诗','song-poetry','','[]','祕邃嚴廬斗極傍，知君此夕較連章。',64,'全唐诗/poet.song.10000.json','["祕邃嚴廬斗極傍，知君此夕較連章。", "天移宿幕鄰堯屋，霞灧仙杯雜嵰霜。", "坐覺銅籤隨漏箭，卧驚銀漢入宮牆。", "精心百汰知無倦，千牘皆供夜石量。"]'),
('c62c928a-277c-4742-8077-1d018dd14243','屯田任君數以歌詩授余感嘆不足因成答贈','宋庠','宋','宋诗','song-poetry','','[]','綠髮仙郎藻思新，就中詩語更通神。',64,'全唐诗/poet.song.10000.json','["綠髮仙郎藻思新，就中詩語更通神。", "清襟逗興初無滓，綵筆呈華別有春。", "顧我風期情背俗，感君官職命欺人。", "湯湯聽盡流波曲，終愧衰聾賞未真。"]'),
('91330c02-434f-466c-b405-81cad2a68c6b','永興端明王左丞寄示見訓長句因爲後答','宋庠','宋','宋诗','song-poetry','','[]','西風書驛到河津，且喜開筩麗句新。',64,'全唐诗/poet.song.10000.json','["西風書驛到河津，且喜開筩麗句新。", "安石風流高映世，君房言語妙驚人。", "公懷遠略須經國，我愧華顛未乞身。", "惟有論交方寸地，歲寒留得比松筠。"]'),
('1cb8328d-0ea6-422f-b3fc-a28c23511bc3','答子京','宋庠','宋','宋诗','song-poetry','','[]','一辭雲陛五周年，瑣闥銷符寵再遷。',64,'全唐诗/poet.song.10000.json','["一辭雲陛五周年，瑣闥銷符寵再遷。", "時譽敢希吳陸俊，歸心偏識漢疏賢。", "蝸頭狼籍爭鋒地，鴻影徘徊避弋天。", "命駕不須頻見約，潁濱嵩麓有私田。"]'),
('370a2598-9c2e-4826-8858-207c6db001ad','閏十二月望日立春禁中作','宋庠','宋','宋诗','song-poetry','','[]','閏曆先春破臘寒，綵花金勝寵千官。',64,'全唐诗/poet.song.10000.json','["閏曆先春破臘寒，綵花金勝寵千官。", "水從太液池邊動，柳向靈和殿裏看。", "瑞氣因風生禁仗，暖暉依日上仙盤。", "須知聖運隨生殖，萬國年年共此歡。"]'),
('f5d3b3c2-f57a-4f3c-a960-914d1a3d0eb2','立春日置酒郡齋因追感三爲郡六迎春矣呈坐客','宋庠','宋','宋诗','song-poetry','','[]','閏章餘曆氣先回，臘尾新陽已暗催。',64,'全唐诗/poet.song.10000.json','["閏章餘曆氣先回，臘尾新陽已暗催。", "三改使符驚歲往，六傾賓酒駕春來。", "枝頭翦綵仙葩折，勝裏宜年寶字開。", "更聽美人金縷曲，從茲爭合捨尊罍。"]'),
('7f91a1cc-1d56-42fb-b91b-010e87f9b50b','晚春出郭游北山佛寺','宋庠','宋','宋诗','song-poetry','','[]','幽剎尋春傍翠微，遊人誰解惜芳菲。',64,'全唐诗/poet.song.10000.json','["幽剎尋春傍翠微，遊人誰解惜芳菲。", "陰晴野日不常見，紅白路花相雜飛。", "一世功名催俊傑，千金歌舞屬輕肥。", "左遷病守真無用，試學山公倒載歸。"]'),
('11d79c9e-ea8f-4e5a-a697-f65cd52c9359','淳之九兄以僕承乏制曹幸聯局事向當成績猥辱裁篇謹抒拙詩以謝來貺','宋庠','宋','宋诗','song-poetry','','[]','漢家挈令頼諸公，末至緣何玷選中。',64,'全唐诗/poet.song.10000.json','["漢家挈令頼諸公，末至緣何玷選中。", "馬尾不知書畫誤，鳥聲偏樂友心同。", "忘憂日接三杯善，軋思時分一溉功。", "敢向明廷邀異賞，從來儒術比司空。"]'),
('48118bfb-0075-44a3-887d-ad6511933c5e','新年謝故人惠建茗','宋庠','宋','宋诗','song-poetry','','[]','春筥收英得幾叢，小團珍串刻閩工。',64,'全唐诗/poet.song.10000.json','["春筥收英得幾叢，小團珍串刻閩工。", "甘踰寶屑非關露，快入煩襟不爲風。", "左䥶沸香殊有韵，越瓷涵綠更疑空。", "從來酪茗嘲傖鬼，莫枉奴名立異同。"]'),
('ae1a80c7-b2e5-4c43-9ae5-c514a6ba515f','陳勤之兄弟同登秀科俱宰江東大邑','宋庠','宋','宋诗','song-poetry','','[]','上林春色老朱櫻，誰見聯科紀佛名。',64,'全唐诗/poet.song.10000.json','["上林春色老朱櫻，誰見聯科紀佛名。", "睢苑妍辭俱右席，太丘遺業肯慚卿。", "離歌坐寫塤箎恨，邑政行聞魯衛聲。", "使橐盡堪傳尺素，雙函同慰一摇旌。"]'),
('24be0078-e8b5-4484-992d-5f10f8668673','宗人緘見過','宋庠','宋','宋诗','song-poetry','','[]','慈恩題墨七彫年，霰雪相逢倦客天。',64,'全唐诗/poet.song.10000.json','["慈恩題墨七彫年，霰雪相逢倦客天。", "男子詣曹羞會課，禿翁無版欲歸田。", "爻占後笑餘艱象，書入窮愁有剩篇。", "聞道漢家求失職，可能梁甲信灰然。"]'),
('23c0d2c5-241a-4b13-b44a-09de2b4adba4','閏三月再到西湖花卉已過春餘夏早景物亦佳因復留連日夕忘返','宋庠','宋','宋诗','song-poetry','','["\u897f\u6e56"]','再來湖上已春殘，物物隨時亦强歡。',64,'全唐诗/poet.song.10000.json','["再來湖上已春殘，物物隨時亦强歡。", "紫葉抽荷疑弄橐，翠皮包竹好裁冠。", "驚橈野鶩移沙渚，貪餌鮮鱗薦客盤。", "盡日臨流忘吏事，須知名世六條寬。"]'),
('78f61aba-7988-4cbc-a4f3-968c6ba0391f','重展西湖二首  其一','宋庠','宋','宋诗','song-poetry','','["\u897f\u6e56"]','綠鴨東陂已可憐，更因雲竇注西田。',64,'全唐诗/poet.song.10000.json','["綠鴨東陂已可憐，更因雲竇注西田。", "鑿開魚鳥忘情地，展盡江河極目天。", "向夕舊灘都浸月，過寒新樹便留煙。", "使君直欲稱漁叟，願賜閒州不計年。"]'),
('84e32221-f0c7-4ab3-a9e5-90bcf4ace0d1','重展西湖二首  其二','宋庠','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西北雲波逗異津，兩陂相合到城闉。',64,'全唐诗/poet.song.10000.json','["西北雲波逗異津，兩陂相合到城闉。", "橋橫斷岸纔通舫，路轉新洲不踏塵。", "倒影剩容霞底日，暖光平展鑑中春。", "摧頹病守時無用，堪與鷗鷳作主人。"]'),
('c45bf048-3a48-4b90-a0ee-f109da151413','次韵和次道學士獻贈留臺吳侍郎洛水泛舟之作','宋庠','宋','宋诗','song-poetry','','[]','歲晚風清洛霧開，有人沿泝避囂埃。',64,'全唐诗/poet.song.10000.json','["歲晚風清洛霧開，有人沿泝避囂埃。", "莊談解辯觀濠樂，潘興能添作賦才。", "蘭菊分洲爭向背，鳬鷖隨棹罷驚猜。", "留都吏役雖羈鞅，亦欲抽身更一陪。"]'),
('a3dd9349-d08d-41eb-ab60-32d8b3da0622','夜爐','宋庠','宋','宋诗','song-poetry','','[]','風窗夜永燭飄煤，坐擁空爐暖凍杯。',64,'全唐诗/poet.song.10000.json','["風窗夜永燭飄煤，坐擁空爐暖凍杯。", "束縕未求曹相火，冥心將冷子綦灰。", "禪牀隠竈徒驚俗，曲突徙薪枉備災。", "餘燼欲銷微霰集，燎薰援錦憶平臺。"]'),
('c0f138a8-ce47-4c8b-8d2f-d53b6db9c445','後園新水初滿坐高明臺遠眺','宋庠','宋','宋诗','song-poetry','','[]','濟渠冰解逗奫淪，花柳兼催近郭春。',64,'全唐诗/poet.song.10000.json','["濟渠冰解逗奫淪，花柳兼催近郭春。", "城外天形低合野，水邊樓影倒傾人。", "趁晴魚意雙游樂，助鬧禽聲百種新。", "老倚芳樽從外誚，且將吟嘯代經綸。"]'),
('9401247b-2ec3-4c5f-85bc-c7d47489bf70','送貴溪尉周懿文','宋庠','宋','宋诗','song-poetry','','[]','津亭理櫂拂朝霞，試補東溪縣道賒。',64,'全唐诗/poet.song.10000.json','["津亭理櫂拂朝霞，試補東溪縣道賒。", "旅突倦供樵客桂，官符貪及戍時瓜。", "蟾生海岸空弦濕，天倚山城一蓋斜。", "歲晚私書無憚數，輕郵不禁嶺頭花。"]'),
('764cb3a0-3b90-45c0-8df5-65bf0fe98f0d','送虞部楊員外出牧池州','宋庠','宋','宋诗','song-poetry','','[]','郎署新聞一進階，漢家臨遣重州臺。',64,'全唐诗/poet.song.10000.json','["郎署新聞一進階，漢家臨遣重州臺。", "人持澤節龍形出，路建風旟隼翼開。", "千頃江禾年有瑞，萬盆吳繭俗豐財。", "吟窗剩賞雲峰翠，即是踰朞報政回。"]'),
('484cc926-cc4a-4d3b-b221-669c0f2198ba','送集賢盛諫議出牧維揚','宋庠','宋','宋诗','song-poetry','','[]','江海多年滯軾熊，書林諫霤得儒宗。',64,'全唐诗/poet.song.10000.json','["江海多年滯軾熊，書林諫霤得儒宗。", "寬條一劄仙泥熟，慈宴千觴湛露濃。", "迎舸蔽川交畫鷁，隊笳橫浦細吟龍。", "輕揚俗改方圖舊，兩馬行催詔傳封。"]'),
('ed4d2172-3e6f-4cc3-8b81-0e5ce72f2f96','晚泊白村登舟回望因成拙句寄淮陽龍圖王給事','宋庠','宋','宋诗','song-poetry','','[]','臨艎西泝近神垌，六輔聯疆見驛亭。',64,'全唐诗/poet.song.10000.json','["臨艎西泝近神垌，六輔聯疆見驛亭。", "千里暮霞烘日脚，一篙春水皺天形。", "野橋煙火微分市，曲岸漁樵別有汀。", "忽憶主人恩意厚，倚檣回首涕空零。"]'),
('f0f36215-9c6d-4cea-9fa8-333ba3d5f3c1','和龍圖王學士經涂洛邑見寄','宋庠','宋','宋诗','song-poetry','','[]','謝病台階別邃旒，更榮符鑰守司州。',64,'全唐诗/poet.song.10000.json','["謝病台階別邃旒，更榮符鑰守司州。", "篋書已辯恩難報，臺禮雖頒政未修。", "潄石洛波鳴佩曉，插雲嵩色紺屏秋。", "煩君麗句催登覽，欲便長隨麋鹿游。"]'),
('fa49a069-dfac-4868-a826-18e5bd9e51c0','楊寺丞以新集見授','宋庠','宋','宋诗','song-poetry','','[]','荆臺杯酒接慇懃，已是緹灰十五春。',64,'全唐诗/poet.song.10000.json','["荆臺杯酒接慇懃，已是緹灰十五春。", "學舍早欣游霧露，辭條今服際天人。", "沈居雌蜺那知賞，葉牖神龍更駭真。", "侍上可能無狗監，子虛賦就長卿貧。"]'),
('ab051c34-d838-4ebd-b0ee-f538ca0bb41f','天禧詔罷寄王貫之','宋庠','宋','宋诗','song-poetry','','[]','裂繻無路學西游，衡木爲扉戀一丘。',64,'全唐诗/poet.song.10000.json','["裂繻無路學西游，衡木爲扉戀一丘。", "阮籍自多回轍淚，虞卿長有著書愁。", "江邊客素沈驚鯉，海上機心失故鷗。", "借問騷人才幾許，莫因鶗鴂枉悲秋。"]'),
('1c0471cc-0a2b-4005-8239-cfadf6f21887','乾興詔罷自詠','宋庠','宋','宋诗','song-poetry','','[]','忍當昭世卧隆中，西笑無謀始諱窮。',64,'全唐诗/poet.song.10000.json','["忍當昭世卧隆中，西笑無謀始諱窮。", "鷗散海邊漁事廢，炙殘京口客盤空。", "鄉魂怨曉虛爲蝶，頭葆悲秋不後蓬。", "欲把遺編論興廢，諸儒爭奈喜嘲雄。"]'),
('3d7c6265-5ca2-4edd-afc1-bf3c8e4f78df','奉詔過都代書寄昭文相公','宋庠','宋','宋诗','song-poetry','','[]','六年衰鬢兩爲州，何意瓜時謁冕旒。',64,'全唐诗/poet.song.10000.json','["六年衰鬢兩爲州，何意瓜時謁冕旒。", "去位本無三已色，過城應有復來謳。", "吹虀膽怯空思勉，淪骨恩深未易酬。", "即日詣門重謝罪，豫慚危涕滿中篝。"]'),
('7d5756ad-2e76-4e5c-8956-93d5ccddb4ac','送安陸朱通判赴召兼過許田別墅','宋庠','宋','宋诗','song-poetry','','[]','綠綈珍檢九天來，綬笥騰裝拂簿埃。',64,'全唐诗/poet.song.10000.json','["綠綈珍檢九天來，綬笥騰裝拂簿埃。", "鈴閣餞歌鵾瑟怨，璧田仙里駟門開。", "厨書久汗南山竹，征袂濃薰北使梅。", "歲晚林光催奉計，五雲城闕倚瑶魁。"]'),
('c1da86e9-f1e4-407f-a058-c8ecb823b13c','和吳侍郎龍門寶應寺設齋','宋庠','宋','宋诗','song-poetry','','[]','闕塞千巖入畫圖，八關修供柅征車。',64,'全唐诗/poet.song.10000.json','["闕塞千巖入畫圖，八關修供柅征車。", "半斤運泰賢將用，不二門深疾始除。", "香鉢凈羞熏寶席，法螺仙曲逗晴虛。", "從茲定許陪登覺，肯效區區栗里輿。"]'),
('0959896f-355f-4f1f-89d4-9df800852b77','和吳侍郎相從經歲忽有陝許之別見貺長句','宋庠','宋','宋诗','song-poetry','','[]','接武西臺屬鉅賢，琴樽歡意滿山川。',64,'全唐诗/poet.song.10000.json','["接武西臺屬鉅賢，琴樽歡意滿山川。", "論交共到忘言地，感別空驚易守年。", "陝界霜氛迎喜氣，潁郊秋色犯華顛。", "卜鄰自有歸休約，終就溪林占一廛。"]'),
('cbbef6ef-4b3c-435e-8f74-f2741f2c6089','送資政侍讀侍郎西赴陝郊','宋庠','宋','宋诗','song-poetry','','[]','君欲歸休未得休，再持符節定西侯。',64,'全唐诗/poet.song.10000.json','["君欲歸休未得休，再持符節定西侯。", "深嚴殿籍恩圖舊，蔽芾棠歌野續謳。", "洛浦神仙觀送客，崤陵風雨避傳騶。", "高懷莫作衰年調，公府重來尚黑頭。"]'),
('451988e0-15cf-4bfa-8e13-2b31b1de7b7e','和河間通博王太博見貺春雨應時雅什','宋庠','宋','宋诗','song-poetry','','[]','東來春色變層陰，甘霈前符望歲心。',64,'全唐诗/poet.song.10000.json','["東來春色變層陰，甘霈前符望歲心。", "雲葉乍驚重礎潤，土膏先過一犂深。", "皇慈已浹流根澤，芳節殊非貫序霖。", "忽枉新篇真寡和，鼻聲衰濁費長吟。"]'),
('93a031f8-dada-44a0-8c14-4843b2cb3063','題高明堂後池雜景二首  其一','宋庠','宋','宋诗','song-poetry','','[]','荒城岑寂冒春霏，竹落江村具體微。',64,'全唐诗/poet.song.10000.json','["荒城岑寂冒春霏，竹落江村具體微。", "蛙怒愛爲先雨叫，燕輕多作逆風飛。", "印波鸞鑑新荷小，礙路犀簪早筍肥。", "極目纖塵都不動，元規安得汙人衣。"]'),
('447b33ef-c135-4392-a2a1-d8a3efca3596','題高明堂後池雜景二首  其二','宋庠','宋','宋诗','song-poetry','','[]','一竇春泉貫曉溪，水光涵物見纖微。',64,'全唐诗/poet.song.10000.json','["一竇春泉貫曉溪，水光涵物見纖微。", "波鳬泛泛騷人卜，風蝶翩翩佛助飛。", "雨足舊蘭穿畹出，餌香鮮鮪壓鈎肥。", "昔聞緩带猶堪羨，退食何妨野客衣。"]'),
('455289ed-36fa-4dd9-949f-d8c27aa42338','憂闋還臺次韵和道卿學士終喪歸集賢舊職見寄二首  其一','宋庠','宋','宋诗','song-poetry','','[]','半生多難竄民廛，北闕重來雪履穿。',64,'全唐诗/poet.song.10000.json','["半生多難竄民廛，北闕重來雪履穿。", "木在溝中寧有間，人從河上更相憐。", "塵棲綬笥昏餘采，蟲食書縢脫故篇。", "不敢對君重撫臆，孤懷同是一潸然。"]'),
('241a2b84-d569-468e-9f12-72e62bdb72ab','憂闋還臺次韵和道卿學士終喪歸集賢舊職見寄二首  其二','宋庠','宋','宋诗','song-poetry','','[]','解籍書林同遇春，煢煢孤影弔窮塵。',64,'全唐诗/poet.song.10000.json','["解籍書林同遇春，煢煢孤影弔窮塵。", "茂陵久卧添遲思，東觀重歸有戲賓。", "爭食已慚池鶩飽，忘機更待海鷗親。", "懣然末曲何能續，聊誌當年並賦人。"]'),
('44ebdbe4-103a-4df2-ae96-3f3b6ff70285','默誦','宋庠','宋','宋诗','song-poetry','','[]','虛名三紀玷王朝，晚歲剛腸萬慮銷。',64,'全唐诗/poet.song.10000.json','["虛名三紀玷王朝，晚歲剛腸萬慮銷。", "篤學自依袁伯業，醒狂誰比蓋寬饒。", "將旄燭日逢兵偃，隠谷連雲負客招。", "白首報恩雖竭節，擬留餘力事耕樵。"]'),
('dbc89180-3ed6-43d9-91e2-7687537d6092','贈令狐進士','宋庠','宋','宋诗','song-poetry','','[]','闕里高談擅席珍，多年嵇痺嘆沈淪。',64,'全唐诗/poet.song.10000.json','["闕里高談擅席珍，多年嵇痺嘆沈淪。", "封軺續食論鄉士，綵服承顔斷織親。", "風直鷁郊傷六翮，機藏鼷弩惜千鈞。", "載餚誰就揚雄宅，覆瓿書成擔石貧。"]'),
('b8f16937-39d9-4781-81c3-aa72b57f0444','感懷寄進士胡肅','宋庠','宋','宋诗','song-poetry','','[]','離懷何事共凄然，雲路無因著祖鞭。',64,'全唐诗/poet.song.10000.json','["離懷何事共凄然，雲路無因著祖鞭。", "賦苑竹荒沈舊賞，書郵梅老怨殘年。", "莊魂斷處星垂地，楚思摇時水接天。", "趙壹窮愁堪自笑，擬將文腹敵囊錢。"]'),
('75eb1342-3b97-44e8-80ee-f7adbd11c53a','送謝沂進士','宋庠','宋','宋诗','song-poetry','','[]','坦牀仙格照瓊筵，歸待蘭陔補逸篇。',64,'全唐诗/poet.song.10000.json','["坦牀仙格照瓊筵，歸待蘭陔補逸篇。", "別路雲霞交友闊，慶門酥酪弟兄賢。", "春郊送目車流水，夕館迷魂月上弦。", "續食定知西笑近，馬生詞賦賈生年。"]'),
('76012827-f249-4f58-b974-16728af6dc83','送總閣學士守秦亭二首  其一','宋庠','宋','宋诗','song-poetry','','[]','幾日章街認錦韉，平明頒節撫秦汧。',64,'全唐诗/poet.song.10000.json','["幾日章街認錦韉，平明頒節撫秦汧。", "嚴廬侍從宣勞久，郄府詩書得帥賢。", "彀騎千蹄嘶隴月，城笳三疊破羌烟。", "賓簪自古從軍樂，別夢空隨使幕蓮。"]'),
('aca4c7a7-5736-4ae0-9ce3-96632fc051e9','送總閣學士守秦亭二首  其二','宋庠','宋','宋诗','song-poetry','','[]','綠圖層閣倚昭回，瑞鷃驚飛詔押開。',64,'全唐诗/poet.song.10000.json','["綠圖層閣倚昭回，瑞鷃驚飛詔押開。", "關內趙張人續譽，禁中頗牧帝憐才。", "垂鞶虎綬朝裝出，夾轂蛇矛使仗來。", "坐鎮平時文檄簡，赤囊邊瑣有輕埃。"]'),
('f08b8369-cdbb-47fd-8308-8518d6fa921b','清明出沐','宋庠','宋','宋诗','song-poetry','','[]','曉樹陰岑客舍春，卿輿不訪著書人。',64,'全唐诗/poet.song.10000.json','["曉樹陰岑客舍春，卿輿不訪著書人。", "長楸有地金成埒，曲突無烟桂徙薪。", "自欠解蘭拋北阜，更堪鳴磬是南鄰。", "餳香醖冷沈歡緒，枉負山郎出沐辰。"]'),
('b5d99478-e928-4494-978d-ee6c98b5464f','朝謁待漏偶成詠懷','宋庠','宋','宋诗','song-poetry','','[]','天街殘月斗城西，五里葱葱瑞霧迷。',64,'全唐诗/poet.song.10000.json','["天街殘月斗城西，五里葱葱瑞霧迷。", "仙翰入陪廱澤鷺，曉籌初聽汝南雞。", "星翻徼道千廬密，雲斂觚稜兩觀齊。", "自顧山林疏賤質，誰將車馬載驚鼷。"]'),
('c3851acc-2a66-42f3-9c53-1d2ffc1eb21f','孟津跨大河寒氣特盛歲暮作','宋庠','宋','宋诗','song-poetry','','[]','河裏孤城歲倍寒，冰霜千里正漫漫。',64,'全唐诗/poet.song.10000.json','["河裏孤城歲倍寒，冰霜千里正漫漫。", "爐熏寶焰翻沈暖，酒入衰容不借丹。", "翠幕障風褰影數，玉琴抽雪按徽難。", "天高木落千花盡，閒撫青松仔細看。"]'),
('a515c23e-862f-447c-be20-cbc8820c068a','世事','宋庠','宋','宋诗','song-poetry','','[]','世事悠悠未遽央，虛名真意兩相忘。',64,'全唐诗/poet.song.10000.json','["世事悠悠未遽央，虛名真意兩相忘。", "休誇失馬曾歸塞，未省牽牛解服箱。", "四客高風輕楚漢，五君新詠棄山王。", "秋來數有漁樵夢，多在箕峰潁水旁。"]'),
('3fb29a17-592b-4831-903d-315826e802e8','和吳侍郎留題北樓','宋庠','宋','宋诗','song-poetry','','[]','疾間勤勤解郡章，北樓舒嘯寄徜徉。',64,'全唐诗/poet.song.10000.json','["疾間勤勤解郡章，北樓舒嘯寄徜徉。", "山圍軒后乘車野，水接堯民洗耳鄉。", "拂衽風頭迎爽籟，壓林霞尾送殘陽。", "冶城極望雖高世，爭奈臨秋鬢未霜。"]'),
('cea13ae5-89d7-4809-aba6-ac39b441ce76','寄許師孟','宋庠','宋','宋诗','song-poetry','','[]','鶗鴂三驚楚澤秋，回腸更用斛添愁。',64,'全唐诗/poet.song.10000.json','["鶗鴂三驚楚澤秋，回腸更用斛添愁。", "燕臺市駿千金骨，漢客逃名九罭鰌。", "木斷華樽俱失性，瓢空陋巷獨堪憂。", "夏畦墦食非吾事，終訪班生問一丘。"]'),
('5adcb649-35d1-49c1-a582-ffa7eeb356a5','同年胡宿自江外寄遺詩筆雜文','宋庠','宋','宋诗','song-poetry','','[]','萬仞青雲接翼翔，江南離思滿雕章。',64,'全唐诗/poet.song.10000.json','["萬仞青雲接翼翔，江南離思滿雕章。", "輕投暗路珠無脛，驟濯迷魂玉有漿。", "奏記諸公多感慨，擬騷前哲剩凄凉。", "寄懷何止三年字，留祕傳家古錦囊。"]'),
('a2a930c5-b3ab-4c5a-a3e0-c98db6887c95','寄子京','宋庠','宋','宋诗','song-poetry','','[]','八年三郡駕朱輪，更忝鴻樞對國均。',64,'全唐诗/poet.song.10000.json','["八年三郡駕朱輪，更忝鴻樞對國均。", "老去師丹多忘事，少來之武不如人。", "車中顧馬空能數，海上逢鷗想見親。", "惟有弟兄歸隠志，共將耕鑿報堯仁。"]'),
('8e6c8d62-ee7e-4c55-9021-a7781491a90a','晚春小園觀物','宋庠','宋','宋诗','song-poetry','','[]','小園乘暖敞孤齋，畦埒經春盡綠苔。',64,'全唐诗/poet.song.10000.json','["小園乘暖敞孤齋，畦埒經春盡綠苔。", "新筍偶隨枯篠出，野花閒抱故藤開。", "雙桐夾路元標井，酸棗依牆本乏臺。", "北戶清風時一至，此身疑到上皇來。"]'),
('8b9d1219-08eb-4e1c-98b8-4851c1d2b63e','郡圃觀春物有感','宋庠','宋','宋诗','song-poetry','','[]','河橋煙北寂寥城，山圃雖春氣尚清。',64,'全唐诗/poet.song.10000.json','["河橋煙北寂寥城，山圃雖春氣尚清。", "戲蝶有時飛自遠，野禽終日語無情。", "露痕浥浥添花重，風意沾沾助絮輕。", "看徧物華還自看，乾坤同是一浮生。"]'),
('920bc220-7500-4100-9803-2f506d8d7b81','晚出池上觀秋物','宋庠','宋','宋诗','song-poetry','','[]','臨溪長是見歸烏，摇落初驚歲物徂。',64,'全唐诗/poet.song.10000.json','["臨溪長是見歸烏，摇落初驚歲物徂。", "虎掌煙芒金穗密，雁頭霜葉紺輪枯。", "差差去幕東西燕，兩兩隨波上下鳬。", "更向岸邊橫飲舫，便疑狂醉宿江湖。"]'),
('a37de30d-f921-4f90-8414-896c7340f3b6','秋霽觀野物','宋庠','宋','宋诗','song-poetry','','[]','雨畢天高卷斷虹，郊原無物不秋豐。',64,'全唐诗/poet.song.10000.json','["雨畢天高卷斷虹，郊原無物不秋豐。", "禾麻自稱霜前熟，梨棗偏依日處紅。", "煙外短帘閒映柳，水邊輕翼暗隨風。", "田廬我亦牽魂夢，歸去嵩陽一老翁。"]'),
('43484bd9-0674-4f40-a582-6b1c81112be8','孟津晚景','宋庠','宋','宋诗','song-poetry','','[]','二月春風引夕陰，鞏煙邙樹悵登臨。',64,'全唐诗/poet.song.10000.json','["二月春風引夕陰，鞏煙邙樹悵登臨。", "醯鷄甕外天方闊，偃鼠河濱水正深。", "萬疊紺螺山北聳，半邊紅壁日西沈。", "憑高薄暮人誰見，一寸如丹魏闕心。"]'),
('f2c9d347-4936-460a-ab9a-dba1fb61b371','晚出池上','宋庠','宋','宋诗','song-poetry','','[]','憭慄梧楸似楚騷，霜餘寒水失溪毛。',64,'全唐诗/poet.song.10000.json','["憭慄梧楸似楚騷，霜餘寒水失溪毛。", "游鱗潑潑心應樂，亂雀飛飛意不高。", "平世功名難强立，昔賢卿相是真逃。", "人間萬事無涯際，爭得先生一藉糟。"]'),
('eb00823c-7108-43cf-ae98-52c0da03c336','次韵和吳侍郎答汝州劉從事','宋庠','宋','宋诗','song-poetry','','[]','賢路綢繆早奮庸，搢紳元許黑頭公。',64,'全唐诗/poet.song.10000.json','["賢路綢繆早奮庸，搢紳元許黑頭公。", "巖霖暫卷浮雲外，國棟來參散櫟中。", "仙禁巢阿思瑞鶠，野場收弋看冥鴻。", "恐難便遂東山卧，憂樂須將一世同。"]'),
('52c46e16-c779-42b1-979e-176d2f5b2d9b','寄武昌胡從事','宋庠','宋','宋诗','song-poetry','','[]','君家酥酪弟兄賢，督府從軍滯幕蓮。',64,'全唐诗/poet.song.10000.json','["君家酥酪弟兄賢，督府從軍滯幕蓮。", "江上歸音魚失素，天邊離思月成弦。", "阮毫答記無遺草，楚賦悲秋有剩篇。", "玉骨道風沈俊久，漢條新計會甘泉。"]'),
('8b1efc9b-0cd0-4507-8f37-ee78dfde502d','春陰復霽','宋庠','宋','宋诗','song-poetry','','[]','河外輕寒氣未佳，春襟愁目徧天涯。',64,'全唐诗/poet.song.10000.json','["河外輕寒氣未佳，春襟愁目徧天涯。", "濃雲破綻翻無雨，落日因循便作霞。", "麥隴寸苗思汙雉，柳灘新葉欲藏鴉。", "如膏且冀均農惠，莫枉層陰挫物華。"]'),
('1c4dea4d-def6-4694-894b-3c35e88231f0','永陽登樓懷闕下知己','宋庠','宋','宋诗','song-poetry','','[]','西北樓邊路欲分，神臯不見見浮雲。',64,'全唐诗/poet.song.10000.json','["西北樓邊路欲分，神臯不見見浮雲。", "晉郵尺牘波中斷，洛客歸心笛裏聞。", "麗賦有情傷桂魄，勞歌無節怨蘭薰。", "漢家續食催西上，忍逐江鷗狎舊羣。"]'),
('2b3fdb38-7081-4dba-b392-f9c2afe5533c','春霽漢南登樓望懷仲氏子京','宋庠','宋','宋诗','song-poetry','','[]','三楚風煙會漢津，憑高倦目此城闉。',64,'全唐诗/poet.song.10000.json','["三楚風煙會漢津，憑高倦目此城闉。", "山前霧密疑藏市，樓上塵輕不污人。", "鳴瑟久拋雩舞地，稱觴更負永和春。", "私書一紙離懷苦，望斷波中六六鱗。"]'),
('84404f8f-72e7-408b-9981-6e5f2a248bcb','春日樓上有寄','宋庠','宋','宋诗','song-poetry','','[]','雲葉西來拂畫樓，江南何處不汀洲。',64,'全唐诗/poet.song.10000.json','["雲葉西來拂畫樓，江南何處不汀洲。", "三春草綠王孫路，萬海梅殘隴使郵。", "落照窗扉塵作馬，黄昏簾幕月成鉤。", "張衡藻思能多少，玉案貂襜各自愁。"]'),
('312b0f8f-4ed4-468f-9535-cb3302f90543','淮南汶上三見春物有感','宋庠','宋','宋诗','song-poetry','','[]','一麾南北數移官，三見鶑花送雁寒。',64,'全唐诗/poet.song.10000.json','["一麾南北數移官，三見鶑花送雁寒。", "雙鬢欺人還似雪，寸心憂國本如丹。", "雕蟲曲藝論文淺，乘障迂儒破敵難。", "惟有歸耕初志在，故田西接飲牛灘。"]'),
('efdf6e90-0434-4990-b7ac-cdddf939df80','暑雨初霽','宋庠','宋','宋诗','song-poetry','','[]','日轉西軒小霧開，羲皇高興伴風來。',64,'全唐诗/poet.song.10000.json','["日轉西軒小霧開，羲皇高興伴風來。", "層雲氣潤猶蒸礎，殘電光微不應雷。", "曲沼清渾魚對躍，暮簾明滅燕雙回。", "憑高更結京華恨，魂遶梁園舊吹臺。"]'),
('121eb7f7-c9a8-4299-b0d5-a9181961f3ec','暑雨夕霽','宋庠','宋','宋诗','song-poetry','','[]','天角殘虹截暮暉，南樓風快暑煙微。',64,'全唐诗/poet.song.10000.json','["天角殘虹截暮暉，南樓風快暑煙微。", "月波半露金樞穴，雲葉全收玉女衣。", "氣爽戍樓孤鵲去，霧沈荒苑數螢歸。", "凉軒更作東山詠，何處莊環有世機。"]'),
('a2e2264f-b2bf-4cc6-a6a1-5f866de4aee1','秋出近郊','宋庠','宋','宋诗','song-poetry','','[]','修邙纔轉便維嵩，都占黄河小曲中。',64,'全唐诗/poet.song.10000.json','["修邙纔轉便維嵩，都占黄河小曲中。", "秋助峰巒相倚碧，日催梨棗一番紅。", "煙蕪雖歇猶藏野，霜葉能飛不待風。", "關輔俗淳無巧弋，天邊何意有驚鴻。"]'),
('49e1d48a-31ae-42a3-84e0-19122e65559f','初至洛陽府廨有東樓曲沼之勝時春色已過園林寂寞晚坐樓上作','宋庠','宋','宋诗','song-poetry','','[]','登臨何處恨春殘，樓上池邊夕照間。',64,'全唐诗/poet.song.10000.json','["登臨何處恨春殘，樓上池邊夕照間。", "非意野雲遮倦目，無情空水鑑衰顔。", "青谿久負幽人約，白髮初辭宰相班。", "才與不才何足辨，此心都擬付莊環。"]'),
('813fdeb6-4edd-434c-8a78-1ec47534e43a','宮保龐丞相以詩二首見寄次韵和答  其一','宋庠','宋','宋诗','song-poetry','','[]','西畿三輔切天閽，何意頒來細札文。',64,'全唐诗/poet.song.10000.json','["西畿三輔切天閽，何意頒來細札文。", "學謬詩書慚作帥，身非甽畝更思君。", "使軺結轍橫周道，鄉木交陰憶漢枌。", "保傅上才敦雅眷，滿章褒意藹蘭薰。"]'),
('b3676084-cf84-41dd-bd03-36eb1fd9a175','宮保龐丞相以詩二首見寄次韵和答  其二','宋庠','宋','宋诗','song-poetry','','[]','出入台階謝奮庸，白頭持節更爲公。',64,'全唐诗/poet.song.10000.json','["出入台階謝奮庸，白頭持節更爲公。", "臨民不稱瞻巖尹，慰俗猶依贈扇風。", "天許雲鴻矰繳外，世憐池鶩稻糧中。", "一聞麗唱情何極，心結平津舊閣東。"]'),
('21b84f72-66b0-4a04-98b4-3f5fff2fcf96','次韵和吳侍郎喜令弟學士請告歸省','宋庠','宋','宋诗','song-poetry','','[]','秋來遥說灑煩襟，季虎昆龍伴嘯吟。',64,'全唐诗/poet.song.10000.json','["秋來遥說灑煩襟，季虎昆龍伴嘯吟。", "弓影奮疑臨酒釋，荆枝歡意戀叢深。", "仙山校籍催歸傳，宿館銷魂警曙砧。", "我亦白頭思共被，非君誰照急難心。"]'),
('27543456-460a-4f06-8f80-e4814149da0f','寄致政杜相國','宋庠','宋','宋诗','song-poetry','','[]','多年零雨詠公歸，得謝高懷與世違。',64,'全唐诗/poet.song.10000.json','["多年零雨詠公歸，得謝高懷與世違。", "池鳳何嘗嗟見奪，冥鴻終不更低飛。", "壽觴應舉三朋酒，師衮閒拋一品衣。", "我亦摧頹踰耳順，異時惇史託餘輝。"]'),
('67845998-29f8-47af-b3cf-e1f5bde7f38b','酬仲微以舍弟忝直螭階余近塵鳳署見慶之作','宋庠','宋','宋诗','song-poetry','','[]','世隠東畿賦遂初，荆枝相樂本田廬。',64,'全唐诗/poet.song.10000.json','["世隠東畿賦遂初，荆枝相樂本田廬。", "偶隨幽鳥同還俗，何意驚鼷並載車。", "浴殿封芝慚視草，史階簪筆玷成書。", "猶欣夙契寒松在，持謝雕章悅柏餘。"]'),
('ed6a0a7d-beff-4efc-b85e-4f04866da795','京師故僚以余退居近畿數賜存問因敘懷自感','宋庠','宋','宋诗','song-poetry','','[]','多年京洛寓靈臺，貪見三山縹帙開。',64,'全唐诗/poet.song.10000.json','["多年京洛寓靈臺，貪見三山縹帙開。", "野鶴據軒真冒祿，跛䍧生奧苦爲災。", "茂陵養疾愔愔骨，莊室刳心寂寂灰。", "南鄙孤城非灞岸，欲乘春氣望瑶魁。"]'),
('e2925225-4c57-4bb5-8343-b93820ff081d','次韵和運使王密學見貽之作','宋庠','宋','宋诗','song-poetry','','[]','天畿巡部聽車音，更值秋空卷夕霖。',64,'全唐诗/poet.song.10000.json','["天畿巡部聽車音，更值秋空卷夕霖。", "擊壤但聞堯俗樂，寬條方識漢恩深。", "釃渠引漕民兼富，飛檄宣風令莫侵。", "餘藻相存知厚意，孤松凌雪鶴鳴陰。"]'),
('29b43836-2ebd-4a44-916b-2fcd17c25fc5','送蔣御史領江東運使','宋庠','宋','宋诗','song-poetry','','[]','幾日都亭避憲驄，使臺分節按江東。',64,'全唐诗/poet.song.10000.json','["幾日都亭避憲驄，使臺分節按江東。", "朝端舊簡飛霜白，關外連艘餉粟紅。", "晨鼓疊喧雞埭月，暝帆遥卸雀桁風。", "先秋若有離懷詠，剩取芳筠作信筒。"]'),
('90490bb6-4102-4955-bb6f-6690c97c8423','寓直晚歸見天街早春景物','宋庠','宋','宋诗','song-poetry','','[]','霽雲銜苑雪雲開，春色先從禁籞回。',64,'全唐诗/poet.song.10000.json','["霽雲銜苑雪雲開，春色先從禁籞回。", "馬上嫵眉偏認柳，樓前妝額固知梅。", "吹殘鳳籥驚寒律，忙殺鴟幐取凍醅。", "莫問康年行樂意，壽觴初罷佛燈來。"]'),
('67e2ca01-e7a6-4b42-84df-b61e17a0c489','次韵和安陸王工部郡圃早春','宋庠','宋','宋诗','song-poetry','','[]','鄖波翻縠抱城流，夢比春風第一州。',64,'全唐诗/poet.song.10000.json','["鄖波翻縠抱城流，夢比春風第一州。", "槁質枉陪溫樹密，勝襟還負峴亭游。", "風英百種紛如繡，溪羽千聲巧命儔。", "遥識使臣興感地，浮雲長映最高樓。"]'),
('658376e2-e8ae-4f18-a070-282fed927632','和經略宣徽吳太尉以將經洛陽舊隠之作','宋庠','宋','宋诗','song-poetry','','[]','公有長才動縉紳，朝廷不肯棄名臣。',64,'全唐诗/poet.song.10000.json','["公有長才動縉紳，朝廷不肯棄名臣。", "高懷空結山中社，遠略今清塞外塵。", "竹塢未荒溪葉密，菊叢雖舊徑花新。", "南臺素壁題名處，莫惜麾鐃一駐輪。"]'),
('d13f7a0b-3080-473f-b484-788cd6de1de8','入朝感舊','宋庠','宋','宋诗','song-poetry','','[]','二紀便蕃冒主恩，歸來榮感兩驚魂。',64,'全唐诗/poet.song.10000.json','["二紀便蕃冒主恩，歸來榮感兩驚魂。", "昌辰盡見羣龍出，急景俱隨駭駟奔。", "史冊褒賢空汗竹，山丘餘泣已陳根。", "此身不減靈光殿，遺老班中巋獨存。"]'),
('0f8fac5f-1baa-49b6-b750-fa9540f77387','久客懷故里','宋庠','宋','宋诗','song-poetry','','[]','漢枌遺産接東陂，舒嘯行吟失舊期。',64,'全唐诗/poet.song.10000.json','["漢枌遺産接東陂，舒嘯行吟失舊期。", "嶺上孤猿驚別久，山中芳草怨歸遲。", "鮒波希潤寧堪待，龍斷求豐忍自欺。", "負郭已荒金未佩，天涯浩歎滿隆墀。"]'),
('780aef86-d5e4-4b5b-a646-a949a8a7939a','和吳侍郎惠詩','宋庠','宋','宋诗','song-poetry','','[]','最樂乘秋浩氣全，洛臺歸興滿新篇。',64,'全唐诗/poet.song.10000.json','["最樂乘秋浩氣全，洛臺歸興滿新篇。", "霞漿不雜甘辛味，廟瑟都遺掩抑弦。", "崑嶺希珍驚倦鵲，蘭臺清吹飲吟蟬。", "欲知傳誦人多少，正似三都紙貴年。"]'),
('d33e4b9b-785c-48fc-9d86-45fff3f46ad8','求志','宋庠','宋','宋诗','song-poetry','','[]','壯心銷盡見天機，敢惜功名與世違。',64,'全唐诗/poet.song.10000.json','["壯心銷盡見天機，敢惜功名與世違。", "拙似潘生難濟用，老于蘧瑗轉知非。", "多年鷄口慚爭食，自古駑筋愛舉肥。", "常恐冒榮孤晚節，春來魂夢到柴扉。"]'),
('1254a2f5-5740-4d31-8696-14eea7600e1d','和子京旅況','宋庠','宋','宋诗','song-poetry','','[]','春城岑寂早花開，久脫冠梁有薄埃。',64,'全唐诗/poet.song.10000.json','["春城岑寂早花開，久脫冠梁有薄埃。", "安邑本緣饑腹累，茂陵非爲富貲來。", "驚羅晚雀同茅宇，爭席春農伴茗杯。", "自有忘言記真意，不煩騷客賦銜枚。"]'),
('e2415fed-4217-4dce-a519-2f4d94aedbb7','和吳侍郎謝予送酒','宋庠','宋','宋诗','song-poetry','','[]','歲稔兵厨富酒材，幾槽新溜滴芳醅。',64,'全唐诗/poet.song.10000.json','["歲稔兵厨富酒材，幾槽新溜滴芳醅。", "秋香自與蘭英合，春色潜依竹葉回。", "蟹甲佐歡賓斝溢，鴟幐參貢縣郵催。", "雖非平樂十千斗，願奉康成三百杯。"]'),
('eb81e555-8050-4c46-91b0-4bc0aef1ae5f','秋夕感懷','宋庠','宋','宋诗','song-poetry','','[]','風蟾成暈露成霜，玉箭添籌怨漏長。',64,'全唐诗/poet.song.10000.json','["風蟾成暈露成霜，玉箭添籌怨漏長。", "四載歸心同騎省，半分仙骨過東陽。", "驚猿久負排巢客，乘駟誰輕喻蜀郎。", "掩鼻裁詩多感慨，吟餘星斗轉秋潢。"]'),
('728be328-c3a6-4b66-aeec-3b79fc4e48c3','題江南程氏家清風閣','宋庠','宋','宋诗','song-poetry','','[]','臨波飛閣迓層飆，溽暑狂酲此併銷。',64,'全唐诗/poet.song.10000.json','["臨波飛閣迓層飆，溽暑狂酲此併銷。", "客至自同仙寇御，舟歸不減鄭公樵。", "雲明別島朝虹飲，月碎前溪夜鯉跳。", "借問北窗餘興否，羲皇高世一相招。"]'),
('ae08251e-0052-4843-8232-649f432c00fc','和吳侍郎游普明禪院','宋庠','宋','宋诗','song-poetry','','[]','履道遺坊敞凈廬，昔人曾此賦閒居。',64,'全唐诗/poet.song.10000.json','["履道遺坊敞凈廬，昔人曾此賦閒居。", "園經漢傳揮金罷，石記商賢作礪餘。", "綠玉千竿多映水，蒼帷雙樹競凌虛。", "神交不必論年輩，一夕清吟萬境如。"]'),
('3f6fafc7-20ae-4136-a5e8-e988d3937e79','次韵范純仁和郭昌朝寺丞見寄二首  其一','宋庠','宋','宋诗','song-poetry','','[]','岷峨秀氣入京華，鵬翼摶風勢莫涯。',64,'全唐诗/poet.song.10000.json','["岷峨秀氣入京華，鵬翼摶風勢莫涯。", "崑玉照人呈美璞，楚蘭芬畹擢新芽。", "朝廷遷陟先諸彥，閭里光榮在一家。", "不鄙蒙陽疲病守，肯來同醉岸烏紗。"]'),
('303e3866-0045-4c0a-8daa-6ebcf5e04f40','次韵范純仁和郭昌朝寺丞見寄二首  其二','宋庠','宋','宋诗','song-poetry','','[]','言路再居無少補，護邊三歲乏微勛。',64,'全唐诗/poet.song.10000.json','["言路再居無少補，護邊三歲乏微勛。", "非才自合投閒地，竭節終期報聖君。", "老去風光流似水，病來世味薄如雲。", "讀書記一將忘十，少壯誰教不自勤。"]'),
('81c9b588-fe0c-42b1-8ed1-4dc7840543b3','送龍圖燕待制出守梓潼','宋庠','宋','宋诗','song-poetry','','[]','寶構沈沈夕霧迷，儒林俊老出分麾。',64,'全唐诗/poet.song.10000.json','["寶構沈沈夕霧迷，儒林俊老出分麾。", "中天祕牒河龍負，上路鳴鐃筰馬馳。", "香襲寵鞶驚放獸，野連豐芋蔽蹲鴟。", "潼江肯學淮陽卧，仙液真腴壯壽祺。"]'),
('7936a614-3cbe-4d73-b737-d96d6eb6bc1c','次韵答襄陽龍圖燕給事慶僕序直禁林','宋庠','宋','宋诗','song-poetry','','[]','右銀仙闥倚雲開，孤客緣何待詔來。',96,'全唐诗/poet.song.10000.json','["右銀仙闥倚雲開，孤客緣何待詔來。", "一節新恩迂使驛，五花前署隔公台。", "英游但喜儒紳集，涸使偏驚吏腕催。", "晝檻寶鵷翔帝竹，夕軒瑶斗掛宮槐。", "朝無濫吹終逃郭，性有真愚敢望回。", "雋老裁篇褒意重，遠分江漢濯餘埃。"]'),
('d257d93a-c039-4af5-918e-fe592e5b1fcf','坐池上看水偶成五絕句  其一','宋庠','宋','宋诗','song-poetry','','[]','冰解初分竇，波平便泛舟。',24,'全唐诗/poet.song.10000.json','["冰解初分竇，波平便泛舟。", "岸花紅弔影，沙鴨綠昂頭。"]'),
('cf16ccda-a54c-4ed8-b822-56694736d4ca','坐池上看水偶成五絕句  其二','宋庠','宋','宋诗','song-poetry','','[]','漾漾通仙穴，潺潺入故城。',24,'全唐诗/poet.song.10000.json','["漾漾通仙穴，潺潺入故城。", "晚來丘壑思，併爲一渠聲。"]'),
('1641f58e-5c59-4201-b58c-a78b02a9adde','坐池上看水偶成五絕句  其三','宋庠','宋','宋诗','song-poetry','','[]','短綠抽心草，深紅半面花。',24,'全唐诗/poet.song.10000.json','["短綠抽心草，深紅半面花。", "游魚知底事，跳碎水中霞。"]'),
