('41b94074-0f8d-4434-bafe-2eb174575fef','和參政丁侍郎洛下新置小園寄留臺張郎中詩三首  其一','宋庠','宋','宋诗','song-poetry','','[]','勤勤高意念林丘，新買溪園洛水頭。',32,'全唐诗/poet.song.10000.json','["勤勤高意念林丘，新買溪園洛水頭。", "千載聖賢方契會，恐君難作赤松游。"]'),
('36712608-c245-48ac-9234-b01287d9ea55','和參政丁侍郎洛下新置小園寄留臺張郎中詩三首  其二','宋庠','宋','宋诗','song-poetry','','[]','芝廛松塢富煙霞，更接西臺御史家。',32,'全唐诗/poet.song.10000.json','["芝廛松塢富煙霞，更接西臺御史家。", "借問賢人何日聚，定知郎宿映台華。"]'),
('0a1bf3bf-b270-4c5e-a2d3-8a9cec546ed2','逍搖堂五詠  其二','傅察','宋','宋诗','song-poetry','','[]','堂上春風至，欣欣草木情。',48,'全唐诗/poet.song.100000.json','["堂上春風至，欣欣草木情。", "鴉鳴藏柳暗，蝶舞映花明。", "暖日遲遲景，輕雷隱隱聲。", "客来何所有，采蕨試新烹。"]'),
('70cea2c6-1215-48e5-bc41-ce22a806d6d4','逍搖堂五詠  其三','傅察','宋','宋诗','song-poetry','','[]','堂上薰風至，陽曦午更驕。',48,'全唐诗/poet.song.100000.json','["堂上薰風至，陽曦午更驕。", "翫陰欣葉密，引飲快冰消。", "乳燕飛還墮，鳴蟬咽復調。", "清談能卻暑，應不費招邀。"]'),
('ba33f918-820e-426e-a7c7-680d4917924c','逍搖堂五詠  其四','傅察','宋','宋诗','song-poetry','','[]','堂上西風至，郊原歲事成。',48,'全唐诗/poet.song.100000.json','["堂上西風至，郊原歲事成。", "雨餘虹影落，雲霽露華清。", "唧唧蛩鳴夜，飄飄雁度晴。", "登臨多物色，筆落競縱橫。"]'),
('1f18341c-8a74-446b-9098-ff8aa16e5429','逍搖堂五詠  其五','傅察','宋','宋诗','song-poetry','','[]','堂上寒風至，蕭條静物華。',48,'全唐诗/poet.song.100000.json','["堂上寒風至，蕭條静物華。", "映窗唯有竹，倚檻更無花。", "碧瓦霜初重，銅壺日易斜。", "罇罍延夜永，不覺已朝霞。"]'),
('c141b245-ac83-41ae-beda-693b16249be1','吏隱亭會集','傅察','宋','宋诗','song-poetry','','[]','招攜共到習家池，雲水爲裳芰製衣。',64,'全唐诗/poet.song.100000.json','["招攜共到習家池，雲水爲裳芰製衣。", "魚戲輕舡浮枕簟，鷗随落日下汀磯。", "岸巾已得杯中趣，横吹如從天外飛。", "野性每来應未厭，驪駒寧復賦言歸。"]'),
('00daa4d6-f074-48f2-9891-073ae403b983','尉治吏隱亭二首  其一','傅察','宋','宋诗','song-poetry','','[]','公餘吏隱剏新亭，野闊雲低疊素屏。',64,'全唐诗/poet.song.100000.json','["公餘吏隱剏新亭，野闊雲低疊素屏。", "風動荷香翻偃蓋，日搖波影散疏星。", "望窮南畝千重綠，坐久西山數點青。", "更待晚凉蟬亂噪，與君散策試同聽。"]'),
('4e6219fa-59eb-4797-8835-01d384249424','尉治吏隱亭二首  其二','傅察','宋','宋诗','song-poetry','','[]','一番新雨洗華亭，四面晴天倚翠屏。',64,'全唐诗/poet.song.100000.json','["一番新雨洗華亭，四面晴天倚翠屏。", "並秀採蓮舒嫩臉，孤飛白鷺带殘星。", "披襟驟覺登仙樂，倚檻猶疑倒影青。", "横笛晚来聲更好，龍吟泓下亦時聽。"]'),
('ad4ec9ca-263e-4b03-961f-5cfb21571cf8','十五伯以詩見贈因次韻爲謝','傅察','宋','宋诗','song-poetry','','[]','蕭然顔巷復誰堪，竟日潛心到五三。',64,'全唐诗/poet.song.100000.json','["蕭然顔巷復誰堪，竟日潛心到五三。", "載酒未妨從靖節，圍棋端不羡羊曇。", "逢人傾倒群兒笑，落筆縱横四座慚。", "舊學青箱知未替，更将新律付諸男。"]'),
('74e7190a-4b64-46c1-add3-3763a45bc00c','次韻申泮宫直宿早秋四首  其一','傅察','宋','宋诗','song-poetry','','[]','新秋爽氣溢長空，弦誦低昻月映櫳。',64,'全唐诗/poet.song.100000.json','["新秋爽氣溢長空，弦誦低昻月映櫳。", "濟濟青衿成魯變，洋洋泮水詠洙風。", "群儒篆刻空章句，百氏紛紜賴折中。", "何日拔才空冀北，如今高譽滿山東。"]'),
('7a642554-bbd0-4863-8e72-3838207d7b96','次韻申泮宫直宿早秋四首  其二','傅察','宋','宋诗','song-poetry','','[]','皎皎清波滿四空，疏林散影弄朦朧。',64,'全唐诗/poet.song.100000.json','["皎皎清波滿四空，疏林散影弄朦朧。", "援毫欲賦陽臺夢，振袂欣乘玉宇風。", "已覺素秋来席上，卻疑仙景落壺中。", "凌雲未許攀仙桂，臥看冰輪沒漢東。"]'),
('137ba541-d10f-4067-a717-3cca48999267','次韻申泮宫直宿早秋四首  其三','傅察','宋','宋诗','song-poetry','','[]','一方明月落長空，萬里餘輝鏁玉櫳。',64,'全唐诗/poet.song.100000.json','["一方明月落長空，萬里餘輝鏁玉櫳。", "蟬韻啾啾来遠木，槐雲裊裊弄清風。", "共邀載酒陶彭澤，走訪談經戴侍中。", "景物蕭然無限思，靚粧應許過墻東。"]'),
('bef3fc3f-5a74-4ec6-b0b5-c86f0e4de46a','次韻申泮宫直宿早秋四首  其四','傅察','宋','宋诗','song-poetry','','[]','泮宫深閉絳帷空，搖想佳人照綺櫳。',64,'全唐诗/poet.song.100000.json','["泮宫深閉絳帷空，搖想佳人照綺櫳。", "閑倚畫屏憐永夜，懶搖紈扇引凉風。", "直疑令史歸天上，猶想陽臺入夢中。", "展轉覺来無一事，日搖槐影桂窗東。"]'),
('2b49597c-212d-4b49-95dc-00f74e89c41c','又次申教授直宿三首  其一','傅察','宋','宋诗','song-poetry','','[]','皎皎虚堂带月清，金風入律露華明。',64,'全唐诗/poet.song.100000.json','["皎皎虚堂带月清，金風入律露華明。", "潘郎寓直生秋興，韓子長歌憶短檠。", "驚鵲遶枝巢未稳，幽蟲尋砌隱餘聲。", "卻嫌詩思撩歸夢，数盡髙城長短更。"]'),
('52431778-1f68-422b-bec8-f36dfef19bd1','又次申教授直宿三首  其二','傅察','宋','宋诗','song-poetry','','[]','擾擾浮名絆此身，相逢樽酒眼還明。',64,'全唐诗/poet.song.100000.json','["擾擾浮名絆此身，相逢樽酒眼還明。", "君如俊鶻方摶翮，我似彎弓不受檠。", "弱植幸容依玉樹，新詩嘗喜擲金聲。", "他時會致青雲上，莫厭卑棲歲屡更。"]'),
('b92be818-a867-4bc4-852f-fb244cba6f1b','又次申教授直宿三首  其三','傅察','宋','宋诗','song-poetry','','[]','秋堂襆被有餘清，驟喜秋光潑眼明。',64,'全唐诗/poet.song.100000.json','["秋堂襆被有餘清，驟喜秋光潑眼明。", "簾外月華篩碎玉，牀頭螢火當長檠。", "直嫌唧唧秋蟲響，且聽琅琅弦誦聲。", "善教尙煩留滯席，朝恩未許便歸更。"]'),
('67bd1769-15e0-4a05-bfeb-f6495466c2a6','同工曹至臨洛道中禾黍蔚然喜而作呈朱令','傅察','宋','宋诗','song-poetry','','[]','甘雨初匀歲事時，冥冥造物本無私。',64,'全唐诗/poet.song.100000.json','["甘雨初匀歲事時，冥冥造物本無私。", "綠雲捲地薰風細，翠浪翻天曉露滋。", "已見郊原深沒馬，預欣場圃積如坻。", "從来令尹憂民切，短句聊憑一解頥。"]'),
('fa77bc1d-b1a7-4ba4-ba48-bbf157e28fa1','方量牧地次韻工曹王亞叟','傅察','宋','宋诗','song-poetry','','[]','朝廷庶事備成康，郡邑承風底事忙。',64,'全唐诗/poet.song.100000.json','["朝廷庶事備成康，郡邑承風底事忙。", "要使幅員無曠土，始知冀北有留良。", "疏狂似我徒勞耳，術業如君詎易量。", "奔走幸容陪笑語，每觀醉墨屡琳琅。"]'),
('c77575f2-95cc-4eef-ae26-ab48b1c19afa','杜無逸留别次韻三首  其一','傅察','宋','宋诗','song-poetry','','[]','薰蒸和氣浹豐年，羸老欣聞詔令宣。',64,'全唐诗/poet.song.100000.json','["薰蒸和氣浹豐年，羸老欣聞詔令宣。", "疾惡如讎知勁節，清言有味樂推賢。", "卻嫌松菊荒三徑，故乞絲綸下九天。", "欲識邦人思厚德，四郊草木亦依然。"]'),
('0aab0a48-b3b4-409a-bee8-96e0b1041295','杜無逸留别次韻三首  其二','傅察','宋','宋诗','song-poetry','','[]','汪汪萬頃浸清波，千里旁漸惠澤多。',64,'全唐诗/poet.song.100000.json','["汪汪萬頃浸清波，千里旁漸惠澤多。", "化比宋均方渡虎，瑞同黄霸自生禾。", "盤根治劇觀游刃，破膽投姦去宿疴。", "已有謳吟喧井邑，更傳佳句似陰何。"]'),
('834fe9f8-2268-4ec7-bc7a-03b530d25f98','杜無逸留别次韻三首  其三','傅察','宋','宋诗','song-poetry','','[]','一官塞北似飄蓬，邂逅威嚴霽弱翁。',32,'全唐诗/poet.song.100000.json','["一官塞北似飄蓬，邂逅威嚴霽弱翁。", "它日若陪林下客，亦能把釣待秋風。"]'),
('bad1577d-78b6-4971-ba06-91c4067cfc36','無逸用前韻見謝復次韻三首  其一','傅察','宋','宋诗','song-poetry','','[]','藉藉聲名自妙年，優優惠化詠来宣。',64,'全唐诗/poet.song.100000.json','["藉藉聲名自妙年，優優惠化詠来宣。", "寧誇衣錦光前牒，便擬揮金繼昔賢。", "秀句屢同歌白雪，髙標猶幸視青天。", "自慚不得陪騶御，空想餘風尚凛然。"]'),
('4b6205b2-7318-4896-ab25-3c9b5e41628b','無逸用前韻見謝復次韻三首  其二','傅察','宋','宋诗','song-poetry','','[]','一麾聊復散餘波，才比淮陰益辦多。',64,'全唐诗/poet.song.100000.json','["一麾聊復散餘波，才比淮陰益辦多。", "千里宣威憺夏日，三年種德斂秋禾。", "如綸忽聽頒新渥，勿藥還欣已舊疴。", "卻恐九重思治行，蒲輪它日竟如何。"]'),
('cc963850-aadc-4bc9-8c30-d9e27cb10a1d','無逸用前韻見謝復次韻三首  其三','傅察','宋','宋诗','song-poetry','','[]','鵬飛初不礙蒿蓬，自擬歸休慕仲翁。',32,'全唐诗/poet.song.100000.json','["鵬飛初不礙蒿蓬，自擬歸休慕仲翁。", "况有仙姿標洞府，泠然禦寇已乘風。"]'),
('5d5c28c2-219c-4d98-9f99-79742447a4fa','和鮑守次韻林德祖十四首  其一','傅察','宋','宋诗','song-poetry','','[]','南宫三日仕非輕，湖海歸来一草亭。',64,'全唐诗/poet.song.100000.json','["南宫三日仕非輕，湖海歸来一草亭。", "譽襲芝蘭方冉冉，節髙松柏獨青青。", "仁風已播袁宏扇，素尚行須毛玠屏。", "豈待朞年歸報政，人占此地有台星。"]'),
('461bd256-82f3-4b3f-87d9-5d83b050a897','和鮑守次韻林德祖十四首  其二','傅察','宋','宋诗','song-poetry','','[]','荘周蝴蝶夢魂輕，盤谷家山有舊亭。',64,'全唐诗/poet.song.100000.json','["荘周蝴蝶夢魂輕，盤谷家山有舊亭。", "下筆未能工嫓白，折腰何敢望紆青。", "思魚此日空彈鋏，誤墨他年點畫屏。", "寂寞草玄繩戶閉，猶堪歸伴少微星。"]'),
('4ee57c61-a6da-404f-a7a7-af5a814aa3d7','和鮑守次韻林德祖十四首  其三','傅察','宋','宋诗','song-poetry','','[]','五月黄塵去傳輕，褰裳幾處宿郵亭。',64,'全唐诗/poet.song.100000.json','["五月黄塵去傳輕，褰裳幾處宿郵亭。", "共知向日輸心赤，莫嘆微霜點鬢青。", "每傍重霄求寶劍，欲令新木作枯屏。", "流傳賸有風騷句，搖想群公若會星。"]'),
('b4906672-d6af-4fb1-8bcb-d4ad1b34dc55','和鮑守次韻林德祖十四首  其四','傅察','宋','宋诗','song-poetry','','[]','恩分千里賞猶輕，好建精思李柏亭。',64,'全唐诗/poet.song.100000.json','["恩分千里賞猶輕，好建精思李柏亭。", "日映冰壺融皎潔，風臨玉樹發葱青。", "高名競慕蒲葵扇，雅操寧施刻鏤屏。", "夢得惠連春草句，虚傳李白是金星。"]'),
('165b6170-8235-40a6-988a-c035a3e9a347','和鮑守次韻林德祖十四首  其五','傅察','宋','宋诗','song-poetry','','[]','氣蓋千人一羽輕，九霄丹鶴唳華亭。',64,'全唐诗/poet.song.100000.json','["氣蓋千人一羽輕，九霄丹鶴唳華亭。", "姓名已入金甌覆，留滯休嗟銀印青。", "彩筆掞天摛麗藻，高標插地見長屏。", "鹽梅他日從人望，商說何功比列星。"]'),
('121fc9c1-04b3-4c5c-8eb8-4b3b993b9ac7','和鮑守次韻林德祖十四首  其六','傅察','宋','宋诗','song-poetry','','[]','聖代勤民豈外輕，聲名今已播邊亭。',64,'全唐诗/poet.song.100000.json','["聖代勤民豈外輕，聲名今已播邊亭。", "風搖鈴閣終晨静，雨鏁棠陰滿地青。", "賜表殊功宜冕服，榮分從吏亦緹屏。", "如公學問留閑郡，東壁何人應二星。"]'),
('d0107cd2-467d-4ec9-aa94-e61e13a80f1a','和鮑守次韻林德祖十四首  其七','傅察','宋','宋诗','song-poetry','','[]','十年塵土坐才輕，五斗猶堪佐縣亭。',64,'全唐诗/poet.song.100000.json','["十年塵土坐才輕，五斗猶堪佐縣亭。", "鼎貴敢歆新綬紫，固窮唯有舊氈青。", "已甘終作輪囷木，未忍翻同屈曲屏。", "猶喜膺門被容接，常瞻郎位蔚然星。"]'),
('29f01416-d5c8-4fdd-84b4-6e9865fdbc90','和鮑守次韻林德祖十四首  其八','傅察','宋','宋诗','song-poetry','','[]','銀鈎落紙彩毫輕，醉寫新詩入禁亭。',64,'全唐诗/poet.song.100000.json','["銀鈎落紙彩毫輕，醉寫新詩入禁亭。", "學擅儒宗窮壼奥，文摛墨妙炳丹青。", "親承零露如金掌，密蔽衝風似寶屏。", "雅意未須嗟出守，宵衣方念庻民星。"]'),
('b5f81b69-3f9c-418e-b8e5-914948e3bfa8','和鮑守次韻林德祖十四首  其九','傅察','宋','宋诗','song-poetry','','[]','九萬鵬程舉翮輕，蚤年高譽滿江亭。',64,'全唐诗/poet.song.100000.json','["九萬鵬程舉翮輕，蚤年高譽滿江亭。", "曾分蘭省趨墀赤，行從荷囊拜瑣青。", "雅度最宜鏘玉佩，精忠不用綠沉屏。", "欲令行部襜帷去，要使人爭識景星。"]'),
('21edb607-b7a4-4350-b9d8-039e602d0521','和鮑守次韻林德祖十四首  其一○','傅察','宋','宋诗','song-poetry','','[]','久嗟留滯壓叢輕，桃李無言向野亭。',64,'全唐诗/poet.song.100000.json','["久嗟留滯壓叢輕，桃李無言向野亭。", "展驥始應流汗赤，登龍早見出藍青。", "三餘共對賢人酒，四野欣瞻别駕屏。", "何日蒲輪趨加節，便看兩兩映魁星。"]'),
('b95616e0-edc9-4254-a3a8-e03954520486','和鮑守次韻林德祖十四首  其一一','傅察','宋','宋诗','song-poetry','','[]','半刺同流寄未輕，勤勞每念離鄉亭。',64,'全唐诗/poet.song.100000.json','["半刺同流寄未輕，勤勞每念離鄉亭。", "髙懷不羡貂蟬貴，麗句還酬玉案青。", "字買千金休擇筆，才兼三絕好書屏。", "獨慚後學波瀾狹，明月舒空映小星。"]'),
('e54c4a59-25d8-481b-bd4e-22692210e3b0','和鮑守次韻林德祖十四首  其一二','傅察','宋','宋诗','song-poetry','','[]','淮陰當日少年輕，官舍渾如寄旅亭。',64,'全唐诗/poet.song.100000.json','["淮陰當日少年輕，官舍渾如寄旅亭。", "十載凄凉甘組綠，三冬諷誦伴燈青。", "才非徐孺慚懸榻，諂異陳咸豈觸屏。", "獨幸親逢陶謝手，每觀一字並華星。"]'),
('531c516d-1d87-4046-a15a-3b4d847642f9','和鮑守次韻林德祖十四首  其一三','傅察','宋','宋诗','song-poetry','','[]','佐縣三年敢意輕，掾曹還許暫平亭。',64,'全唐诗/poet.song.100000.json','["佐縣三年敢意輕，掾曹還許暫平亭。", "齒延屡醉爭扶白，嗣響非工愧取青。", "自此浮鷗容海浪，幸同馴鹿傍車屏。", "從今已恐終更去，悵望參商是别星。"]'),
('6a63a71a-c95b-41ca-9d30-78d8780e6ea6','和鮑守次韻林德祖十四首  其一四','傅察','宋','宋诗','song-poetry','','[]','使軺問俗畫輪輕，五馬張筵駐驛亭。',64,'全唐诗/poet.song.100000.json','["使軺問俗畫輪輕，五馬張筵駐驛亭。", "他日恩榮封詔紫，佇看蹇諤伏蒲青。", "才能並賜龍文劍，勳業同分雲母屏。", "太史已書賢者聚，荀陳此地仰華星。"]'),
('85e22d53-3190-4a84-a41d-b498d7712c1f','七月二十五登舟','傅察','宋','宋诗','song-poetry','','[]','暫来征騎出闍闉，卻棹扁舟下小津。',64,'全唐诗/poet.song.100000.json','["暫来征騎出闍闉，卻棹扁舟下小津。", "颯颯西風如送客，蕭蕭晚雨欲留人。", "一年蹤跡無停日，千里羈遊又遠親。", "爲問篙師從此去，定知幾日到東秦。"]'),
('3f56e13e-cfa9-4068-9d8a-76f8128a12fc','野宿','傅察','宋','宋诗','song-poetry','','[]','泝水秋風揚短棹，穿林落日繫孤舟。',64,'全唐诗/poet.song.100000.json','["泝水秋風揚短棹，穿林落日繫孤舟。", "心清乍喜離囂俗，野曠翻疑動旅愁。", "歸雁高飛雲杳杳，幽蟲夜語草悠悠。", "此間景物君知否，即是瀟湘一片秋。"]'),
('ea6c72ba-bbb2-4d68-9297-c6f33cf47631','晚發','傅察','宋','宋诗','song-poetry','','[]','理棹頻看溪水分，岸移不覺轉孤村。',64,'全唐诗/poet.song.100000.json','["理棹頻看溪水分，岸移不覺轉孤村。", "漁翁醉臥灘沙穏，樵子行歌岸草昏。", "白鷺成行低欲落，清蟬無数斷還聞。", "自将野色幷秋色，都付詩魂與醉魂。"]'),
('85dce5ad-ba0c-476c-a249-5c714b40ac1e','過濼次衡元度韻','傅察','宋','宋诗','song-poetry','','[]','山雲漠漠水溟溟，千里拏舟似葉輕。',64,'全唐诗/poet.song.100000.json','["山雲漠漠水溟溟，千里拏舟似葉輕。", "乍喜晚光偏照耀，卻嫌秋色太分明。", "疑人鷗鳥看来熟，殢客荷花望處平。", "佳景直須乘興入，蚤催風伯送吾行。"]'),
('5297acba-639a-48ea-a510-d8181facbb80','再阻風次衡元度韻','傅察','宋','宋诗','song-poetry','','[]','阻風三日不舂粮，浪逆篙横未到莊。',64,'全唐诗/poet.song.100000.json','["阻風三日不舂粮，浪逆篙横未到莊。", "碧水賴知饒夜月，青山已復下殘陽。", "每吟秋興空多淚，欲賦西征細作行。", "行止定非臧氏力，艱難險阻自須嘗。"]'),
('7de3f9d3-a1ea-4aa5-96bb-212fd88c4ca9','次韻烹茶四首  其一','傅察','宋','宋诗','song-poetry','','[]','移種疑從紫府仙，世間凡草護芊眠。',64,'全唐诗/poet.song.100000.json','["移種疑從紫府仙，世間凡草護芊眠。", "味高石蜜甘居下，效捷靈芝愧在前。", "玉𩊓並標官焙印，月團猶带御爐烟。", "年来海宇皆知愧，卻笑神農未解煎。"]'),
('bd83e0f3-5b35-4d4b-b503-e7c865727ffe','次韻烹茶四首  其二','傅察','宋','宋诗','song-poetry','','[]','吏隱從人號懶仙，一甌常及日高眠。',64,'全唐诗/poet.song.100000.json','["吏隱從人號懶仙，一甌常及日高眠。", "要令萬卷澆胸次，便覺三山到眼前。", "客至不須樽有酒，家貧肯厭突無烟。", "清泉近在南山麓，珍味殊勝渭水煎。"]'),
('fffebe2f-b7ff-41a4-adf1-07975095a949','次韻烹茶四首  其三','傅察','宋','宋诗','song-poetry','','[]','不但蠲煩起醉仙，能令古莽失多眠。',64,'全唐诗/poet.song.100000.json','["不但蠲煩起醉仙，能令古莽失多眠。", "春風乍拂千巖上，曉雨初沾百草前。", "絳縷縫囊包紫璧，玉塵凝盌照清烟。", "今人嗤點前人拙，未肯須依古法煎。"]'),
('0d8fe391-40b6-4781-a06b-8626161dda32','次韻烹茶四首  其四','傅察','宋','宋诗','song-poetry','','[]','仰望群公若會仙，貪論茗飲未安眠。',64,'全唐诗/poet.song.100000.json','["仰望群公若會仙，貪論茗飲未安眠。", "冥搜往往遊塵外，得句時時在枕前。", "夜漏謳吟清徹骨，晴窗揮染净無烟。", "中秋風月佳辰近，應把雲腴對竹煎。"]'),
('30a6a410-790e-4fee-a416-ef7e137f6f2f','槐堂二首  其一','傅察','宋','宋诗','song-poetry','','[]','殷勤當日植文槐，志在經綸世豈知。',64,'全唐诗/poet.song.100000.json','["殷勤當日植文槐，志在經綸世豈知。", "古柏空傳武侯廟，甘裳爭誦召公詩。", "頽顔共惜成陳迹，厦屋初欣敞舊規。", "豈但一時追盛事，髙名從此看雙垂。"]'),
('5f63077b-5edb-4c12-98cd-2f25fa444eb2','槐堂二首  其二','傅察','宋','宋诗','song-poetry','','[]','鬰鬰庭柯已百年，相傳勿翦豈徒然。',64,'全唐诗/poet.song.100000.json','["鬰鬰庭柯已百年，相傳勿翦豈徒然。", "曾棲鸞鳳枝條聳，直傍雲霄雨露偏。", "彩制乍驚增昔構，佳名還喜契台躔。", "故知異日思遺愛，爭指新堂說二賢。"]'),
('5d050a3d-fedc-45ab-85cc-bc93cdbfca2f','李良寵示牡丹長句謹賦三首  其一','傅察','宋','宋诗','song-poetry','','[]','一見奇葩潑眼明，兩川風物寄爭新。',64,'全唐诗/poet.song.100000.json','["一見奇葩潑眼明，兩川風物寄爭新。", "十家京洛供長日，萬朵東秦照暮春。", "諦視尚疑傾國女，醉吟猶付謫仙人。", "定知不是無情物，爲有真香暗度頻。"]'),
('48ec1cb0-6a0c-4c29-abfa-e64b9bbba41b','李良寵示牡丹長句謹賦三首  其二','傅察','宋','宋诗','song-poetry','','[]','紫檀刻蘂香初吐，紅粉匀葩色正新。',64,'全唐诗/poet.song.100000.json','["紫檀刻蘂香初吐，紅粉匀葩色正新。", "孤艷最宜微带雨，衆芳誰復與爭春。", "無端應恨風驚葉，不醉卻宜花笑人。", "從此徑須連夜賞，遶闌百匝未爲頻。"]'),
('78952c58-83fc-4509-89bb-bcb08dfe4556','李良寵示牡丹長句謹賦三首  其三','傅察','宋','宋诗','song-poetry','','[]','如酥小雨壓芳塵，曲檻重来花更新。',64,'全唐诗/poet.song.100000.json','["如酥小雨壓芳塵，曲檻重来花更新。", "莫怪東風鍾異美，獨将仙種殿餘春。", "愧非阿母池邉客，喜見陽臺夢裏人。", "猶恨此生輸蛺蝶，偷香抱蕊往来頻。"]'),
('bd717c56-e4d2-4b41-8c74-7d0c91f809ac','題毛彦謨容膝軒','傅察','宋','宋诗','song-poetry','','[]','蓴菜鱸魚意未疏，歸来端爲憶吾廬。',64,'全唐诗/poet.song.100000.json','["蓴菜鱸魚意未疏，歸来端爲憶吾廬。", "縱談袞袞皆忘倦，豪氣飄飄尚不除。", "賴有一經如長孺，休嫌四壁似相如。", "小窗宴坐無餘事，門外頻聽長者車。"]'),
('4ce1982c-45af-49ca-a515-8cdbaf96413a','次毛彦謨韻','傅察','宋','宋诗','song-poetry','','[]','平生貴異不謀身，率道恂恂范伯孫。',64,'全唐诗/poet.song.100000.json','["平生貴異不謀身，率道恂恂范伯孫。", "巷有青衿来問道，家無赤腳可應門。", "抗章曾叩蒼龍闕，讜議終開白獸罇。", "見說晚聞多妙教，悠悠浮世更堪論。"]'),
('8c013ea3-27d5-4389-bf45-e241e21d4208','南溪會集二首  其一','傅察','宋','宋诗','song-poetry','','[]','傳聞公退集群英，共惜殘春到野亭。',64,'全唐诗/poet.song.100000.json','["傳聞公退集群英，共惜殘春到野亭。", "髙柳半天成翠幄，搖峰插地作長屏。", "應憐曠寂囂塵絕，更覺蕭疏物象泠。", "顧我阻陪車馬客，空吟河畔草青青。"]'),
('c7a1766c-fcd3-4ce2-8e22-2a2a6c44a6c2','南溪會集二首  其二','傅察','宋','宋诗','song-poetry','','[]','淡蕩春溪带晚城，勝遊此地繼蘭亭。',64,'全唐诗/poet.song.100000.json','["淡蕩春溪带晚城，勝遊此地繼蘭亭。", "風搖波面琉璃簟，雨洗山光翡翠屏。", "舉酒莫辭歸酩酊，垂綸聊復向清泠。", "曾須踏月重追賞，要看林烟共罩青。"]'),
('bbc5ed5f-a4bc-4421-b9c4-c2192f75c9ff','次韻任伯仲均父詩和唐英之什','傅察','宋','宋诗','song-poetry','','[]','数子聲華久絕塵，更将詩律闘清新。',64,'全唐诗/poet.song.100000.json','["数子聲華久絕塵，更将詩律闘清新。", "爛如曉日鋪紅錦，穆若薰風泛綠蘋。", "王謝由来多大手，何劉那得比斯人。", "從今海內傳流徧，在處常應護鬼神。"]'),
('3aa97284-4701-4c82-834d-a4a74b1ff18a','九日次韻邢子友','傅察','宋','宋诗','song-poetry','','[]','側身西望涕沾翰，黄菊丹茰又滿闌。',64,'全唐诗/poet.song.100000.json','["側身西望涕沾翰，黄菊丹茰又滿闌。", "徧插定應憐我遠，從遊誰復盡親歡。", "年過騎省悲秋易，貧似司空乞酒難。", "何日故園鳴雁侣，醉歸松竹挂衣冠。"]'),
('1e1c6266-3ee6-4c92-a1eb-e700300b494d','贈毛彦謨二首  其一','傅察','宋','宋诗','song-poetry','','[]','相逢晚歲莫情疏，徑欲連墻卜並居。',64,'全唐诗/poet.song.100000.json','["相逢晚歲莫情疏，徑欲連墻卜並居。", "苦學羡君詩有味，固窮憐我食無餘。", "從容杯酒頻揮麈，斗藪塵埃喜振裾。", "聞道談言過輔嗣，故應回首萬浮虚。"]'),
('08430510-d21a-4a38-bb73-d9cf5a9a54fb','贈毛彦謨二首  其二','傅察','宋','宋诗','song-poetry','','[]','歎息朝廷記憶疏，未聞平子賦閑居。',64,'全唐诗/poet.song.100000.json','["歎息朝廷記憶疏，未聞平子賦閑居。", "窮經豈但論糟粕，樂道寧能逐腐餘。", "已覺烟霞親几杖，不教塵土汙簪裾。", "客来強起談名理，寂寞茅齋盡日虚。"]'),
('8550d0db-4147-480b-95d5-5914e64f34ff','馬上作','傅察','宋','宋诗','song-poetry','','[]','心逐輕波去，身随匹馬歸。',24,'全唐诗/poet.song.100000.json','["心逐輕波去，身随匹馬歸。", "據鞍揮淚盡，回首一依依。"]'),
('f6393df5-82ee-46c9-bf7f-64623c7595a0','夢覺','傅察','宋','宋诗','song-poetry','','[]','日永不可過，夜凉愁更多。',24,'全唐诗/poet.song.100000.json','["日永不可過，夜凉愁更多。", "蟬聲嘶晚月，孤枕夢如何。"]'),
('0a6c3760-e9b2-4e3d-83e8-d774e0ba6b53','思家','傅察','宋','宋诗','song-poetry','','[]','一别遽如許，歸期可奈何。',24,'全唐诗/poet.song.100000.json','["一别遽如許，歸期可奈何。", "無心戀明月，有淚寄流波。"]'),
('4d42187e-b727-4cf9-955d-218cd037248a','七月十一日夜凉風驟至即事書懷三絕句  其一','傅察','宋','宋诗','song-poetry','','[]','凉飈此夕何佳哉，萬里朱炎去不来。',32,'全唐诗/poet.song.100000.json','["凉飈此夕何佳哉，萬里朱炎去不来。", "吹入離人多少恨，卻将魂夢到陽臺。"]'),
('1b63eeb8-3943-427d-9219-fc016fd18abc','七月十一日夜凉風驟至即事書懷三絕句  其二','傅察','宋','宋诗','song-poetry','','[]','蕭蕭初覺澹雲輕，颯颯如聞轉樹聲。',32,'全唐诗/poet.song.100000.json','["蕭蕭初覺澹雲輕，颯颯如聞轉樹聲。", "收拾光輝渾在眼，應知騎省賦初成。"]'),
('48885c21-a164-4038-b5ea-3a0376a3377c','七月十一日夜凉風驟至即事書懷三絕句  其三','傅察','宋','宋诗','song-poetry','','[]','窗外時聞一葉落，槐陰驚起幾蟬鳴。',32,'全唐诗/poet.song.100000.json','["窗外時聞一葉落，槐陰驚起幾蟬鳴。", "秋風定是多情物，解作離腸欲斷聲。"]'),
('c7461091-a50b-40ee-9bae-74eb7fbe076b','七月十六夜對月','傅察','宋','宋诗','song-poetry','','[]','雲捲天高鳥鵲飛，滿庭槐影轉風枝。',32,'全唐诗/poet.song.100000.json','["雲捲天高鳥鵲飛，滿庭槐影轉風枝。", "可憐秋色誰分付，正是安仁作賦時。"]'),
('9eac8e91-71c4-4cd5-9e08-f81e76819244','牡丹三首  其一','傅察','宋','宋诗','song-poetry','','[]','侍中宅畔千餘朵，興慶池邊四五枝。',32,'全唐诗/poet.song.100000.json','["侍中宅畔千餘朵，興慶池邊四五枝。", "何似城南王處士，滿園無数鬬新奇。"]'),
('6a4538d7-135e-4c3c-94bf-0e5baa6bd7d0','牡丹三首  其二','傅察','宋','宋诗','song-poetry','','[]','無奈狂風日日催，東君欲去復徘徊。',32,'全唐诗/poet.song.100000.json','["無奈狂風日日催，東君欲去復徘徊。", "應緣衆卉羞相並，故遣妖姿最後開。"]'),
('0cf9eea5-a8e6-4b99-88a1-de7da219e7b0','牡丹三首  其三','傅察','宋','宋诗','song-poetry','','[]','半醉西施暈曉粧，天香一夜染衣裳。',32,'全唐诗/poet.song.100000.json','["半醉西施暈曉粧，天香一夜染衣裳。", "躊蹰欲畫無窮意，筆法何人繼趙昌。"]'),
('f5450abb-1051-426d-91de-52e9e767d24c','聞有游蔡氏園看牡丹詩戲作一絕呈季長','傅察','宋','宋诗','song-poetry','','[]','車騎雍容駐道傍，小園尋勝見花王。',32,'全唐诗/poet.song.100000.json','["車騎雍容駐道傍，小園尋勝見花王。", "應知異日傳佳句，處處人稱黄四娘。"]'),
('9aa94ba9-0b29-46ce-b6a5-b3a7c66520c9','海棠二首  其一','傅察','宋','宋诗','song-poetry','','[]','恰恰清明昨夜過，海棠幽獨占春多。',32,'全唐诗/poet.song.100000.json','["恰恰清明昨夜過，海棠幽獨占春多。", "杜陵不是無心賦，才薄難工奈若何。"]'),
('b17d65e3-a35c-4be1-9157-fa6782ad3e29','海棠二首  其二','傅察','宋','宋诗','song-poetry','','[]','欲識東君用意工，故将殘葉襯輕紅。',32,'全唐诗/poet.song.100000.json','["欲識東君用意工，故将殘葉襯輕紅。", "可憐雨洗胭脂濕，只怕風吹翠幄空。"]'),
('edbaf3ef-0f65-4de1-bf2e-831747ec254e','天寧節前筵口號','傅察','宋','宋诗','song-poetry','','[]','天扶寶運世興王，慶陋猗蘭入畫堂。',64,'全唐诗/poet.song.100000.json','["天扶寶運世興王，慶陋猗蘭入畫堂。", "千載後觀周禮樂，萬邦搖奉舜衣裳。", "北門驕子常輸賮，南極老人方效祥。", "試向紅雲瞻魏闕，侍臣應上萬年觴。"]'),
('eb72f0c1-271b-4a2c-bfba-6c03e2cbc0ae','天寧節後筵口號','傅察','宋','宋诗','song-poetry','','[]','流虹啓聖際千年，湛露洪恩下九天。',64,'全唐诗/poet.song.100000.json','["流虹啓聖際千年，湛露洪恩下九天。", "騰踏歡聲來擊壤，氤氳瑞色散非煙。", "已賡聖代中和頌，更草前賢封禪篇。", "四海豈知蒙帝力，春臺此日倍熙然。"]'),
('032a274f-3b14-4b2d-9780-bc3e6c961fb5','天寧節馬前口號','傅察','宋','宋诗','song-poetry','','[]','千秋從昔慶嘉名，四海而今賀太平。',64,'全唐诗/poet.song.100000.json','["千秋從昔慶嘉名，四海而今賀太平。", "十里旌旗明曉色，萬家弦管被新聲。", "五雲已逐陽烏現，百獸方隨儀鳯鳴。", "更喜簪紳趨燕衎，南山祝聖願同傾。"]'),
('2b147c84-8d7b-4ed7-9e2c-d42c1ec9544f','送杜守口號','傅察','宋','宋诗','song-poetry','','[]','九重丹詔錫恩榮，嫋嫋秋風卷旆旌。',64,'全唐诗/poet.song.100000.json','["九重丹詔錫恩榮，嫋嫋秋風卷旆旌。", "藉甚搢紳争頌德，爛然衣錦得徐行。", "一錢選受群翁送，三徑歸來萬事輕。", "宣室異時思賈傅，蒲輪應復召枚生。"]'),
('a27f30d2-b998-465c-a405-ed57cf53b6cb','虞憲按樂致語','傅察','宋','宋诗','song-poetry','','[]','熙然伏運慶當千，初見簫韶被管弦。',64,'全唐诗/poet.song.100000.json','["熙然伏運慶當千，初見簫韶被管弦。", "況際軺車臨樂國，更張綺席會群仙。", "歡聲已逐鏗鏘奏，和氣方隨律呂宣。", "何日九重頒召節，好從鵷鷺聽鈞天。"]'),
('d6903ee7-f67b-4be8-b1f7-4aa880b6d92a','傅倅請杜守樂語','傅察','宋','宋诗','song-poetry','','[]','清時樂事昔難逢，曦御初移晝景融。',64,'全唐诗/poet.song.100000.json','["清時樂事昔難逢，曦御初移晝景融。", "麥秀兩岐翻翠浪，槐陰四面舞輕風。", "揮餘玉塵談無倦，醉倒金罍酒屢空。", "髣髴已聞頒鳯詔，朝來喜氣滿城中。"]'),
('2b17efbe-f864-4e34-a514-c0d2a52d92fa','毛彦謨以其弟彦周出殯見索挽詞謹賦一首','傅察','宋','宋诗','song-poetry','','[]','十年鄉校嘆蹉跎，一日皇恩盡網羅。',64,'全唐诗/poet.song.100000.json','["十年鄉校嘆蹉跎，一日皇恩盡網羅。", "别去謂宜登上第，歸來還復遇沉痾。", "秋風但結原鴒恨，曉露空聞蒿里歌。", "榮願未酬身已殁，平生稽古竟如何。"]'),
('e545d8cd-b78d-4a37-a021-e79cfbf8e1f4','挽詞二首  其一','傅察','宋','宋诗','song-poetry','','[]','仙李遺風遠，髙門積慶長。',48,'全唐诗/poet.song.100000.json','["仙李遺風遠，髙門積慶長。", "及身儀禁路，有子耀巖廊。", "不及千鍾樂，應留八葉昌。", "凄凉封蜜印，髣髴映金章。"]'),
('e0d3edfd-a8b6-499e-bb56-73707bc8e070','挽詞二首  其二','傅察','宋','宋诗','song-poetry','','[]','故里尊疏傅，群公慶孟侯。',48,'全唐诗/poet.song.100000.json','["故里尊疏傅，群公慶孟侯。", "方歆五福備，遽隔九原幽。", "歎息人何贖，褒榮禮獨優。", "翻疑脱仙骨，名字照丹丘。"]'),
('56389437-5a5e-4e81-9581-5b505d56113a','又挽詞三首  其一','傅察','宋','宋诗','song-poetry','','[]','蕭葉蟠根大，于門結駟新。',48,'全唐诗/poet.song.100000.json','["蕭葉蟠根大，于門結駟新。", "鵷行尊几杖，鶴骨離風塵。", "追挽傾朝紱，褒榮動帝宸。", "惟應兩河道，猶想錦衣春。"]'),
('d8cfdf10-6394-4669-ac75-999a4ac0851a','又挽詞三首  其二','傅察','宋','宋诗','song-poetry','','[]','遺子一經足，成家五福幷。',48,'全唐诗/poet.song.100000.json','["遺子一經足，成家五福幷。", "千鍾欣祿養，萬石仰榮名。", "日射銘旌字，風傳袞鐸聲。", "搖知開吉地，不假問三生。"]'),
('1ce67365-1775-4963-97ea-78410ab2f52b','又挽詞三首  其三','傅察','宋','宋诗','song-poetry','','[]','榆社聆風遠，蘭階托契深。',48,'全唐诗/poet.song.100000.json','["榆社聆風遠，蘭階托契深。", "興宗知有自，處貴獨無心。", "隴柏晞朝露，庭槐長夏陰。", "如公更何恨，顧我尚沾襟。"]'),
('48bcca65-8f44-4fb2-8e26-b755f841486d','次韻謝文驥主簿見寄兼示劉宣叔','陳與義','宋','宋诗','song-poetry','','[]','斷蓬隨天風，飄蕩去何許。',192,'全唐诗/poet.song.100000.json','["斷蓬隨天風，飄蕩去何許。", "寒草不自振，生死依牆堵。", "兩途俱寂寞，衆手劇雲雨。", "坐令習主簿，下與雞鶩伍。", "遥知竹林交，未肯一時數。", "翩翩三語掾，智與謾相補。", "髯劉吾所畏，道屈空去魯。", "子才亦落落，傾蓋極許予。", "四夔照河濱，一笑寬逆旅。", "堂堂吾景方，去作泉下土。", "未知我露電，能復幾寒暑。", "思蒓久未决，食薺轉覺苦。", "我不逮諸子，要先諸子去。", "不種楊惲田，但灌呂安圃。", "未知誰善釀，可作孔文舉。", "十年亦晚矣，請便事斯語。"]'),
('4d9f86b5-4a12-4f1b-b254-a8a14c79193f','題劉路宣義風月堂','陳與義','宋','宋诗','song-poetry','','[]','長風將佳月，萬里到此堂。',96,'全唐诗/poet.song.100000.json','["長風將佳月，萬里到此堂。", "天遊本無待，邂逅今夕凉。", "北窗舊竹短，南窗新竹長。", "此君本無心，風月不相忘。", "道人方燕坐，萬物凝清光。", "不獨揖霜雪，似聞笙鶴翔。", "乃知一念靜，可洗千劫忙。", "明當携麯生，往問安心方。"]'),
('4c215231-7a4b-4c79-85a4-a0820f05a978','送呂欽問監酒受代歸','陳與義','宋','宋诗','song-poetry','','[]','以我千金帚，逢君萬斛船。',48,'全唐诗/poet.song.100000.json','["以我千金帚，逢君萬斛船。", "要知窮有自，未覺懶相先。", "盆盎三年夢，篇章四海傳。", "怱怱秣歸馬，離恨滿霜天。"]'),
('fa3b746d-558a-4015-8a5b-e8102b483227','次韻周教授秋懷','陳與義','宋','宋诗','song-poetry','','[]','一官不辦作生涯，幾見秋風捲岸沙。',64,'全唐诗/poet.song.100000.json','["一官不辦作生涯，幾見秋風捲岸沙。", "宋玉有文悲落木，陶潜無酒對黄花。", "天機衮衮山新瘦，世事悠悠日自斜。", "誤矣載書三十乘，東門何地不宜瓜。"]'),
('032b7ae3-f772-4932-98b5-feadf8b6f22a','次韻張矩臣迪功見示建除體','陳與義','宋','宋诗','song-poetry','','[]','建德我故國，歸哉遄我驅。',144,'全唐诗/poet.song.100000.json','["建德我故國，歸哉遄我驅。", "除道得歡伯，荆棘無復餘。", "滿懷秋月色，未覺饑腸虛。", "平林過西風，爲我起笙竽。", "定知張公子，能共寂寞娛。", "執此以贈君，意重貂襜褕。", "破帽與青鞋，耐久心亦舒。", "危處要進步，安處勿停車。", "成虧在道德，不在功利區。", "收視以爲期，問君此何如。", "開尊且復飲，辭費道已迂。", "閉口味更長，香斷窗櫺疏。"]'),
('45de2d5e-ec92-471f-8191-29904885e28e','八音歌  其一','陳與義','宋','宋诗','song-poetry','','[]','金張與許史，不知寒士名。',96,'全唐诗/poet.song.100000.json','["金張與許史，不知寒士名。", "石交少瑕疵，但有一麯生。", "絲色隨染异，擇交士所貴。", "竹林固皆賢，山王以官累。", "匏酌可延客，藜羹無是非。", "土思非不深，無屋未能歸。", "革華雖可侯，不敢踐危地。", "木奴會足飽，寬作十年計。"]'),
('3af85ffc-1d12-4936-936c-9bd8ded9f8d9','八音歌  其二','陳與義','宋','宋诗','song-poetry','','[]','金章笑鶉衣，玉堂陋茅茨。',96,'全唐诗/poet.song.100000.json','["金章笑鶉衣，玉堂陋茅茨。", "石火不須臾，白駒隙中馳。", "絲鬢那可避，會當來如期。", "竹固不如肉，飛觴莫辭速。", "匏竹且勿喧，聽我歌此曲。", "土花玩四時，未覺有榮辱。", "革木要一聲，好异乖人情。", "木公不可待，且復舉吾觥。"]'),
('0a3a0ced-3cdb-4e34-863a-c031956f45ef','題牧牛圖','陳與義','宋','宋诗','song-poetry','','[]','千里烟草綠，連山雨新足。',88,'全唐诗/poet.song.100000.json','["千里烟草綠，連山雨新足。", "老牛抱朝饑，向山影觳觫。", "犢兒狂走先過浦，却立長鳴待其母。", "母子爲人實倉廩，汝飽不慚人愧汝。", "牧童生來日日娛，只憂身大當把鉏。", "日斜睡足牛背上，不信人間有廣輿。"]'),
('61bc4717-1d75-4c1b-b76a-00b423145add','題易元吉畫麞','陳與義','宋','宋诗','song-poetry','','[]','紛紛騎馬塵及腹，名利之窟爭馳逐。',126,'全唐诗/poet.song.100000.json','["紛紛騎馬塵及腹，名利之窟爭馳逐。", "眼明見此山中吏，怪底吾廬有林谷。", "雌雄相對目炯炯，意閑不受榮與辱。", "掇皮皆真豈自知，坐令貓犬羞奴僕。", "我不是李衛公，欺爾無魂規爾肉。", "又不是曹將軍，數肋射爾不遺鏃。", "明窗無塵簾有香，與爾共此春日長。", "戲弄竹枝聊卒歲，不羨晉宮車下羊。"]'),
('6c3a88a3-9270-4f53-8342-3974d3c79696','題唐希雅畫寒江圖','陳與義','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','江頭雲黄天醞雪，樹枝慘慘凍欲折。',80,'全唐诗/poet.song.100000.json','["江頭雲黄天醞雪，樹枝慘慘凍欲折。", "耐寒野鴨不知歸，猶向沙邊弄羽衣。", "黄茅終日不自力，影亂弱藻相因依。", "惟有蒼石如卧虎，不受陰晴與寒暑。", "舟中過客莫敢侮，閑伴長江了今古。"]'),
('77b5ec21-5ec2-4ed8-b68e-b2ed78e32cb4','江南春','陳與義','宋','宋诗','song-poetry','','[]','雨後江上綠，客愁隨眼新。',56,'全唐诗/poet.song.100000.json','["雨後江上綠，客愁隨眼新。", "桃花十里影，摇蕩一江春。", "朝風迎船波浪惡，暮風送船無處泊。", "江南雖好不如歸，老薺遶牆人得肥。"]'),
('fc34efa2-a90e-4504-903e-1345820f3264','蠟梅','陳與義','宋','宋诗','song-poetry','','[]','智瓊額黄且勿誇，回眼視此風前葩。',98,'全唐诗/poet.song.100000.json','["智瓊額黄且勿誇，回眼視此風前葩。", "家家融蠟作杏蔕，歲歲逢梅是蠟花。", "世間真僞非兩法，映日細看真是蠟。", "我今嚼蠟已甘腴，况此有味蠟不如。", "只愁繁香欺定力，薰我欲醉須人扶。", "不辭花前醉倒卧經月，是酒是香君試別。"]'),
('8c1ef54a-bf60-47fc-80e1-30279880663f','次韻張元方春雪','陳與義','宋','宋诗','song-poetry','','[]','雲黄天爲低，窗白雪初作。',96,'全唐诗/poet.song.100000.json','["雲黄天爲低，窗白雪初作。", "幽人睡方覺，簾外舞萬鶴。", "斜斜既可人，整整亦不惡。", "不知來何暮，遂失梅花約。", "東風桃杏暖，不受珠璣絡。", "聊回萬斛潤，點點付藜藿。", "幽人無酒飲，一笑供酬酢。", "歲晚會復來，相期在丘壑。"]'),
('81549f83-7129-4e33-be8b-ce3d60a07361','舍弟踰日不知雪勢密因再賦','陳與義','宋','宋诗','song-poetry','','[]','密雪來催詩，似怪子不作。',96,'全唐诗/poet.song.100000.json','["密雪來催詩，似怪子不作。", "蔽天白漫漫，誰辨鷺與鶴。", "坐令天回笑，未受風作惡。", "急飛既繁麗，緩舞尤綽約。", "稍積草木上，斷縞莽聯絡。", "終然要白日，印彼葵與藿。", "滿眼豐歲意，空詩信難酢。", "慎勿辭典衣，已不慮填壑。"]'),
('066ed8df-2f80-4a95-a495-9c6aad2ab73b','雜書示陳國佐胡元茂四首  其一','陳與義','宋','宋诗','song-poetry','','["\u7ec8\u5357\u5c71"]','一官專爲口，俯仰汗我顔。',72,'全唐诗/poet.song.100000.json','["一官專爲口，俯仰汗我顔。", "顧將千日饑，換此三歲閑。", "冥冥雲表雁，時節自往還。", "不憂稻粱絕，憂在羅網間。", "絕勝杜拾遺，一飽常間關。", "晚知儒冠誤，猶戀終南山。"]'),
('fc394ab5-e5e8-4ae9-b1de-160167afec39','雜書示陳國佐胡元茂四首  其二','陳與義','宋','宋诗','song-poetry','','[]','杜門十日疾，因得觀妄身。',48,'全唐诗/poet.song.100000.json','["杜門十日疾，因得觀妄身。", "勿云千金軀，今視如埃塵。", "平生老赤脚，每見生怒嗔。", "揮汗煮我藥，見此愧其勤。"]'),
('3aea1c87-369a-42a6-b701-0152332deb5e','雜書示陳國佐胡元茂四首  其三','陳與義','宋','宋诗','song-poetry','','[]','巨源邦之棟，急士如拾珍。',72,'全唐诗/poet.song.100000.json','["巨源邦之棟，急士如拾珍。", "定知柳下鍛，遠勝崔史陳。", "絕交雖已隘，益見叔夜真。", "士要雖衣食，求仁今得仁。", "釋之與王生，盛美俱絕倫。", "吾評竹林詠，未可少若人。"]'),
('05954203-8e2e-42c3-99bc-7672e39e04b9','雜書示陳國佐胡元茂四首  其四','陳與義','宋','宋诗','song-poetry','','[]','昔吾同年友，壯志各南溟。',72,'全唐诗/poet.song.100000.json','["昔吾同年友，壯志各南溟。", "十年風雨過，見此落落星。", "秀者吾元茂，衆器見鼎鉶。", "許身稷契間，不但醉六經。", "時逢下車揖，慰我兩眼青。", "勿憂事不理，伯始在朝廷。"]'),
('316ed2b1-43f2-424f-adeb-ed37eb936903','書懷示友十首  其一','陳與義','宋','宋诗','song-poetry','','[]','俗子令我病，紛然來座隅。',84,'全唐诗/poet.song.100000.json','["俗子令我病，紛然來座隅。", "賢士費懷思，不受折簡呼。", "城東陳孟公，久闊今何如。", "明月照天下，此夕與君俱。", "不難十里勤，畏借東家驢。", "似聞有老眼，能作薦鶚書。", "功名勿念我，此心已掃除。"]'),
('aa5fd7eb-baf3-465a-b36d-704701825eb8','書懷示友十首  其二','陳與義','宋','宋诗','song-poetry','','[]','張子霜後鷹，眉骨非凡曹。',48,'全唐诗/poet.song.100000.json','["張子霜後鷹，眉骨非凡曹。", "不肯兄事錢，但欲僕命騷。", "胡爲隨我輩，碌碌著青袍。", "相逢車馬邊，伎癢不得搔。"]'),
('0dfa6a2a-1d31-4825-ae2e-a0c04d728fad','書懷示友十首  其三','陳與義','宋','宋诗','song-poetry','','[]','平生詩作祟，腸肚困藿食。',60,'全唐诗/poet.song.100000.json','["平生詩作祟，腸肚困藿食。", "使我忘隱憂，亦自得詩力。", "絕知是餘蔽，且復求今日。", "不如付杯酒，一笑萬事畢。", "毛穎僅升堂，麯生真入室。"]'),
('0bb7c636-7b83-400b-b9ac-54fd0cd0f956','書懷示友十首  其四','陳與義','宋','宋诗','song-poetry','','[]','我夢鍾鼎食，或作山林遊。',48,'全唐诗/poet.song.100000.json','["我夢鍾鼎食，或作山林遊。", "當其適意時，略與人間侔。", "覺來迹便掃，我已不悲憂。", "人間安可比，夢中無悔尤。"]'),
('b7e7a8e0-999c-40fd-994d-4a86ec53b345','書懷示友十首  其五','陳與義','宋','宋诗','song-poetry','','[]','我策三十六，第一當歸田。',48,'全唐诗/poet.song.100000.json','["我策三十六，第一當歸田。", "柴門種雜樹，婆娑樂餘年。", "是中三益友，不減二仲賢。", "柏樹解說法，桑葉能通禪。"]'),
('797c9c6b-5512-44cb-a052-4b39551582e6','書懷示友十首  其六','陳與義','宋','宋诗','song-poetry','','[]','有錢可使鬼，無錢鬼揶揄。',84,'全唐诗/poet.song.100000.json','["有錢可使鬼，無錢鬼揶揄。", "百年堂前燕，萬事屋上烏。", "微官不救饑，出處違壯圖。", "相牛豈無經，種樹亦有書。", "如何求二頃，歸卧淵明廬。", "曝背對青山，鳥鳴人意舒。", "試數門前客，終歲幾覆車。"]'),
('fbaed71f-4e4b-4d03-968d-826edd2aa3dc','書懷示友十首  其七','陳與義','宋','宋诗','song-poetry','','[]','仲舒老一經，策世非所長。',48,'全唐诗/poet.song.100000.json','["仲舒老一經，策世非所長。", "瓦鼎薦蔬食，但取充饑腸。", "偉哉賈生書，開闔有耿光。", "既珍亦可飽，舉俗不見嘗。"]'),
('a3a0ea01-e8eb-432a-b5ff-a5de163c3ce8','書懷示友十首  其八','陳與義','宋','宋诗','song-poetry','','[]','揚雄平生學，肝腎困雕鑴。',48,'全唐诗/poet.song.100000.json','["揚雄平生學，肝腎困雕鑴。", "晚於玄有得，始悔賦甘泉。", "使雄早大悟，亦何事於玄。", "賴有一言善，酒箴真可傳。"]'),
('7ded0b56-405a-415d-9c4e-50b7d4a4ede2','書懷示友十首  其九','陳與義','宋','宋诗','song-poetry','','[]','蕭蕭十月菊，耿耿照白草。',48,'全唐诗/poet.song.100000.json','["蕭蕭十月菊，耿耿照白草。", "開窗逢一笑，未覺徐娘老。", "風霜要飽更，獨立晚更好。", "韓公真躁人，顧用擾懷抱。"]'),
('3f920f6b-cc62-4851-8510-858ad0ce8dc4','書懷示友十首  其一○','陳與義','宋','宋诗','song-poetry','','[]','青青堂西竹，歲寒不緇磷。',48,'全唐诗/poet.song.100000.json','["青青堂西竹，歲寒不緇磷。", "蓬蒿衆小中，拭眼見長身。", "澹然冬日影，此處極可人。", "子猷幸見過，一洗聲色塵。"]'),
('108bba76-482e-4989-a371-f1b50f32e16d','風雨','陳與義','宋','宋诗','song-poetry','','[]','風雨破秋夕，梧葉窗前驚。',48,'全唐诗/poet.song.100000.json','["風雨破秋夕，梧葉窗前驚。", "不愁黄落近，滿意作秋聲。", "客子無定力，夢中波撼城。", "覺來俱不見，微月照殘更。"]'),
('e9d16976-a608-44aa-aac5-977d39407496','曼陀羅花','陳與義','宋','宋诗','song-poetry','','[]','我圃殊不俗，翠蕤敷玉房。',48,'全唐诗/poet.song.100000.json','["我圃殊不俗，翠蕤敷玉房。", "秋風不敢吹，謂是天上香。", "烟迷金錢夢，露醉木蕖粧。", "同時不同調，曉月照低昂。"]'),
('a456e913-7414-459e-be1e-9345110ed2eb','螢火','陳與義','宋','宋诗','song-poetry','','[]','翩翩飛蛾掩明燭，見烹膏油罪莫贖。',64,'全唐诗/poet.song.100000.json','["翩翩飛蛾掩明燭，見烹膏油罪莫贖。", "嘉爾螢火不自欺，草間相照光煜煜。", "却馬已錄仙人方，映書曾登君子堂。", "不畏月明見陋質，但畏風雨難爲光。"]'),
('60b5bcd6-ea63-4403-8600-f3026fc5ae7c','北風','陳與義','宋','宋诗','song-poetry','','[]','北風掠野悲歲暮，黄塵漲街人不度。',64,'全唐诗/poet.song.100000.json','["北風掠野悲歲暮，黄塵漲街人不度。", "孤鴻抱饑客千里，性命么微不當怒。", "梅花欲動天作難，蓬飛上天得盤桓。", "千里卧木枝葉盡，獨自人間不受寒。"]'),
('39d0b06b-b935-4f26-a679-a8ac55f24f3b','送張仲宗押戟歸閩中','陳與義','宋','宋诗','song-poetry','','[]','翩然鴻鵠本不群，亦復爲口長紛紛。',128,'全唐诗/poet.song.100000.json','["翩然鴻鵠本不群，亦復爲口長紛紛。", "去年弄影河北月，今年迎面江南雲。", "還家不比陶令冷，持節正效相如勤。", "青天白日映徒御，玄髮絳旆明江濆。", "舟前落花慰野老，浦口杜若愁湘君。", "遥知詩成寄驛使，萬里春色當見分。", "贈人以言予豈敢，不忍負子聊云云。", "舊山雖好慎勿過，恐有德璋能勒文。"]'),
('e4fbbc63-bab3-4a9c-aa92-c8d51d592442','襄邑道中','陳與義','宋','宋诗','song-poetry','','["\u7eaa\u884c", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u5b8b\u8bd7", "\u5199\u4e91"]','飛花兩岸照船紅，百里榆堤半日風。',32,'全唐诗/poet.song.100000.json','["飛花兩岸照船紅，百里榆堤半日風。", "卧看滿天雲不動，不知雲與我俱東。"]'),
('ec1c36ef-c4ea-4a59-aff7-856a8f15ea4f','寄新息家叔','陳與義','宋','宋诗','song-poetry','','[]','風雨淮西夢，危魂費九升。',48,'全唐诗/poet.song.100000.json','["風雨淮西夢，危魂費九升。", "一官遮日手，兩地讀書燈。", "見客深藏舌，吟詩不負丞。", "竹林雖有約，門戶要人興。"]'),
('05de1bc2-f169-4a5a-870a-3b556f2cec51','年華','陳與義','宋','宋诗','song-poetry','','[]','去國頻更歲，爲官不救饑。',48,'全唐诗/poet.song.100000.json','["去國頻更歲，爲官不救饑。", "春生殘雪外，酒盡落梅時。", "白日山川映，青天草木宜。", "年華不負客，一一入吾詩。"]'),
('eb3727bc-3028-46ea-beef-548104632caf','茅屋','陳與義','宋','宋诗','song-poetry','','[]','茅屋年年破，春風歲歲來。',48,'全唐诗/poet.song.100000.json','["茅屋年年破，春風歲歲來。", "寒從草根退，花值客愁開。", "時序添詩卷，乾坤進酒杯。", "片雲無思極，日暮却空迴。"]'),
('e816a561-45de-4488-8025-fc3deb14cf75','酴醾','陳與義','宋','宋诗','song-poetry','','[]','雨過無桃李，唯餘雪覆牆。',48,'全唐诗/poet.song.100000.json','["雨過無桃李，唯餘雪覆牆。", "青天映妙質，白日照繁香。", "影動春微透，花寒韻更長。", "風流到尊酒，猶足助詩狂。"]'),
('f155e7bd-565a-45c8-bbfa-2e7ed098c03f','雨','陳與義','宋','宋诗','song-poetry','','[]','蕭蕭十日雨，穩送祝融歸。',48,'全唐诗/poet.song.100000.json','["蕭蕭十日雨，穩送祝融歸。", "燕子經年夢，梧桐昨暮非。", "一凉恩到骨，四壁事多違。", "衮衮繁華地，西風吹客衣。"]'),
('0c1296c7-a99e-4cf7-bff0-f3b8cf2bbb99','西風','陳與義','宋','宋诗','song-poetry','','[]','木末西風起，中含萬里凉。',48,'全唐诗/poet.song.100000.json','["木末西風起，中含萬里凉。", "浮雲不愁思，盡日只飛揚。", "夢斷頭將白，詩成葉自黄。", "不關明主棄，本出涸陰鄉。"]'),
('ceed11f4-2d26-4d4c-a5a5-78a950d47071','題許道寧畫','陳與義','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','滿眼長江水，蒼然何郡山。',48,'全唐诗/poet.song.100000.json','["滿眼長江水，蒼然何郡山。", "向來萬里意，今在一窗間。", "衆木俱含晚，孤雲遂不還。", "此中有佳句，吟斷不相關。"]'),
('45560b90-6c23-4397-a748-a2fb097ce9a1','和張規臣水墨梅五絕  其一','陳與義','宋','宋诗','song-poetry','','[]','巧畫無鹽醜不除，此花風韻更清姝。',32,'全唐诗/poet.song.100000.json','["巧畫無鹽醜不除，此花風韻更清姝。", "從教變白能爲黑，桃李依然是僕奴。"]'),
('a14caea9-c447-4011-8e91-d4842e28236f','和張規臣水墨梅五絕  其二','陳與義','宋','宋诗','song-poetry','','[]','病見昏花已數年，只應梅蕊固依然。',32,'全唐诗/poet.song.100000.json','["病見昏花已數年，只應梅蕊固依然。", "誰教也作陳玄面，眼亂初逢未敢憐。"]'),
('bc9d32a8-e617-425f-ac54-19d4d0a76a4c','和張規臣水墨梅五絕  其三','陳與義','宋','宋诗','song-poetry','','[]','粲粲江南萬玉妃，別來幾度見春歸。',32,'全唐诗/poet.song.100000.json','["粲粲江南萬玉妃，別來幾度見春歸。", "相逢京洛渾依舊，唯恨緇塵染素衣。"]'),
('b8065e05-b229-4ff5-a0f5-9992b2cc071b','和張規臣水墨梅五絕  其四','陳與義','宋','宋诗','song-poetry','','[]','含章檐下春風面，造化功成秋兔毫。',32,'全唐诗/poet.song.100000.json','["含章檐下春風面，造化功成秋兔毫。", "意足不求顔色似，前身相馬九方皋。"]'),
('5540cdd6-b197-412f-ba0f-51b6be826ac8','和張規臣水墨梅五絕  其五','陳與義','宋','宋诗','song-poetry','','["\u897f\u6e56"]','自讀西湖處士詩，年年臨水看幽姿。',32,'全唐诗/poet.song.100000.json','["自讀西湖處士詩，年年臨水看幽姿。", "晴窗畫出橫斜影，絕勝前村夜雪時。"]'),
('722f5338-a4bf-424f-bdc4-9263abaa46f3','夜雨','陳與義','宋','宋诗','song-poetry','','[]','經歲柴門百事乖，此身只合卧蒼苔。',64,'全唐诗/poet.song.100000.json','["經歲柴門百事乖，此身只合卧蒼苔。", "蟬聲未足秋風起，木葉俱鳴夜雨來。", "棋局可觀浮世理，燈花應爲好詩開。", "獨無宋玉悲歌念，但喜新凉入酒杯。"]'),
('2c25a071-75fa-4fbf-b026-43e7a38f1134','連雨不能出有懷同年陳國佐','陳與義','宋','宋诗','song-poetry','','[]','雨師風伯不吾謀，漠漠窮陰斷送秋。',64,'全唐诗/poet.song.100000.json','["雨師風伯不吾謀，漠漠窮陰斷送秋。", "欲過蘇端泥浩蕩，定知高鳳麥漂流。", "檐前甘菊已無益，階下决明還可憂。", "安得如鴻六尺馬，暫時相對說新愁。"]'),
('cd37fa9c-268f-4f3d-9320-e8cd856d2b31','目疾','陳與義','宋','宋诗','song-poetry','','[]','天公嗔我眼常白，故著昏花阿堵中。',64,'全唐诗/poet.song.100000.json','["天公嗔我眼常白，故著昏花阿堵中。", "不怪參軍談瞎馬，但妨中散送飛鴻。", "著籬令惡誰能繼，損讀方奇定有功。", "九惱從來是佛種，會如那律證圓通。"]'),
('a2777b9a-6c1d-4c41-95e6-60b89b6622a5','以事走郊外示友','陳與義','宋','宋诗','song-poetry','','[]','二十九年知已非，今年依舊壯心違。',64,'全唐诗/poet.song.100000.json','["二十九年知已非，今年依舊壯心違。", "黄塵滿面人猶去，紅葉無言秋又歸。", "萬里天寒鴻雁瘦，千村歲暮鳥烏微。", "往來屑屑君應笑，要就南池照客衣。"]'),
('6a6c8e69-b435-462f-9db5-0534a6b607b4','十月','陳與義','宋','宋诗','song-poetry','','[]','十月北風催歲闌，九衢黄土污儒冠。',64,'全唐诗/poet.song.100000.json','["十月北風催歲闌，九衢黄土污儒冠。", "歸鴉落日天機熟，老雁長雲行路難。", "欲詣熱官憂冷語，且求濁酒寄清歡。", "孤吟坐到三更月，枯木無枝不受寒。"]'),
('d9ede228-fbdb-4b09-b6f8-aeb7f5165ed9','題小室','陳與義','宋','宋诗','song-poetry','','[]','暫脫朝衣不當閑，澶州夢斷已多年。',64,'全唐诗/poet.song.100000.json','["暫脫朝衣不當閑，澶州夢斷已多年。", "諸公自致青雲上，病客長齋繡佛前。", "隨意時爲師子卧，安心懶作野狐禪。", "爐煙忽散無蹤跡，屋上寒雲自黯然。"]'),
('0b51812a-5756-4e17-b091-4645ba42a392','次韻張迪功春日','陳與義','宋','宋诗','song-poetry','','[]','年年春日寒欺客，今日春無一半寒。',64,'全唐诗/poet.song.100000.json','["年年春日寒欺客，今日春無一半寒。", "不覺轉頭逢歲換，便須揩目待花看。", "爭新遊女幡垂鬢，依舊先生日照盤。", "從此不憂風雪厄，杖藜時可過蘇端。"]'),
('2d661df7-12a9-428b-960a-40fa4fb46237','又和歲除感懷用前韻','陳與義','宋','宋诗','song-poetry','','[]','宦情吾與歲俱闌，只有詩盟偶未寒。',64,'全唐诗/poet.song.100000.json','["宦情吾與歲俱闌，只有詩盟偶未寒。", "鬢色定從今夜改，梅花已判隔年看。", "高門召客車稠疊，下里燒香篆屈盤。", "我亦三杯聊復爾，夢回鵷鷺出朝端。"]'),
('ad8da6f3-3eae-496f-a998-5216720bd42a','張迪功携詩見過次韻謝之二首  其一','陳與義','宋','宋诗','song-poetry','','[]','黄紙紅旗意未闌，青衫俱不救饑寒。',64,'全唐诗/poet.song.100000.json','["黄紙紅旗意未闌，青衫俱不救饑寒。", "久荒三徑未得返，偶有一錢何足看。", "世事豈能磨鐵硯，詩盟聊可歃銅盤。", "不嫌野外時迂蓋，政要相從叩兩端。"]'),
('e8c52245-3e03-454f-ae0d-6c0a3182360f','張迪功携詩見過次韻謝之二首  其二','陳與義','宋','宋诗','song-poetry','','[]','黄雞白日唱初闌，便覺杯觴耐薄寒。',64,'全唐诗/poet.song.100000.json','["黄雞白日唱初闌，便覺杯觴耐薄寒。", "坐上客多真足樂，床頭易在不須看。", "更思深徑挼紅蕊，政待移厨洗玉盤。", "苦恨重城催興盡，歸時落日尚雲端。"]'),
('3666d65c-6c9d-486e-8b6c-2fed3cf9fdcc','即席重賦且約再遊  其一','陳與義','宋','宋诗','song-poetry','','[]','牆頭花定覺風闌，牆外池深酒亦寒。',64,'全唐诗/poet.song.100000.json','["牆頭花定覺風闌，牆外池深酒亦寒。", "馬健莫愁歸路遠，詩成未許俗人看。", "釣魚不用尋溫水，濯髮真如到洧盤。", "一笑得君天所借，尊前無地著憂端。"]'),
('6459f585-62a3-4331-a92b-f38df1ab078b','即席重賦且約再遊  其二','陳與義','宋','宋诗','song-poetry','','[]','詩情不與歲情闌，春氣猶兼水氣寒。',64,'全唐诗/poet.song.100000.json','["詩情不與歲情闌，春氣猶兼水氣寒。", "怪我問花終不語，須公走馬更來看。", "共知浮世悲駒隙，即見平波散芡盤。", "得一老兵雖可飲，從今取友要須端。"]'),
('93ce7dc9-d4cb-4263-aa9d-f9d108dd550e','次韻家叔','陳與義','宋','宋诗','song-poetry','','[]','衮衮諸公車馬塵，先生孤唱發陽春。',64,'全唐诗/poet.song.100000.json','["衮衮諸公車馬塵，先生孤唱發陽春。", "黄花不負秋風意，白髮空隨世事新。", "閉戶讀書真得計，載肴從學豈無人。", "只應又被支郎笑，從者依前困在陳。"]'),
('a7499ec4-4eb1-4208-91f6-0d4ef8448e8d','次韻答張迪功坐上見貽張將赴南都任  其一','陳與義','宋','宋诗','song-poetry','','[]','足錢便可不須侯，免對妻兒賦百憂。',64,'全唐诗/poet.song.100000.json','["足錢便可不須侯，免對妻兒賦百憂。", "一笑相逢亦奇事，平生所得是清流。", "談天安用如鄒子，掃地還應學趙州。", "南北東西底非夢，心閑隨處有真遊。"]'),
('067c9c5e-17e7-4d60-a3b5-ccd4f5752f39','次韻答張迪功坐上見貽張將赴南都任  其二','陳與義','宋','宋诗','song-poetry','','[]','千首能輕萬戶侯，誦君佳句解人憂。',64,'全唐诗/poet.song.100000.json','["千首能輕萬戶侯，誦君佳句解人憂。", "夢闌塵裏功名晚，笑罷尊前歲月流。", "世事無窮悲客子，梅花欲動憶吾州。", "明朝又作河梁別，莫負平生馬少遊。"]'),
('88fb9bb8-07cb-4f74-ba12-2eaedf778cfd','送張迪功赴南京掾  其一','陳與義','宋','宋诗','song-poetry','','[]','士固難推挽，君其自寵珍。',48,'全唐诗/poet.song.100000.json','["士固難推挽，君其自寵珍。", "詩成建安子，名到斗南人。", "晚歲還爲客，微官只爲身。", "向來書盡熟，去不愧張巡。"]'),
('d50e67da-4500-4bb7-9d60-16f3c3ab437d','送張迪功赴南京掾  其二','陳與義','宋','宋诗','song-poetry','','[]','岸闊舟仍小，林空風更多。',48,'全唐诗/poet.song.100000.json','["岸闊舟仍小，林空風更多。", "能堪幾寒暑，又作隔山河。", "看客休題鳳，將書莫換鵝。", "功名大槐國，終要白鷗波。"]'),
('5855ace8-4ef4-4d2c-9b70-cc93f495d5c3','梅花','陳與義','宋','宋诗','song-poetry','','[]','高花玉質照窮臈，破雪數枝春已多。',32,'全唐诗/poet.song.100000.json','["高花玉質照窮臈，破雪數枝春已多。", "一時傾倒東風意，桃李爭春奈晚何。"]'),
('5159882b-aa04-4507-a521-8b62aa6a56ab','與周紹祖分茶','陳與義','宋','宋诗','song-poetry','','[]','竹影滿幽窗，欲出腰髀懶。',48,'全唐诗/poet.song.100000.json','["竹影滿幽窗，欲出腰髀懶。", "何以同歲暮，共此晴雲椀。", "摩挲蟄雷腹，自笑計常短。", "异時分憂虞，小杓勿辭滿。"]'),
('9734dd7f-4bf4-4725-a85b-ec15fed17607','題畫兔','陳與義','宋','宋诗','song-poetry','','[]','碎身鷹犬慚何忍，埋骨詩書事亦微。',32,'全唐诗/poet.song.100000.json','["碎身鷹犬慚何忍，埋骨詩書事亦微。", "霜露深林可終歲，雌雄暖日莫忘機。"]'),
('f50dfd20-8634-4f17-8eb6-be9e341e5b2c','寄若拙弟兼呈二十家叔','陳與義','宋','宋诗','song-poetry','','[]','退之送窮窮不去，樂天待富富不來。',128,'全唐诗/poet.song.100000.json','["退之送窮窮不去，樂天待富富不來。", "政須青山映白髮，顧著皂蓋爭黄埃。", "何如父子共一壑，龐家活計良不惡。", "阿奴况自不碌碌，白鷗之盟可同諾。", "三間瓦屋亦易求，著子東頭我西頭。", "中間共作老萊戲，世上樂復有此不。", "問夢膏肓應已瘳，歸來歸來無久留。", "竹林步兵非俗流，爲道此意思同遊。"]'),
('37bc4e3d-23da-49d7-aba3-ac0d0fa49912','次韻謝表兄張元東見寄','陳與義','宋','宋诗','song-poetry','','[]','平生張翰極風流，好事工文妙九州。',64,'全唐诗/poet.song.100000.json','["平生張翰極風流，好事工文妙九州。", "燈裏偶然同一笑，書來已似隔三秋。", "林泉入夢吾當隱，花鳥催詩歲不留。", "安得清談一陶寫，令人絕憶許文休。"]'),
('16691612-d4a2-4f3a-8a65-18f3108342c2','若拙弟說汝州可居已卜約一丘用韻寄元東','陳與義','宋','宋诗','song-poetry','','[]','四歲冷官桑濮地，三年羸馬帝王州。',64,'全唐诗/poet.song.100000.json','["四歲冷官桑濮地，三年羸馬帝王州。", "陶潜迷路已良遠，張翰思歸那待秋。", "病鶴欲飛還躑躅，孤雲欲去更遲留。", "盍簪共結雞豚社，一笑相從萬事休。"]'),
('ad984657-7ec5-4517-a804-55989c00163c','元方用韻見寄次韻奉謝兼呈元東  其一','陳與義','宋','宋诗','song-poetry','','[]','大難詞源三峽流，小難詩不數蘇州。',64,'全唐诗/poet.song.100000.json','["大難詞源三峽流，小難詩不數蘇州。", "了無徐生齊氣累，正值甯子商歌秋。", "鵠飛千里從此始，驥絕九衢誰得留。", "歲晚煩君起我病，兩篇三嘆不能休。"]'),
('4158817e-b689-48f1-b6d9-af80e86fab87','元方用韻見寄次韻奉謝兼呈元東  其二','陳與義','宋','宋诗','song-poetry','','[]','一歡玄髮水東流，兩脚黄塵閱幾州。',64,'全唐诗/poet.song.100000.json','["一歡玄髮水東流，兩脚黄塵閱幾州。", "王湛時須看周易，虞卿未敢著春秋。", "不辭彭澤腰常折，却得邯鄲夢少留。", "有句驚人雖可喜，無錢使鬼故宜休。"]'),
('5d6e6c8d-5c60-4795-b41f-af4e36dc5254','元方用韻寄若拙弟邀同賦元方將託若拙覓顔淵之五十畝故詩中見意','陳與義','宋','宋诗','song-poetry','','[]','夢中與世極周流，錯認三刀是得州。',64,'全唐诗/poet.song.100000.json','["夢中與世極周流，錯認三刀是得州。", "擬學耕田給公上，要爲同社燕春秋。", "囊間已辦青芒屨，桑間想聞黄栗留。", "儻有幽人諮出處，爲言無况莫來休。"]'),
('4d672e5b-cefc-4104-9cd8-55db30856564','西郊春事漸入老境元方欲出遊以無馬未果今日得詩又有舉鞭何日之嘆因次韻招之','陳與義','宋','宋诗','song-poetry','','[]','毛穎陳玄雖勝流，也須從事到青州。',64,'全唐诗/poet.song.100000.json','["毛穎陳玄雖勝流，也須從事到青州。", "重吟玉樹懷崔子，欲唱金衣無杜秋。", "官柳正須工部出，園花猶爲退之留。", "籃輿自可煩兒輩，一笑來從樾下休。"]'),
('1589cea8-d654-4747-a46c-e9876bd1d408','答元方述懷作','陳與義','宋','宋诗','song-poetry','','[]','不見圓機論九流，紛紛騎鶴上揚州。',64,'全唐诗/poet.song.100000.json','["不見圓機論九流，紛紛騎鶴上揚州。", "令之敢恨松桂冷，君叔但傷蒲柳秋。", "汝海蛇杯應已悟，襄陵駒隙竟難留。", "來牛去馬無窮債，未蓋棺前盍少休。"]'),
('448e94a7-6a98-4605-bd8f-234b68e2b36b','六言二首  其一','陳與義','宋','宋诗','song-poetry','','[]','莫賦澗松鬰鬰，但吟陂麥青青。',28,'全唐诗/poet.song.100000.json','["莫賦澗松鬰鬰，但吟陂麥青青。", "爲婦讀劉伶傳，教兒書甯戚經。"]'),
('bd79b0cc-e661-47af-ab15-2215fa072521','六言二首  其二','陳與義','宋','宋诗','song-poetry','','[]','種竹可侔千戶，擁書不假百城。',28,'全唐诗/poet.song.100000.json','["種竹可侔千戶，擁書不假百城。", "何必思之爛熟，熱官無用分明。"]'),
('3f7c0ef6-a6a9-48e5-86c4-70539725d5a1','聞葛工部寫華嚴經成隨喜賦詩','陳與義','宋','宋诗','song-poetry','','[]','如來性海深復深，著書與世湔蓬心。',128,'全唐诗/poet.song.100000.json','["如來性海深復深，著書與世湔蓬心。", "畫沙累土皆佛事，况乃一字能千金。", "老郎居塵念不起，法中龍象人師子。", "前身智永心了然，結習未空猶寄此。", "怪公聚筆如須彌，經成筆盡手不知。", "凌雲題就韋誕老，願力所到公何疑。", "珠函繡帙芝蘭室，護持金剛竦神物。", "枯葵應感不足論，毛頴陶泓俱見佛。"]'),
('6481c466-d6d7-4153-8e2e-4fbef35c4b0b','次韻家弟碧線泉','陳與義','宋','宋诗','song-poetry','','[]','七孔穿針可得過，冰蠶映日吐寒波。',64,'全唐诗/poet.song.100000.json','["七孔穿針可得過，冰蠶映日吐寒波。", "練飛空詠徐凝水，带斷疑分漢帝河。", "川后不愁微步襪，鮫人暗動卷綃梭。", "才高下視玄虛賦，對此區區轉患多。"]'),
('eb0b9f8e-0a13-4305-8fbf-e7a8e9a82c19','同家弟賦蠟梅詩得四絕句  其一','陳與義','宋','宋诗','song-poetry','','[]','朱朱與白白，著意待春開。',24,'全唐诗/poet.song.100000.json','["朱朱與白白，著意待春開。", "那知洞房裏，已傍額黄來。"]'),
('9ae8af74-a0f1-4901-acf2-17e630753954','同家弟賦蠟梅詩得四絕句  其二','陳與義','宋','宋诗','song-poetry','','[]','韻勝誰能捨，色莊那得親。',24,'全唐诗/poet.song.100000.json','["韻勝誰能捨，色莊那得親。", "朝陽一映樹，到骨不留塵。"]'),
('05649655-534b-49a0-a260-8f16eabb2b3b','同家弟賦蠟梅詩得四絕句  其三','陳與義','宋','宋诗','song-poetry','','[]','黄羅作廣袂，絳帳作中單。',24,'全唐诗/poet.song.100000.json','["黄羅作廣袂，絳帳作中單。", "人間誰敢著，留得護春寒。"]'),
('8b8345e7-203f-44bd-a09b-1497bc32f5b6','同家弟賦蠟梅詩得四絕句  其四','陳與義','宋','宋诗','song-poetry','','[]','一花香十里，更值滿枝開。',24,'全唐诗/poet.song.100000.json','["一花香十里，更值滿枝開。", "承恩不在貌，誰敢鬬香來。"]'),
('6e3bc0fc-8701-4e45-928e-e5dfdd8e0798','次韻光化宋唐年主簿見寄二首  其一','陳與義','宋','宋诗','song-poetry','','[]','茂林當日映群賢，也喚畸人到席間。',64,'全唐诗/poet.song.100000.json','["茂林當日映群賢，也喚畸人到席間。", "棄我便驚車轍遠，懷君端合鬢毛班。", "夢中猶得攀珠樹，別後能忘倒玉山。", "遥想詩成記來日，筆端風雨發天慳。"]'),
('672ea80f-b079-4580-a10f-4f5bfa5620ee','次韻光化宋唐年主簿見寄二首  其二','陳與義','宋','宋诗','song-poetry','','[]','高人主簿固非宜，天馬何妨畧受鞿。',64,'全唐诗/poet.song.100000.json','["高人主簿固非宜，天馬何妨畧受鞿。", "會有梅花堪寄遠，可因蒓菜便懷歸。", "相如未免家徒壁，季子行看嫂下機。", "且復哦詩置此事，江山相助莫相違。"]'),
('b48f12ae-d30a-466e-bbc7-a993b36c31ca','再用景純韻詠懷二首  其一','陳與義','宋','宋诗','song-poetry','','[]','路斷赤墀青瑣賢，士龍同此屋三間。',64,'全唐诗/poet.song.100000.json','["路斷赤墀青瑣賢，士龍同此屋三間。", "愁邊潘令鬢先白，夢裏老萊衣更班。", "欲學大招那有賦，試謀小隱可無山。", "一錢留得真堪笑，未到囊空猶是慳。"]'),
('bd85fc4e-a371-4480-8d32-c9ae3b9d78dd','再用景純韻詠懷二首  其二','陳與義','宋','宋诗','song-poetry','','[]','木枕蒲團病更宜，從教惡少事鞍鞿。',64,'全唐诗/poet.song.100000.json','["木枕蒲團病更宜，從教惡少事鞍鞿。", "元無王老又何怨，不有麯生誰與歸。", "六日取蟾乖世用，三年刻楮費天機。", "只應杖屨從公處，未覺平生與願違。"]'),
('3615a253-e386-486e-bc98-ce7f110d5bf6','謝楊工曹','陳與義','宋','宋诗','song-poetry','','[]','借屋三間稍離塵，携書一束謾娛身。',64,'全唐诗/poet.song.100000.json','["借屋三間稍離塵，携書一束謾娛身。", "客居最負青春好，世事空隨白髮新。", "造化小兒真薄相，市朝大隱亦長貧。", "獨無芋粟供賓客，虛辱先生賦北鄰。"]'),
('9008928f-db56-46ed-b589-2310fd15ed5e','謹次十七叔去鄭詩韻二章以寄家叔一章以自詠  其一','陳與義','宋','宋诗','song-poetry','','[]','鄉里小兒真可憐，市朝大隱正陶然。',64,'全唐诗/poet.song.100000.json','["鄉里小兒真可憐，市朝大隱正陶然。", "固應聊頌屈原橘，底事便歌楊惲田。", "廣陌遥知駒款段，曲池猶記鷺聯拳。", "對床夜雨平生約，話舊應驚歲月遷。"]'),
('1326cfd4-a770-417f-b823-49f49dedfbb5','謹次十七叔去鄭詩韻二章以寄家叔一章以自詠  其二','陳與義','宋','宋诗','song-poetry','','[]','蚍蜉堪笑亦堪憐，撼樹無功更怫然。',64,'全唐诗/poet.song.100000.json','["蚍蜉堪笑亦堪憐，撼樹無功更怫然。", "賦就柳州聊解祟，詩成彭澤要歸田。", "身謀共悔蛇安足，理遣須看佛舉拳。", "懷祖定知當晚合，次君未可怨稀遷。"]'),
('8089756b-8621-406d-a340-06ee0efc9bcd','謹次十七叔去鄭詩韻二章以寄家叔一章以自詠  其三','陳與義','宋','宋诗','song-poetry','','[]','鏡中無復故人憐，却愧謀生後計然。',64,'全唐诗/poet.song.100000.json','["鏡中無復故人憐，却愧謀生後計然。", "叔夜本非堪作吏，元龍今悔不求田。", "懷親更值薪如桂，作客重看栗過拳。", "萬事巧違高枕卧，憂來一夕費三遷。"]'),
('4bf0d24a-e969-44a5-bbbe-359e81a9cfd6','連雨書事四首  其一','陳與義','宋','宋诗','song-poetry','','[]','九月逢連雨，蕭蕭穩送秋。',48,'全唐诗/poet.song.100000.json','["九月逢連雨，蕭蕭穩送秋。", "龍公無乃倦，客子不勝愁。", "雲氣昏城壁，鐘聲咽寺樓。", "年年授衣節，牢落向他州。"]'),
('41929266-8adc-4348-a506-3a3136cde24b','連雨書事四首  其二','陳與義','宋','宋诗','song-poetry','','[]','風伯方安卧，雲師亦少饕。',48,'全唐诗/poet.song.100000.json','["風伯方安卧，雲師亦少饕。", "氣連河漢潤，聲到竹松高。", "老雁猶貪去，寒蟬遂不號。", "相悲更相識，滿眼楚人騷。"]'),
('fac68965-63db-4c5a-ba12-adffbdfdcb7e','連雨書事四首  其三','陳與義','宋','宋诗','song-poetry','','[]','寒入薪芻價，連天兩眼愁。',48,'全唐诗/poet.song.100000.json','["寒入薪芻價，連天兩眼愁。", "生涯赤藤杖，契分黑貂裘。", "烏鵲無言暮，蓬蒿滿意秋。", "同時不同味，世事劇悠悠。"]'),
('d38da30d-924e-48c6-9da5-550068f60b2b','連雨書事四首  其四','陳與義','宋','宋诗','song-poetry','','[]','白菊生新紫，黄蕪失舊青。',48,'全唐诗/poet.song.100000.json','["白菊生新紫，黄蕪失舊青。", "俱含歲晚恨，併入夜深聽。", "夢寐連蕭瑟，更籌亂晦冥。", "雲移過吳越，應爲洗餘腥。"]'),
('da83ef9c-7aad-48ae-828a-0a627a68aa37','陳叔易賦王秀才所藏梁織佛圖詩邀同賦因次其韻','陳與義','宋','宋诗','song-poetry','','[]','維摩之室本自空，忽驚滿月臨丹宮。',384,'全唐诗/poet.song.100000.json','["維摩之室本自空，忽驚滿月臨丹宮。", "稽首世尊真實相，不比圖畫填青紅。", "天女之孫擅天巧，經緯星宿超庸庸。", "淪精入此三昧手，一念直到祇園中。", "意匠經營與佛會，七寶欲動聲瓏瓏。", "眉間毫光放未盡，指下已带旃檀風。", "飛梭本是龍變化，挾大威德行神通。", "恍若祇洹遇佛影，豈彼臺像能比崇。", "共惟此事不思議，細看衆巧無遺蹤。", "日浮雞園赤爛爛，天入鷲嶺青叢叢。", "那知金臂是正倒，但覺已挫千魔鋒。", "龍天四衆儼然侍，喜滿尺宅俱成功。", "向來八風幾卷地，衆寶行樹無摧桻。", "老蕭區區佛所憫，豈與十二蟯蚘同。", "重雲之殿珠作帳，一朝入海奔雷公。", "幸留此像不爲少，福聚萬紀兼千總。", "餘休八葉終灰燼，堅固却賴三眠蟲。", "似聞法猛藕絲像，當時已不隨煙東。", "煌煌二寶照南北，客攝萬鬼專其雄。", "龍華已耀東坡墨，驚夢不假撞洪鐘。", "唯有茲圖晦幾歲，留待公句貽無窮。", "畫沙累土皆見佛，而况筆墨如此工。", "亦念衆生業障厚，要與機杼聊分攻。", "從今俱盡未來世，買絲不繡平原容。"]'),
('5a15389e-80e5-41d3-965d-20cbb4025714','趙虛中有石名小華山以詩借之','陳與義','宋','宋诗','song-poetry','','[]','君家蒼石三峯樣，磅礴乾坤氣象橫。',64,'全唐诗/poet.song.100000.json','["君家蒼石三峯樣，磅礴乾坤氣象橫。", "賤子與山曾半面，小窗如夢慰平生。", "爐煙巧作公超霧，書冊尚避秦皇城。", "病眼朝來欲開懶，借君巖岫障新晴。"]'),
('2cb931bd-eb19-4e19-8730-8bee5842d47a','次韻樂文卿北園','陳與義','宋','宋诗','song-poetry','','[]','故園歸計墮虛空，啼鳥驚心處處同。',64,'全唐诗/poet.song.100000.json','["故園歸計墮虛空，啼鳥驚心處處同。", "四壁一身長客夢，百憂雙鬢更春風。", "梅花不是人間白，日色爭如酒面紅。", "且復高吟置餘事，此生能費幾詩筒。"]'),
('23110fb7-a837-426d-ae58-8bec90b47b87','汝州吳學士觀我齋分韻得真字','陳與義','宋','宋诗','song-poetry','','[]','狂夫縛軒冕，自許稷契身。',120,'全唐诗/poet.song.100000.json','["狂夫縛軒冕，自許稷契身。", "靜者樂山林，謂是羲皇人。", "不如兩忘快，內保一色醇。", "偉哉道山傑，滯此汝水濱。", "大來會闊步，小憩得幽欣。", "一齋有琴酒，萬事無緇磷。", "不作子公書，肯受元規塵。", "人言君侯癡，我知丈人真。", "月明泉聲細，雨過竹色新。", "是間有真我，宴坐方申申。"]'),
('2202bf04-2e30-4a2d-9037-35f4a7edd800','送秘典座勝侍者乞麥','陳與義','宋','宋诗','song-poetry','','[]','一春不雨但多風，家家買龜問豐凶。',96,'全唐诗/poet.song.100000.json','["一春不雨但多風，家家買龜問豐凶。", "天寧疏頭與天通，泚筆未了雲埋空。", "一雨三日勤老龍，隴頭滿眼十分豐。", "法中福將兩英雄，自詭去立丘山功。", "堂頭老師言語工，一詩自直三千鍾。", "不憂乞米送盧仝，末章謹已藏胸中。"]'),
('5dbc9f68-bd75-4c11-8df0-728eb8b31892','食虀','陳與義','宋','宋诗','song-poetry','','[]','君不見領軍家有鞋一屋，相國藏椒八百斛。',131,'全唐诗/poet.song.100000.json','["君不見領軍家有鞋一屋，相國藏椒八百斛。", "士患饑寒求免患，癡兒已足憂不足。", "伯龍平生受鬼笑，無錢可使宜見瀆。", "但當與作謫仙詩，聊復使渠終夜哭。", "詩中有味甜如蜜，佳處一哦三鼓腹。", "空腸時作不平鳴，却恨忍饑猶未熟。", "冰壺先生當立傳，木奴魚婢何足錄。", "顔生狡獪還可憐，晚食由來未忘肉。"]'),
('ab87d1ff-79e6-4641-886e-d0dd048b54a8','古別離','陳與義','宋','宋诗','song-poetry','','[]','東門柳，年年歲歲征人手。',44,'全唐诗/poet.song.100000.json','["東門柳，年年歲歲征人手。", "千人萬人於此別，柳亦能堪幾人折。", "願君遄歸與君期，要及此柳未衰時。"]'),
('6111c427-bb1d-4534-ac97-c1eef171f527','蠟梅四絕句  其一','陳與義','宋','宋诗','song-poetry','','[]','花房小如許，銅剪黄金塗。',24,'全唐诗/poet.song.100000.json','["花房小如許，銅剪黄金塗。", "中有萬斛香，與君細細輸。"]'),
('09e1426b-42ed-4443-827b-0891cb0367bd','蠟梅四絕句  其二','陳與義','宋','宋诗','song-poetry','','[]','來從底處所，黄露滿衣濕。',24,'全唐诗/poet.song.100000.json','["來從底處所，黄露滿衣濕。", "緣憨翻得憐，亭亭倚風立。"]'),
('fc6c66c2-3c6e-43d7-8fe5-45179deb61c2','蠟梅四絕句  其三','陳與義','宋','宋诗','song-poetry','','[]','奕奕金仙面，排行立曉晴。',24,'全唐诗/poet.song.100000.json','["奕奕金仙面，排行立曉晴。", "殷勤夜來雪，少住作珠瓔。"]'),
('ff8358cd-9715-4e81-87f9-7eb00b7168b0','蠟梅四絕句  其四','陳與義','宋','宋诗','song-poetry','','[]','亭亭金步摇，朝日明漢宮。',24,'全唐诗/poet.song.100000.json','["亭亭金步摇，朝日明漢宮。", "當時好光景，一似此園中。"]'),
('f3a642e1-81d8-4b46-bd00-56f6db9728a4','次韻富季申主簿梅花','陳與義','宋','宋诗','song-poetry','','[]','東風知君將出遊，玉人迥立林之幽。',128,'全唐诗/poet.song.100000.json','["東風知君將出遊，玉人迥立林之幽。", "欹牆數苞乃爾瘦，中有萬斛江南愁。", "君哦新詩我聽瑩，句裏無塵春色靜。", "人人索笑那得禁，獨爲君詩起君病。", "欲語未語令人嗟，桃李回看眼中沙。", "同心不見昭儀種，五出時驚公主花。", "典衣重作明朝約，聊復寬君念歸洛。", "笛催疏影日更疏，快飲莫教春寂寞。"]'),
('cd88948a-624c-4a74-bf08-2db44b95342e','錢東之教授惠澤州呂道人硯爲賦長句','陳與義','宋','宋诗','song-poetry','','[]','君不見銅雀臺邊多事土，走上觚稜蔭歌舞。',131,'全唐诗/poet.song.100000.json','["君不見銅雀臺邊多事土，走上觚稜蔭歌舞。", "餘香分盡垢不除，却寄書林汙縑楮。", "豈如此瓦凝青膏，冷面不識姦雄曹。", "呂公已去泫餘泣，通譜未許弘農陶。", "暮年得君真耐久，摩挲玉質雲生手。", "未知南越石虛中，亦有文章似君否。", "西家撲滿本弟昆，趣尚清濁何年分。", "一朝墮地真瓦礫，莫望韓公無瘞文。"]'),
('bb78a42b-e535-43da-9e0a-00f8ba26fde8','以石龜子施覺心長老','陳與義','宋','宋诗','song-poetry','','[]','老龜千年作一息，天地併入支床力。',82,'全唐诗/poet.song.100000.json','["老龜千年作一息，天地併入支床力。", "何年生此石腸兒，非皮裹骨骨裹皮。", "君家元緒不慎口，遂與老桑同一朽。", "知君遊世磨不磷，往作道人之石友。", "道人莫欺此龜無六眸，試與話禪當點頭。"]'),
('c5713f87-947d-4516-a442-51aff1259c94','陪諸公登南樓啜新茶家弟出建除體詩諸公既和余因次韻','陳與義','宋','宋诗','song-poetry','','[]','建康九醞羙，侑以八品珍。',144,'全唐诗/poet.song.100000.json','["建康九醞羙，侑以八品珍。", "除瘴去熱惱，與茶不相親。", "滿月墮九天，紫面光磷磷。", "平生酪奴謗，脈脈氣未申。", "定論得公詩，雅號知凝神。", "執持甘露椀，未覺有等倫。", "破睡及四座，愧我非嘉賓。", "危樓與世隔，萬事不及唇。", "成公方坐嘯，賞此玉花勻。", "收杯未要忙，再試晴天雲。", "開口得一笑，茲遊念當頻。", "閉眼歸默存，助發梨棗春。"]'),
('cea6de36-09df-4159-afa0-7fac7ddbb1b4','諸公和淵明止酒詩因同賦','陳與義','宋','宋诗','song-poetry','','[]','愛河漂一世，既溺不能止。',120,'全唐诗/poet.song.100000.json','["愛河漂一世，既溺不能止。", "不如淡生活，吟詩北窗裏。", "肺肝亦何罪，困此毛錐子。", "不如友麯生，是子差可喜。", "三杯取徑醉，萬緒散莫起。", "奈何劉伶婦，苦語見料理。", "不如一覺睡，浩然忘彼己。", "三十六策中，此策信高矣。", "政使江變酒，誓不涉其涘。", "尚須學王通，藝黍供祭祀。"]'),
('609a3779-042b-4d9f-a38e-f9244b07bb83','以紙託樂秀才搗治','陳與義','宋','宋诗','song-poetry','','[]','古人爭名翰墨藪，柿葉桑根俱不朽。',64,'全唐诗/poet.song.100000.json','["古人爭名翰墨藪，柿葉桑根俱不朽。", "固知老褚下歐陽，控御管城須好手。", "嫁非好時聊自强，幅則甚短慚甚長。", "聞道蔡侯閑石臼，爲借餘力生銀光。"]'),
('403b826f-1093-41ad-bb20-3c6dc5102630','述懷呈十七家叔  其一','陳與義','宋','宋诗','song-poetry','','[]','兒時學道逃悲歡，只今未免憂饑寒。',82,'全唐诗/poet.song.100000.json','["兒時學道逃悲歡，只今未免憂饑寒。", "浮生萬事蟻旋磨，冷官十年魚上竿。", "竹林步兵亦忍辱，長安閉門出無僕。", "門前故人擁廬兒，政坐向來甘碌碌。", "公不見古人有待良不多，利名溺人甚風。"]'),
('654090cd-f86c-4f0d-bc97-fb68b35c801c','述懷呈十七家叔  其二','陳與義','宋','宋诗','song-poetry','','[]','波。',46,'全唐诗/poet.song.100000.json','["波。", "垂露成幃仲長統，明月爲燭張志和。", "塵中別多會日少，世事欲談何可了。", "胸中萬卷已無用，勸公留。"]');
